// GENERATED by tools/gen_pt_landmarks.py — Portuguese landmark texts,
// keyed by '<citySlug>/<icon>'. Regenerate with the script; do not
// hand-edit individual entries.

const Map<String, (String namePt, String descPt)> kLandmarkPt = {
  'chengdu/panda': ('Base de Pesquisa de Criação de Pandas Gigantes de Chengdu', 'A Base de Pesquisa de Criação do Panda-Gigante de Chengdu é o maior centro de conservação de pandas do mundo. Milhões de visitantes chegam todos os anos para ver o símbolo querido da cidade rolando entre os bosques de bambu.'),
  'chengdu/hotpot': ('Hot pot de Sichuan', 'Borbulhando com a pimenta de Sichuan, que adormece a boca, e um óleo vermelho ardente, o hotpot é o coração da mesa de Chengdu. Cada um mergulha o próprio bocado no caldeirão compartilhado no centro da mesa — comer aqui é uma brincadeira coletiva.'),
  'chengdu/bianlian': ('Bian Lian (Mudança de Rosto)', 'No Bian Lian, a arte mágica da ópera de Sichuan, os mestres trocam máscaras coloridas num piscar de olhos com um simples gesto da mão. O segredo é transmitido apenas de mestre para aprendiz, de geração em geração.'),
  'chengdu/jinli': ('Rua Antiga Jinli', 'Iluminada por lanternas vermelhas, Jinli é uma rua de mercado cujas origens remontam à era dos Três Reinos. Com casas de chá, teatro de sombras e mestres que desenham dragões de açúcar, é aqui que melhor se sente o famoso ritmo tranquilo de vida de Chengdu.'),
  'nanjing/citywall': ('Muralha da Cidade da Dinastia Ming', 'Erguida pelo fundador da dinastia Ming para proteger sua capital, esta muralha colossal é a mais longa muralha urbana ainda de pé no mundo. Como garantia de qualidade, cada tijolo traz gravado o nome de quem o fez; hoje, caminhar sobre ela permite ver ao mesmo tempo a Nanjing antiga e a moderna.'),
  'nanjing/plum': ('Flor de ameixeira', 'Florescendo sob a neve no auge do inverno, a flor de ameixeira simboliza resiliência e esperança na cultura chinesa — e Nanjing a escolheu como flor da cidade. No fim do inverno, as encostas da colina Meihua se transformam num mar de pétalas rosa e brancas, e as pessoas passeiam sob as árvores.'),
  'nanjing/duck': ('Pato salgado', 'O pato salgado, assinatura da cozinha de Nanjing, é curado numa salmoura temperada, cozido suavemente e servido frio. Macio e com um equilíbrio delicado de sal, o pato é uma paixão da cidade inteira — uma piada local diz que nenhum pato sai vivo de Nanjing.'),
  'nanjing/bridge': ('Ponte sobre o Rio Yangtzé', 'Concluída em 1968 inteiramente por engenheiros chineses, a Ponte de Nanjing sobre o Yangtzé é uma gigantesca estrutura de dois andares que leva rodovia e ferrovia sobre o rio. Construída sem ajuda estrangeira, tornou-se símbolo da autoconfiança da China moderna e ainda é celebrada com orgulho nos livros escolares.'),
  'qingdao/beer': ('Cerveja Tsingtao', 'Fundada durante o período alemão da cidade, a cervejaria Tsingtao fez de Qingdao o lar da cerveja mais famosa da China. Todo verão, um festival internacional de cerveja toma conta da cidade, e a cerveja fresca de barril vendida em saquinhos plásticos — bebida de canudinho — continua sendo a tradição de rua mais charmosa de Qingdao.'),
  'qingdao/sailing': ('Cidade da Vela', 'As provas de vela das Olimpíadas de 2008 aconteceram na marina de Qingdao, e desde então a cidade carrega o título de \'Cidade da Vela\'. Com sua baía ventosa, velas brancas pontilhando o horizonte e longos calçadões à beira-mar, é a capital chinesa dos esportes náuticos.'),
  'qingdao/beach': ('Praias', 'As praias de Qingdao se estendem diante de colinas cobertas por construções de telhados vermelhos da era alemã, dando à cidade um ar de balneário europeu raro na China. No verão, as areias se enchem de banhistas, e o caminho costeiro que liga as enseadas é um clássico passeio ao pôr do sol.'),
  'qingdao/crab': ('Frutos do mar', 'De frente para o Mar Amarelo, Qingdao come fresco direto da água: barracas de mariscos, ostras, ouriços-do-mar e caranguejos lotam os píeres. O jeito local é cozinhar a pesca do dia simplesmente no vapor e acompanhá-la com uma Tsingtao geladíssima.'),
  'changsha/pepper': ('Pimenta', 'Diferente do ardor entorpecente de Sichuan, a cozinha de Hunan é conhecida por uma pimenta seca e cortante — pimentas frescas e em conserva aparecem em quase todos os pratos. Em Changsha, o picante é uma resposta secular ao clima úmido; os moradores brincam que não têm medo do ardor, têm medo da falta dele.'),
  'changsha/tofu': ('Tofu fedido', 'Mergulhado numa salmoura fermentada e depois frito, o tofu fedorento de Changsha sai preto e crocante por fora, branco como neve e macio por dentro. Não se deixe enganar pelo cheiro forte: regado com molho de pimenta, esse petisco atrai as filas mais longas dos mercados noturnos.'),
  'changsha/fireworks': ('Fogos de artifício', 'Liuyang, vizinha de Changsha, é considerada há séculos a capital mundial dos fogos de artifício — na terra natal da pólvora, o ofício passa de geração em geração. Nos espetáculos regulares às margens do rio Xiang, o céu e a água se pintam de cores ao mesmo tempo.'),
  'changsha/orange': ('Ilha da Laranja', 'A Ilha das Laranjas, uma longa faixa de terra no meio do rio Xiang, deve seu nome aos pomares de tangerinas que cobrem suas margens. Mao Zedong nadou nessas águas na juventude e escreveu um poema famoso sobre a ilha; hoje, um gigantesco busto de granito do jovem Mao contempla o rio na sua ponta.'),
  'zhengzhou/kungfu': ('Kung Fu Shaolin', 'Aos pés do monte Song, perto de Zhengzhou, fica o Templo Shaolin, berço do budismo Chan e do kung fu Shaolin. Ao redor do mosteiro de cerca de 1.500 anos, milhares de alunos das escolas de artes marciais mantêm o legado vivo com treinos que começam ao amanhecer.'),
  'zhengzhou/train': ('Centro Ferroviário', 'Zhengzhou cresceu como cidade-encruzilhada no ponto onde as principais linhas ferroviárias norte-sul e leste-oeste da China se cruzam. Conhecida como \'a cidade que os trens construíram\', continua sendo um dos centros de baldeação mais movimentados da rede de trens de alta velocidade do país.'),
  'zhengzhou/wheat': ('Planícies de Trigo', 'A planície de Henan, irrigada pelo rio Amarelo, é um dos maiores celeiros de trigo da China. Essa terra fértil alimenta a alma da cozinha do norte: macarrões puxados à mão, pastéis no vapor e pães assados na chapa — tudo nasce do trigo desses campos.'),
  'zhengzhou/ding': ('Vaso de Bronze Ding', 'Zhengzhou e seus arredores abrigaram capitais da dinastia Shang, uma das mais antigas da China, e as escavações revelaram caldeirões cerimoniais de bronze chamados ding. Esses vasos simbolizavam o poder e as oferendas aos ancestrais — por isso a cidade é considerada um dos berços da civilização chinesa.'),
  'wuxi/lake': ('Lago Taihu', 'Wuxi fica às margens do Taihu, um dos maiores lagos de água doce da China, cujos peixes, camarões e plantas aquáticas são a base da cozinha local. Contemplado ao pôr do sol do promontório de Yuantouzhu, o lago ganha uma beleza especial na época das cerejeiras em flor.'),
  'wuxi/peach': ('Pêssego de Yangshan', 'A cidadezinha de Yangshan, em Wuxi, é famosa em toda a China por pêssegos tão doces e suculentos que podem ser comidos de colher. A fruta amadurece no meio do verão, quando a colheita traz um clima de festa e os pomares se abrem aos visitantes.'),
  'wuxi/figurine': ('Figurinos de Argila de Huishan', 'Os bonecos de argila de Huishan são um artesanato popular centenário, moldado com a argila escura e macia do sopé da colina Hui, em Wuxi. O mais querido é A-Fu, uma criança de bochechas gordinhas que simboliza abundância e alegria; pintados à mão em cores vivas, esses bonecos são a lembrança clássica da cidade.'),
  'wuxi/boat': ('Barcos do Grande Canal', 'O Grande Canal, a mais longa via navegável artificial do mundo, passa bem pelo coração de Wuxi. Embarcar num barco no bairro da Ponte Qingming, iluminado por lanternas à noite, e deslizar entre casas antigas de paredes brancas e telhas escuras é o jeito mais bonito de conhecer a cidade.'),
  'nanning/tree': ('Cidade Verde', 'Situada na faixa tropical do sul da China, Nanning é chamada de \'Cidade Verde\' por suas ruas sombreadas por árvores enormes e parques que permanecem verdes o ano inteiro. Perto da fronteira com o Vietnã, é uma porta de comércio e de intercâmbio cultural entre a China e o Sudeste Asiático.'),
  'nanning/noodle': ('Macarrão Laoyou', 'O laoyou fen, o \'macarrão do velho amigo\', é um clássico de Nanning, azedo e picante, preparado com broto de bambu em conserva, feijão-preto fermentado e pimenta. Diz a lenda que o dono de uma casa de chá criou a sopa para curar um velho amigo adoentado — e desde então ela é o remédio dos dias úmidos.'),
  'nanning/song': ('Canções Folclóricas', 'O povo Zhuang de Guangxi mantém há séculos a tradição de expressar seus sentimentos em cantos folclóricos improvisados, respondidos um ao outro. Toda primavera, a feira de canções do \'terceiro mês\' enche a cidade de versos em duelo, e a lendária cantora Liu Sanjie continua sendo a heroína mais amada dessa tradição.'),
  'nanning/mango': ('Frutas Tropicais', 'O clima tropical faz de Nanning uma terra farta de manga, longan, lichia e mamão — as barracas de rua transbordam de frutas frescas o ano todo. Nas noites quentes, as sobremesas geladas de frutas e os sucos espremidos na hora são o jeito favorito da cidade de se refrescar.'),
  'nanchang/pavilion': ('Pavilhão Tengwang', 'O Pavilhão Tengwang, às margens do rio Gan, destruído e reconstruído muitas vezes desde a dinastia Tang, é uma das três torres mais célebres do sul da China. O prefácio que o jovem poeta Wang Bo compôs aqui tornou-se uma obra-prima da literatura chinesa e imortalizou o pavilhão.'),
  'nanchang/star': ('Levante de 1º de Agosto', 'O Levante de Nanchang, de 1º de agosto de 1927, é considerado o nascimento do Exército de Libertação Popular, o que rendeu à cidade o título de \'Cidade dos Heróis\'. Os caracteres \'8-1\' na bandeira do exército remetem a essa data — e dão nome à praça central da cidade.'),
  'nanchang/porcelain': ('Terra da Porcelana', 'Jiangxi, a província de Nanchang, abriga Jingdezhen, a capital mundial da porcelana. Por mil anos, seus fornos imperiais produziram esse \'ouro branco\' para os palácios, e caravanas e navios o levaram daqui para o mundo inteiro — um ofício que segue vivo nas mãos de jovens artesãos.'),
  'nanchang/sunset': ('Vista do Rio Gan', 'Ao anoitecer, as duas margens do rio Gan ganham um rosto completamente novo: as fachadas de centenas de prédios se transformam num imenso espetáculo de luzes sincronizadas. Os parques ribeirinhos e a silhueta iluminada do Pavilhão Tengwang fazem deste o passeio noturno favorito de Nanchang.'),
  'yinchuan/camel': ('Rota da Seda', 'Oásis alimentado pelo rio Amarelo, Yinchuan era uma das portas ocidentais onde as caravanas da Rota da Seda descansavam antes de enfrentar o deserto. Nos arredores da cidade, as tumbas reais da dinastia Xia Ocidental, que lembram pirâmides, ainda se erguem em silêncio sob o sol do deserto.'),
  'yinchuan/grapes': ('Vinhedos de Helan', 'As encostas orientais das montanhas Helan, com sol abundante, ar seco e solo pedregoso, são consideradas a melhor região vinícola da China. Os vinhos desses vinhedos vêm ganhando prêmios internacionais, e os apreciadores já chamam a região de \'Bordeaux da China\'.'),
  'yinchuan/desert': ('Deserto de Shapotou', 'Em Shapotou, perto de Yinchuan, as dunas douradas do deserto de Tengger encontram o rio Amarelo — uma das raras paisagens onde deserto e rio convivem lado a lado. Descer as dunas de trenó, partir pelo deserto em caravanas de camelos e cruzar o rio em balsas de pele de carneiro são as aventuras clássicas da região.'),
  'yinchuan/sheep': ('Cordeiro Hui', 'O cordeiro é a estrela da cozinha muçulmana Hui de Ningxia: espetinhos com cominho, cordeiro cozido macio e sopas com macarrão puxado à mão enchem as mesas da cidade. Criado nas pastagens da estepe, o cordeiro local é famoso em toda a China por sua maciez e sabor limpo.'),
  'lhasa/mountain': ('Palácio Potala', 'Erguido no alto da Colina Vermelha, o Palácio de Potala é a obra-prima da arquitetura tibetana, com centenas de salas, tumbas sagradas e capelas. Antigo palácio de inverno dos Dalai Lamas, o edifício vermelho e branco é Patrimônio Mundial da UNESCO e pode ser visto de quase qualquer ponto de Lhasa.'),
  'lhasa/prayer': ('Templo Jokhang', 'Os peregrinos chegam ao Jokhang, o templo mais sagrado do budismo tibetano, às vezes prostrando-se ao longo de todo o caminho. No circuito de Barkhor, ao redor do templo, o fluxo de fiéis girando rodas de oração não para em nenhum momento do dia, e o aroma de incenso toma as ruas.'),
  'lhasa/yak': ('Cultura do Iaque', 'Feito para o frio do alto platô, o iaque é o pilar da vida tibetana: do leite vêm a manteiga e o queijo, da lã saem tendas e roupas, e o esterco vira combustível. Até as lamparinas que ardem dia e noite nos templos são alimentadas com manteiga de leite de iaque.'),
  'lhasa/tea': ('Chá de Manteiga', 'O chá de manteiga, batido com manteiga de iaque, sal e chá preto bem forte, é a bebida de todo dia no Tibete. No frio seco da alta altitude, ele aquece e nutre ao mesmo tempo — e reabastecer a xícara do convidado sempre que ela esvazia é a regra mais doce da hospitalidade tibetana.'),
  'zhuhai/shell': ('Estátua da Menina Pescadora', 'De pé sobre uma rocha no mar, erguendo uma pérola ao céu, a estátua da Menina Pescadora é o emblema de Zhuhai. Ela nasceu de uma lenda local sobre uma fada que assumiu forma humana por amor a um pescador, e saúda com sua pose graciosa todos os que passeiam pela avenida costeira.'),
  'zhuhai/bridge': ('Ponte Hong Kong-Zhuhai-Macau', 'A ponte Hong Kong-Zhuhai-Macau é a mais longa travessia marítima do mundo, com 55 km — uma sequência de pontes, ilhas artificiais e um túnel submarino. Ligando três cidades do delta do Rio das Pérolas numa única linha, essa obra gigantesca é um dos projetos-símbolo da engenharia moderna.'),
  'zhuhai/island': ('Cem Ilhas', 'O nome de Zhuhai significa \'mar de pérolas\', e mais de cem ilhas se espalham ao longo de sua costa. Ilhas como Dong\'ao e Wailingding, alcançadas de balsa, oferecem vilas de pescadores, enseadas tranquilas e restaurantes de frutos do mar — cada uma vivendo no seu próprio ritmo.'),
  'zhuhai/lobster': ('Mesa de Frutos do Mar', 'Onde o Rio das Pérolas encontra o mar, Zhuhai põe a mesa com a pesca do dia: lagostas, tamarutacas, vieiras e ostras são escolhidas vivas nos tanques e preparadas na hora. O suave cozimento no vapor à moda cantonesa realça o frescor e a doçura natural dos frutos do mar.'),
  'yantai/apple': ('Maçã de Yantai', 'O clima marítimo fresco e o sol generoso de Yantai produzem as maçãs mais famosas da China — vermelhas, crocantes e com aroma de mel, enviadas para todos os cantos do país. No outono, os pomares ao longo da costa fervilham com a colheita, e a cidade se enche do perfume de maçãs.'),
  'yantai/wine': ('Vinhos Changyu', 'A Changyu, primeira vinícola moderna da China, foi fundada em Yantai em 1892 e continua sendo a casa de vinhos mais tradicional do país. Com seu museu da cultura do vinho, adegas históricas e rotas de vinhedos nos arredores, Yantai figura entre as poucas verdadeiras \'cidades do vinho\' da Ásia.'),
  'yantai/wave': ('Costa de Penglai', 'A costa de Penglai, em Yantai, é contada na mitologia chinesa como o lugar de onde os Oito Imortais partiram pelo mar. As miragens que às vezes tremeluzem sobre as águas deram a esse litoral a fama de \'terra das fadas\', e o histórico Pavilhão de Penglai contempla o mar do alto de seu penhasco.'),
  'yantai/cherry': ('Pomares de cerejeiras', 'Yantai é uma das grandes regiões produtoras de cereja da China; seu clima costeiro fresco é ideal para frutas graúdas, suculentas e doces. No início do verão, os pomares se abrem aos visitantes — colher cerejas direto do pé é o passeio mais doce da estação.'),
  'datong/buddha': ('Grutas de Yungang', 'Esculpidas nos penhascos a oeste de Datong, as Grutas de Yungang guardam milhares de estátuas de Buda da dinastia Wei do Norte — um dos pontos altos da arte budista chinesa. Algumas figuras cabem na palma da mão, outras têm a altura de um prédio; as grutas são Patrimônio Mundial da UNESCO.'),
  'datong/citywall': ('Muralhas da Dinastia Ming', 'Antiga guarnição de fronteira, Datong reergueu suas muralhas da era Ming, completas com portões imponentes e torres nos cantos. Caminhar ao entardecer sobre as muralhas iluminadas por lanternas é o jeito mais agradável de ver, num só olhar, os telhados da cidade antiga e as luzes da nova Datong.'),
  'datong/noodle': ('Macarrão cortado a faca', 'No daoxiao mian, orgulho de Shanxi, o mestre apoia o bloco de massa no braço e, com uma lâmina, faz voar fitas de macarrão direto para a panela fervente. De bordas grossas e centro fino, esse macarrão segura o molho perfeitamente — o clássico indispensável da mesa de Datong.'),
  'datong/lantern': ('Templo Suspenso', 'Cravado num penhasco do monte Heng, perto de Datong, o Mosteiro Suspenso parece flutuar no ar sobre finos pilares de madeira. Com cerca de 1.500 anos, ele é único também por outro motivo: abriga o budismo, o taoísmo e o confucionismo sob o mesmo teto.'),
  'baotou/horse': ('Cavalos da estepe', 'O nome mongol de Baotou significa \'lugar com cervos\', e a cidade fica à beira da estepe da Mongólia Interior. Nas pastagens ao redor, os cavalos ainda fazem parte da vida cotidiana: pastores mongóis organizam corridas, e as melodias do violino de cabeça de cavalo, o morin huur, ecoam pelas yurtas.'),
  'baotou/deer': ('Parque dos Veados', 'Baotou é apelidada de \'Cidade dos Cervos\', e os cervos que circulam livremente por seus parques mantêm o nome vivo. Os visitantes podem alimentá-los com as próprias mãos — uma cena delicada no meio da estepe que revela o lado surpreendentemente suave de uma cidade industrial.'),
  'baotou/factory': ('Cidade do Aço', 'Baotou abriga uma das maiores produtoras de aço da China e ocupa um lugar especial no mapa da indústria pesada do país. Graças às jazidas minerais próximas, a cidade também é reconhecida como um dos centros mais importantes do mundo em elementos de terras raras.'),
  'baotou/grass': ('Passeios pelas pradarias', 'Uma curta viagem a partir da cidade leva a pastagens que se estendem até o horizonte. Os hóspedes se acomodam em yurtas e são recebidos com chá de leite e cordeiro assado; à noite, canções mongóis sobem ao redor da fogueira. A hospitalidade da estepe é aqui uma tradição de séculos.'),
  'weifang/kite': ('Capital das Pipas', 'Weifang, considerada a terra natal da pipa, pratica esse ofício há séculos com armações de bambu e seda pintada à mão. Todo mês de abril, o Festival Internacional de Pipas de Weifang transforma o céu numa festa de cores, com pipas vindas de todas as partes do mundo.'),
  'weifang/woodprint': ('Gravuras de Yangjiabu', 'A vila de Yangjiabu, em Weifang, é um dos centros mais famosos das coloridas gravuras em madeira penduradas nas portas no Ano-Novo Chinês. Deuses das portas, bebês rechonchudos e símbolos de fartura são impressos camada por camada a partir de matrizes entalhadas à mão — um ofício passado de geração em geração.'),
  'weifang/dragon': ('Pipas de dragão', 'As estrelas dos céus de Weifang são as pipas gigantes em forma de centopeia com cabeça de dragão: dezenas de aros de bambu unidos por um corpo de seda que ondula por muitos metros ao vento. Levantar voo com um gigante desses exige a habilidade e a força de uma equipe inteira.'),
  'weifang/radish': ('Rabanete de Weifang', 'O rabanete verde de Weifang é tão doce e suculento que os moradores o descascam e fatiam como fruta. Um ditado local garante que \'o rabanete de Weifang é melhor que a pera\', mostrando o orgulho por esse vegetal modesto — oferecer rabanete junto com o chá é um gesto de gentileza da cidade.'),
  'dezhou/chicken': ('Frango de Dezhou', 'O frango cozido com especiarias de Dezhou é preparado até a carne se soltar sozinha do osso; sua fama se espalhou pelo país graças à posição movimentada da cidade no Grande Canal e, depois, na ferrovia. Envernizado com mel, frito e cozido lentamente num caldo temperado, esse frango já foi servido às mesas imperiais.'),
  'dezhou/sun': ('Vale Solar', 'Investidora pioneira na indústria solar, Dezhou carrega o título de \'Cidade do Sol\'; no gigantesco campus do Vale Solar, hotéis, postes de luz e casas funcionam com energia do sol. A cidade é uma das vitrines mais visíveis da energia renovável na China.'),
  'dezhou/grapes': ('Melões e Vinhas', 'O solo fértil da planície do rio Amarelo transforma Dezhou numa terra de frutas de verão: os campos se enchem de melancias e as parreiras vergam de cachos de uva. Uma fatia de melancia geladinha numa barraca de beira de estrada é a pausa clássica dos dias quentes de verão.'),
  'dezhou/train': ('Porto do Grande Canal', 'Nos séculos em que o Grande Canal fervilhava, Dezhou era um porto de parada obrigatória para as barcaças que levavam grãos para o norte. Hoje a ferrovia assumiu o papel do canal: situada na linha Pequim-Xangai, a cidade continua sendo uma das principais portas de entrada do norte da China.'),
  'xuzhou/stone': ('Relevos em Pedra da Dinastia Han', 'Xuzhou, terra natal de Liu Bang, fundador da dinastia Han, é um arquivo de história esculpido em pedra. Os relevos de pedra Han que revestiam as câmaras funerárias retratam banquetes, carruagens e criaturas míticas, desenrolando o cotidiano de dois mil anos atrás como uma antiga história em quadrinhos.'),
  'xuzhou/terracotta': ('Exército de Terracota', 'Menores que o famoso exército de Xi\'an, estes soldados de terracota da era Han foram encontrados guardando o túmulo de um rei de Chu. As figuras, da altura de um joelho, formam fileiras impecáveis; apesar do tamanho em miniatura, sua ordem solene fala de um exército destinado a servir mesmo depois da morte.'),
  'xuzhou/lake': ('Lago Yunlong', 'Batizado em homenagem ao \'Dragão das Nuvens\', o Lago Yunlong é um amplo espelho d\'água cercado de colinas — o pulmão verde da cidade. Com trilhas à beira do lago, casas de chá e encostas coroadas por templos, os moradores de Xuzhou acorrem para cá a qualquer hora, da ginástica matinal ao passeio noturno.'),
  'xuzhou/skewer': ('Cultura de Churrasco', 'Xuzhou se orgulha de ser a capital do churrasco da China; a fumaça dos espetinhos de cordeiro girando sobre as brasas percorre suas ruas noite adentro. Pequenos braseiros chegam direto à mesa e cada um assa o próprio espeto — um ritual barulhento e alegre, compartilhado com amigos até tarde.'),
  'zhenjiang/vinegar': ('Vinagre de Zhenjiang', 'O vinagre preto de arroz de Zhenjiang nasce da fermentação longa e paciente do arroz glutinoso; de acidez suave e leve doçura, é o vinagre mais famoso da culinária chinesa. É o acompanhamento indispensável da mesa de dumplings — como dizem os moradores, o aroma de vinagre passeia pelas ruas de Zhenjiang.'),
  'zhenjiang/temple': ('Templo Jinshan', 'O Templo Jinshan, às margens do Yangtzé, abriga a cena mais dramática da Lenda da Serpente Branca, o conto popular mais amado da China: foi aqui que o espírito-serpente Bai Suzhen inundou o templo por amor. O pagode que coroa a colina domina o rio e a cidade.'),
  'zhenjiang/pot': ('Macarrão com Tampa de Panela', 'No guogai mian de Zhenjiang, uma pequena tampa de madeira é deixada flutuando dentro do grande panelão fervente; ela impede que a água transborde e garante que o macarrão cozinhe no ponto certo. O macarrão fino encontra o vinagre local e um caldo à base de soja — o jeito clássico de começar o dia nesta cidade.'),
  'zhenjiang/bridge': ('Margens do Rio Yangtzé', 'Zhenjiang é uma antiga cidade portuária fundada no ponto estratégico onde o Yangtzé encontra o Grande Canal. Suas três colinas ribeirinhas — Jinshan, Beigushan e Jiaoshan — enfeitam as margens com pagodes, templos e parques, transformando a orla numa faixa verde de cultura.'),
  'jiaxing/zongzi': ('Zongzi', 'Jiaxing é a capital do zongzi — trouxinhas de arroz glutinoso envoltas em folhas de bambu e cozidas no vapor. A comida símbolo do Festival do Barco-Dragão é vendida aqui o ano inteiro, recheada com carne de porco, pasta de feijão ou gema de ovo salgada; abrir um zongzi quentinho é uma pequena cerimônia que começa com o perfume da folha.'),
  'jiaxing/boat': ('Barco do Lago Sul', 'Em 1921, obrigado a deixar Shanghai, o primeiro congresso do Partido Comunista Chinês concluiu sua reunião em um barco no Lago do Sul, em Jiaxing. Uma réplica do \'Barco Vermelho\' flutua ali até hoje, e a água enevoada, os salgueiros e os pavilhões da ilha dão à visita uma serena atmosfera histórica.'),
  'jiaxing/silk': ('Terra da Seda', 'Há séculos os bosques de amoreiras e a cultura do bicho-da-seda de Jiangnan sustentam as cidades de canais de Jiaxing. O fio extraído dos casulos vira aqui edredons, tecidos e bordados; a maciez da seda é um presente do clima úmido e ameno da região, que vai do campo ao guarda-roupa.'),
  'jiaxing/canal': ('Wuzhen', 'Wuzhen, na órbita de Jiaxing, está entre as mais graciosas cidades aquáticas de Jiangnan, com pontes de pedra, casas de telhas negras e escadarias que descem até o canal. Quando as lanternas se acendem ao entardecer, a água ganha um brilho avermelhado, e ofícios antigos como a tintura com índigo e o teatro de sombras ainda vivem em suas vielas.'),
  'lishui/mountains': ('Picos Verdes', 'Lishui é o canto mais montanhoso de Zhejiang: seus vales se enchem de névoa e suas cristas, de bambus e pinheiros. Aldeias de pedra penduradas nas encostas e terraços de arroz que tocam as nuvens escondem uma China lenta e verde, longe da agitação da província litorânea.'),
  'lishui/camera': ('Paraíso da Fotografia', 'Vales tomados pela névoa da madrugada, camponeses surgindo nos terraços e um mar de nuvens que muda com a luz fizeram de Lishui um lugar de peregrinação para fotógrafos. A cidade é conhecida por seus eventos internacionais de fotografia; as imagens mais famosas capturam os terraços cheios d\'água reluzindo como ouro ao nascer do sol.'),
  'lishui/mushroom': ('Terra dos Cogumelos', 'O condado de Qingyuan, em Lishui, é considerado o berço do cultivo de cogumelos; o método de cultivar shiitake em troncos foi desenvolvido nestas montanhas há séculos. Os mercados das aldeias ainda exalam o aroma de cogumelos secos, e a cozinha local se orgulha de sopas e cozidos preparados com a colheita fresca.'),
  'lishui/raft': ('Rafting no Rio', 'O rio Ou serpenteia entre os desfiladeiros verdes de Lishui, e deslizar por suas águas cristalinas em uma balsa de bambu é o prazer clássico da região. Enquanto o barqueiro conduz com uma longa vara, aldeias de pescadores, colinas enevoadas e cenas dignas de uma pintura chinesa a nanquim desfilam pelas margens.'),
  'anqing/opera': ('Ópera Huangmei', 'A Ópera Huangmei nasceu das canções de colheita de chá do interior de Anqing e se tornou uma das óperas regionais mais amadas da China. Suas melodias simples e fluidas e suas histórias de amor contadas na fala do dia a dia foram decoradas por gerações — e Anqing ainda é considerada a capital dessa arte.'),
  'anqing/pagoda': ('Pagode Zhenfeng', 'Erguido às margens do Yangtzé, o Pagode Zhenfeng serviu de farol aos barqueiros do rio por séculos e ganhou o nome de \'primeiro pagode do Yangtzé\'. A torre octogonal da era Ming recompensa quem sobe seus andares com uma vista deslumbrante da grande curva do rio.'),
  'anqing/tea': ('Chá de Yuexi', 'As encostas frescas e enevoadas das montanhas Dabie, atrás de Anqing, formam o jardim ideal para um chá verde perfumado. No condado de Yuexi, as folhas tenras colhidas à mão na primavera rendem uma infusão leve e floral — e, nas vilas da montanha, a colheita do chá ainda é o maior acontecimento da estação.'),
  'anqing/sail': ('Porto do Rio', 'Anqing, cujo nome significa \'celebração tranquila\', é a histórica porta portuária da província de Anhui para o Yangtzé — o \'An\' do nome da própria província vem desta cidade. Seus cais à beira-rio e bairros antigos ainda guardam as marcas dos dias de porto movimentado.'),
  'ganzhou/orange': ('Laranja Umbigo de Gannan', 'Os solos vermelhos de Ganzhou e o clima ameno do sul produzem a laranja-de-umbigo de Gannan, considerada uma das mais doces da China. Na época da colheita as colinas se pintam de laranja; suculenta e sem sementes, a fruta leva o nome da cidade a todo o país como motivo de orgulho.'),
  'ganzhou/house': ('Casas Hakka', 'O povo Hakka, migrante vindo do norte, construiu casas-fortaleza nas aldeias montanhosas de Ganzhou; atrás de suas grossas muralhas defensivas, dezenas de famílias viviam sob um único teto. Lá dentro há pátios comuns, salões dedicados aos ancestrais e uma cultura de forte solidariedade mantida viva por séculos.'),
  'ganzhou/pavilion': ('Pavilhão Yugu', 'O Pavilhão Yugu contempla o ponto onde os rios Zhang e Gong se encontram para formar o Gan. Celebrado nos versos dos poetas da dinastia Song, o pavilhão de madeira entrelaça a paisagem fluvial com mil anos de tradição poética; ao entardecer, é o recanto mais melancólico da cidade.'),
  'ganzhou/star': ('Longa Marcha', 'Em 1934, o Exército Vermelho partiu do condado de Yudu, em Ganzhou, para sua retirada épica, que entrou para a história como a Longa Marcha. A história dos soldados atravessando o rio pela noite é lembrada aqui com monumentos e museus; a cidade marca a linha de partida de um dos pontos de virada da história moderna da China.'),
  'putian/shrine': ('Templo de Mazu', 'A deusa Mazu, protetora dos marinheiros, nasceu em Putian; seu templo-mãe ergue-se na ilha de Meizhou e é considerado a origem de milhares de templos de Mazu pelo mundo. A crença e os costumes de Mazu integram o patrimônio imaterial da UNESCO, e nos dias de festa a ilha se enche de fumaça de incenso e peregrinos.'),
  'putian/lychee': ('Pomares de Lichia', 'Putian também é conhecida como a \'Cidade da Lichia\'; lichieiras centenárias ainda dão frutos e sombreiam suas ruas. Corando de vermelho na colheita de verão, a fruta doce foi um luxo do sul exaltado em poemas clássicos, e comer lichias recém-colhidas do pé é uma das alegrias do verão de Putian.'),
  'putian/shoe': ('Capital dos Calçados', 'Putian é um dos gigantes silenciosos da produção mundial de tênis; suas oficinas e fábricas produzem milhões de pares para grandes marcas. Aqui a sapataria funciona quase como um ofício de família — dos modelistas às costureiras, toda uma cadeia de artesãos forma a cozinha invisível da moda esportiva global.'),
  'putian/wave': ('Ilha de Meizhou', 'Alcançada de balsa, a ilha de Meizhou é famosa por suas praias douradas, enseadas rochosas e pelas festas do templo de Mazu. No aniversário da deusa, a ilha ganha vida com tambores e procissões; nos dias mais calmos, é um lugar arejado de peregrinação e descanso à beira-mar.'),
  'mudanjiang/snow': ('Vila da Neve', 'A \'Cidade da Neve da China\', perto de Mudanjiang, é um dos vilarejos mais nevados do país, onde grossas almofadas de neve se acumulam nos telhados e transformam as casas em cabanas de conto de fadas. Quando as lanternas vermelhas se acendem ao anoitecer, as ruelas cobertas de neve brilham com uma luz acolhedora.'),
  'mudanjiang/lake': ('Lago Jingpo', 'O lago Jingpo, formado quando antigas erupções vulcânicas represaram um rio, está entre os maiores lagos de barragem vulcânica da China. Suas águas despencam pela cachoeira Diaoshuilou, famosa pelos saltos de mergulhadores corajosos no verão e pela paisagem congelada espetacular no inverno.'),
  'mudanjiang/tiger': ('Parque dos Tigres Siberianos', 'Hengdaohezi, na região de Mudanjiang, é um dos centros mais importantes do mundo para a proteção e a reprodução do tigre-siberiano, o maior de todos os felinos. Os visitantes observam os tigres circulando por amplas áreas de floresta a partir de rotas protegidas, e o centro é o coração dos esforços para garantir o futuro dessa espécie rara.'),
  'mudanjiang/ski': ('Temporada de Esqui', 'Em Mudanjiang, no coração do cinturão de neve da China, os invernos são longos e a neve cai seca e abundante; as colinas florestadas ao redor da cidade se enchem de esquiadores a cada temporada. As rotas de esqui, combinadas com uma visita à Cidade da Neve, fazem da região um dos polos de turismo de inverno do nordeste chinês.'),
  'changzhou/dino': ('Parque dos Dinossauros', 'O Parque dos Dinossauros de Changzhou, o mais famoso parque temático de dinossauros da China, une um museu de fósseis a um parque de diversões completo e é carinhosamente chamado de \'Jurassic Park da China\'. Com réplicas gigantes de dinossauros, brinquedos aquáticos e montanhas-russas, é o endereço número um da cidade para as famílias.'),
  'changzhou/pagoda': ('Pagode Tianning', 'O pagode de 153 metros do Templo Tianning, no centro da cidade, é considerado o pagode mais alto do mundo. Erguendo-se do pátio de um templo com mais de mil anos de história, seu último andar coloca toda Changzhou e as curvas do Grande Canal aos seus pés.'),
  'changzhou/comb': ('Artesanato de Pentes', 'O pente de Changzhou é um artesanato centenário, feito de madeiras nobres como buxo e ébano em dezenas de etapas manuais. Antigamente oferecidos de presente à corte imperial, esses pentes — com seus entalhes delicados e figuras pintadas à mão — continuam sendo a lembrança mais elegante da cidade.'),
  'changzhou/canal': ('Grande Canal', 'O Grande Canal atravessa Changzhou há séculos, e a cidade enriqueceu com o comércio e a tecelagem que essa via navegável trouxe. À noite, os bairros antigos às margens do canal se iluminam com lanternas, e passear pelos cais de pedra é o prazer mais clássico da cidade.'),
  'shaoxing/wine': ('Vinho de Shaoxing', 'O vinho de arroz amarelo de Shaoxing, de cor âmbar, é fermentado com a água do lago local Jianhu; é apreciado tanto como bebida quanto como tempero indispensável da cozinha chinesa. Pela tradição mais graciosa da cidade, jarras de vinho eram enterradas no nascimento de uma filha e abertas no dia do seu casamento.'),
  'shaoxing/bridge': ('Pontes de Pedra', 'Em Shaoxing, entrelaçada por canais, as vias aquáticas são tão movimentadas quanto as ruas; com centenas de pontes de pedra em arco, a cidade é chamada de \'museu das pontes\'. Algumas estão de pé há séculos, e seus arcos cobertos de musgo ainda fazem sombra para os barcos que deslizam por baixo.'),
  'shaoxing/pen': ('Berço da Caligrafia', 'Wang Xizhi, reverenciado como o maior mestre da caligrafia, escreveu sua obra-prima, o Prefácio do Pavilhão das Orquídeas, num encontro entre os bosques de bambu de Shaoxing. O costume de deixar taças de vinho flutuarem riacho abaixo enquanto se compõem poemas vem daquele dia, e o pavilhão continua sendo parada sagrada para os amantes do pincel.'),
  'shaoxing/boat': ('Barcos Wupeng', 'Nos barcos wupeng de toldo preto de Shaoxing, o barqueiro rema com os pés enquanto guia o leme com as mãos — uma técnica singular transmitida por gerações. Deslizando sob as pontes de pedra pelos canais estreitos, esses barcos também navegam pelas memórias de infância de Lu Xun, o célebre escritor que a cidade criou.'),
  'bengbu/shell': ('Porto das Pérolas', 'O nome de Bengbu significa \'cais das ostras\', e este trecho do rio Huai já foi famoso por seus coletores de pérolas de água doce. A pérola continua sendo o símbolo da cidade — aparece em toda parte, das estátuas das praças ao brasão municipal.'),
  'bengbu/train': ('Portão Ferroviário', 'Bengbu cresceu de um pequeno vilarejo para uma grande cidade no ponto onde a ferrovia Tianjin-Pukou cruzou o rio Huai. Essa porta de entrada na linha norte-sul continua ligando o norte de Anhui à principal rede de transportes do país até hoje.'),
  'bengbu/river': ('Rio Huai', 'O rio Huai é considerado a fronteira natural que divide a China entre norte e sul: ao norte da linha planta-se trigo, ao sul, arroz; no inverno, as casas do norte têm aquecimento central e as do sul, não. Bengbu vive exatamente sobre essa linha de transição, entre dois climas e duas cozinhas.'),
  'bengbu/blossom': ('Feiras de Primavera', 'Na primavera, os parques às margens do Huai explodem em flores, e os moradores de Bengbu passam os fins de semana à beira do rio com piqueniques e festivais de floração. O Parque Zhanggongshan, à beira do lago, torna-se o ponto de encontro mais movimentado da cidade quando as cerejeiras e os pessegueiros florescem.'),
  'jiujiang/mountain': ('Monte Lu', 'Erguendo-se entre o Yangtzé e o lago Poyang, o monte Lu é a montanha mais poética da China — picos envoltos em névoa, cachoeiras e planaltos frescos, inscritos na lista do Patrimônio Mundial da UNESCO. Dos versos de Li Bai sobre sua cachoeira às vilas de pedra da cidadezinha de Guling na encosta, cada canto conta uma história.'),
  'jiujiang/tea': ('Chá Yunwu', 'O chá yunwu (\'nuvem e névoa\'), cultivado nas encostas encobertas de nuvens do monte Lu, está entre os chás verdes mais famosos da China. A umidade da montanha e a luz do sol filtrada pela névoa dão às folhas um aroma fresco e doce; os primeiros brotos da primavera são colhidos à mão e considerados a colheita mais preciosa.'),
  'jiujiang/lake': ('Lago Poyang', 'O Poyang, maior lago de água doce da China, encontra o Yangtzé bem ao lado de Jiujiang. Suas águas avançam e recuam com as estações, e os campos alagados que surgem no inverno recebem dezenas de milhares de aves migratórias — entre elas o raro grou-siberiano.'),
  'jiujiang/scroll': ('Cidade dos Poemas', 'Este antigo porto do Yangtzé acolheu os grandes nomes da poesia chinesa: foi aqui que Bai Juyi escreveu sua famosa \'Canção da Pipa\', inspirado por uma melodia ouvida no rio. À sombra do monte Lu, Jiujiang é uma das portas fluviais mais citadas nos versos da China.'),
  'quanzhou/ship': ('Rota da Seda Marítima', 'Conhecida no mundo medieval como \'Zayton\', Quanzhou foi o maior porto da Rota da Seda Marítima — Marco Polo a descreveu como um dos portos mais movimentados da Terra. Com mesquitas, templos e igrejas lado a lado, o legado cosmopolita da cidade lhe garantiu um lugar na lista do Patrimônio Mundial da UNESCO.'),
  'quanzhou/mosque': ('Mesquita Qingjing', 'Fundada em 1009 por mercadores árabes, a Mesquita Qingjing é uma das mais antigas mesquitas ainda de pé na China. Seu portal de granito e suas paredes de pedra, inspirados na arquitetura do Oriente Médio, comprovam como o porto de Quanzhou era multirreligioso e cosmopolita na era da Rota da Seda Marítima.'),
  'quanzhou/puppet': ('Teatro de Marionetes', 'Na arte das marionetes de fio de Quanzhou, os mestres dão vida às figuras de madeira manejando dezenas de fios delicados ao mesmo tempo — os bonecos conseguem escrever caligrafia e até sacar espadas e duelar. Essa tradição milenar continua sendo a convidada de honra das feiras de templo e dos palcos de festival.'),
  'quanzhou/tea': ('Chá Tieguanyin', 'O condado montanhoso de Anxi, em Quanzhou, é a terra natal do Tieguanyin, a \'Deusa de Ferro\' — o chá oolong mais famoso do mundo. Suas folhas semifermentadas se abrem com um aroma que lembra orquídeas, e a cerimônia do chá gongfu, servida em xicarazinhas, é simplesmente a vida cotidiana por aqui.'),
  'shanghai/pearl': ('Torre Pérola do Oriente', 'Erguendo-se no distrito de Lujiazui, em Pudong, a torre com suas esferas cor-de-rosa é a silhueta mais reconhecível da Xangai moderna. Do mirante com piso de vidro, o rio Huangpu e o Bund, na margem oposta, se estendem aos seus pés; à noite, suas cores cintilam refletidas na água.'),
  'shanghai/bund': ('The Bund', 'As fachadas históricas de bancos e hotéis ao longo do Huangpu carregam o esplendor da época em que Xangai era um porto mundial. Num passeio ao entardecer, de um lado brilham os antigos edifícios comerciais de colunas de pedra e, do outro, os arranha-céus de Pudong — dois séculos se encontram num único olhar.'),
  'shanghai/garden': ('Jardim Yu', 'Este jardim clássico da era Ming, com suas rochas ornamentais, lagos e ponte em zigue-zague, é um oásis no coração da cidade. O bazar ao redor fervilha de casas de chá e barracas de petiscos, enquanto atrás dos muros coroados por dragões se esconde a arte refinada dos jardins de Jiangnan.'),
  'shanghai/xlb': ('Xiaolongbao', 'O xiaolongbao, um bolinho de massa fina que guarda caldo quente em seu interior, é a obra-prima da culinária de Xangai. Primeiro dá-se uma pequena mordida na borda para sorver a sopa, depois mergulha-se o bolinho em vinagre preto com gengibre. As cestas de bambu para cozinhar no vapor enchem de vapor as ruas da cidade toda manhã.'),
  'hangzhou/lake': ('Lago Oeste', 'Com salgueiros, ilhotas e pontes em arco, o Lago do Oeste é a paisagem mais celebrada pela poesia chinesa e Patrimônio Mundial da UNESCO. Passear pelos diques Su e Bai é um costume secular, e conta-se que a Ponte Quebrada foi o ponto de encontro dos amantes da lenda da Serpente Branca.'),
  'hangzhou/tea': ('Chá Longjing', 'Cultivado nas encostas ao redor do lago, o chá verde \'Poço do Dragão\' é o mais famoso da China. Suas folhas achatadas ainda são moldadas à mão em panelas quentes, e a colheita do início da primavera é a mais valorizada. Uma xícara de Longjing numa casa de chá de vila oferece a própria alma de Hangzhou.'),
  'hangzhou/temple': ('Templo Lingyin', 'Lingyin, o \'Templo do Retiro da Alma\', é um dos templos budistas mais antigos da China. Em frente a ele, centenas de figuras de Buda foram esculpidas ao longo dos séculos nas rochas do Pico Feilai. Caminhar entre a fumaça do incenso e a sombra dos pinheiros faz esquecer o barulho da cidade.'),
  'hangzhou/silk': ('Cidade da Seda', 'A seda de Hangzhou é tecida há bem mais de mil anos, e a cidade simbolizava a riqueza do extremo oriental da Rota da Seda. Hoje, tecidos, lenços e bordados trocam de mãos no mercado da seda, enquanto o museu da seda conta a jornada do casulo ao tear. Macia ao toque, ela continua sendo o mais elegante dos presentes.'),
  'chongqing/hongya': ('Caverna Hongya', 'Um conjunto de casas tradicionais sobre palafitas agarradas ao penhasco, Hongya mantém viva a arquitetura antiga da cidade montanhosa. Quando seus terraços empilhados se iluminam à noite, o lugar brilha como um conto de fadas sobre o rio Jialing, e suas vielas estreitas transbordam de petiscos locais e lojas de artesanato.'),
  'chongqing/hotpot': ('Hot pot de Chongqing', 'Borbulhando com óleo vermelho ardente e a pimenta de Sichuan que adormece a língua, o hotpot é a alma flamejante de Chongqing. Diz a lenda que ele nasceu nos caldeirões dos carregadores que trabalhavam nos cais do rio. Cada pedaço mergulhado na panela de nove divisões no centro da mesa se transforma numa longa conversa entre amigos.'),
  'chongqing/monorail': ('Monotrilho de Chongqing', 'Na montanhosa Chongqing, as linhas de metrô saltam sobre os vales, e numa estação o trem atravessa, famosamente, um prédio de apartamentos. Essa cena virou o cartão-postal da cidade. Com suas ladeiras, elevadores e pontes, a \'cidade da montanha\' desafia a lógica plana dos mapas.'),
  'chongqing/river': ('Desfiladeiros do Rio Yangtzé', 'A cidade se ergue onde o Yangtzé encontra o Jialing, e os cruzeiros pelas Três Gargantas partem dos cais de Chaotianmen. Enquanto os barcos deslizam entre penhascos escarpados, milênios de comércio e poesia carregados pelo maior rio da China desfilam diante dos seus olhos.'),
  'dalian/square': ('Praça Xinghai', 'Aberta para o mar, Xinghai é uma das maiores praças urbanas do mundo e recebe seu nome de um \'mar de estrelas\'. Pipas voam sobre seus amplos gramados e ciclistas deslizam pela orla ao entardecer; na época dos festivais, a praça transborda de shows e espetáculos.'),
  'dalian/beach': ('Praias de Dalian', 'Com enseadas rochosas, praias limpas e verões frescos, Dalian é o refúgio litorâneo favorito do norte da China. A estrada Binhai, que serpenteia pela costa, oferece vistas de tirar o fôlego entre falésias e baías. Quando o calor aperta, os nortistas vêm aqui respirar o ar do mar.'),
  'dalian/football': ('Cidade do Futebol', 'Dalian é chamada de \'berço do futebol\' da China; clubes campeões que dominaram as ligas nacionais e inúmeros jogadores da seleção saíram desta cidade. As crianças que correm atrás da bola nos parques à beira-mar levam a tradição adiante, e nos dias de jogo a cidade inteira se transforma numa só arquibancada pulsante.'),
  'dalian/seafood': ('Frutos do mar', 'O Mar Amarelo, frio e cristalino, abastece as mesas de Dalian com vieiras, camarões, ouriços e pepinos-do-mar. Nos restaurantes da orla, você escolhe o pescado direto do tanque e ele é cozido no vapor em poucos minutos. O aroma de lula grelhada, por sua vez, é a alma dos mercados noturnos.'),
  'shenyang/palace': ('Palácio de Mukden', 'Construído pelos fundadores da dinastia Qing, o Palácio de Mukden foi sua primeira sede antes de a corte se mudar para Pequim. Costuma ser chamado de irmão menor da Cidade Proibida, mas tem personalidade própria, com salões octogonais de estilo manchu — hoje é um museu tombado pela UNESCO.'),
  'shenyang/tomb': ('Túmulos Qing', 'As tumbas do Leste e do Norte, que cercam a cidade, são os mausoléus monumentais dos governantes fundadores da dinastia Qing e integram a lista da UNESCO. Caminhos sagrados ladeados por estátuas de animais em pedra atravessam florestas de pinheiros centenários, e no outono os parques das tumbas se vestem de dourado.'),
  'shenyang/factory': ('Berço industrial', 'Boa parte da indústria pesada da China nasceu em Shenyang, e suas gigantescas fábricas de máquinas lhe renderam o apelido de \'Ruhr do Oriente\'. As antigas oficinas do distrito de Tiexi hoje se transformam em museus e espaços de arte, mas o orgulho das gerações que trabalharam nos tornos ainda paira no ar.'),
  'shenyang/dumpling': ('Bolinhos Laobian', 'Feitos desde a era Qing, os bolinhos no vapor Laobian são o prato-assinatura da mesa do norte. Pré-cozinhar o recheio para que ele absorva o próprio caldo dá aos bolinhos uma maciez incomparável. Uma cesta deles num dos restaurantes centenários da cidade é praticamente a recepção oficial de Shenyang.'),
  'hefei/judge': ('Templo do Juiz Bao', 'Bao Zheng, o juiz lendário da dinastia Song, nasceu em Hefei; o povo o chama de \'Bao Qingtian\', o céu sem mácula. Sua justiça incorruptível inspirou óperas e séries de televisão. Seu parque memorial à beira do lago parece um templo dedicado à integridade.'),
  'hefei/science': ('Cidade da Ciência', 'Hefei é uma cidade da ciência, que abriga algumas das principais universidades e laboratórios da China. Projetos que vão de experimentos de fusão nuclear a pesquisas quânticas são conduzidos aqui, e seus campi e parques tecnológicos dão à cidade um espírito jovem e curioso.'),
  'hefei/lake': ('Lago Chaohu', 'O Chaohu é um dos cinco grandes lagos de água doce da China e se estende logo ao sul de Hefei. Seu peixe-prata, seu camarão branco e seu caranguejo são conhecidos como os \'três tesouros\'. Nas cidadezinhas da margem, barcos de pesca e casas de chá com vista para o lago ditam um ritmo de vida lento e tranquilo.'),
  'hefei/cake': ('Bolo de gergelim Lu', 'O antigo nome de Hefei é Luzhou, e o bolinho de gergelim com recheio doce é uma guloseima secular que carrega esse nome. O aroma do gergelim tostado se encontra com um recheio macio sob a casquinha crocante. Nas festas, esse bolinho sempre ocupa o lugar de honra nas caixas de presente.'),
  'foshan/wingchun': ('Wing Chun', 'A arte marcial Wing Chun amadureceu em Foshan; o lendário mestre Ip Man treinou aqui, e por meio de seu aluno Bruce Lee esse legado se espalhou pelo mundo. Salões memoriais e escolas de artes marciais mantêm a tradição viva — encontrar mestres praticando suas formas nos parques pela manhã é cena do dia a dia.'),
  'foshan/lion': ('Dança do Leão', 'Foshan é a capital da dança do leão do sul, e o famoso herói popular Wong Fei-hung também veio destas terras. Nos festivais, leões coloridos saltam sobre postes altos ao som dos tambores. A confecção das cabeças de leão é um artesanato delicado transmitido de geração em geração.'),
  'foshan/ceramic': ('Cerâmica Shiwan', 'Os fornos de cerâmica de Shiwan ardem sem se apagar há séculos; o forno Nanfeng é um dos mais antigos fornos a lenha da China ainda em atividade. Com estatuetas de expressões vivas e ornamentos vitrificados de telhado, a cerâmica de Shiwan chega a coroar os telhados dos templos de Guangdong.'),
  'foshan/opera': ('Ópera Cantonesa', 'A ópera cantonesa, a arte cênica mais querida do sul da China, amadureceu nestas terras. Antigamente, as companhias percorriam o delta do Rio das Pérolas em \'barcos vermelhos\', apresentando-se de vila em vila. Figurinos ornamentados, acrobacias e melodias em cantonês ainda lotam os teatros hoje.'),
  'guiyang/pavilion': ('Pavilhão Jiaxiu', 'Erguido sobre uma rocha no meio do rio Nanming, o Pavilhão Jiaxiu, de três andares, é o símbolo da cidade desde a era Ming. Seu nome significa \'primeiro erudito\' e foi construído com o desejo de que a cidade formasse sábios brilhantes nos exames imperiais. Quando suas luzes tocam o rio à noite, nasce a vista mais graciosa de Guiyang.'),
  'guiyang/sourfish': ('Peixe ao molho azedo', 'O peixe em sopa azeda é o prato-assinatura de Guizhou, enraizado nas tradições de fermentação do povo Miao. O peixe de água doce é cozido num caldo vermelho vivo, acidificado com tomate e fermento de arroz. A dança entre o azedo, o picante e o aromático combina perfeitamente com o clima do sul montanhoso.'),
  'guiyang/waterfall': ('Cataratas de Huangguoshu', 'Acessível a partir de Guiyang, Huangguoshu é uma das maiores cachoeiras da Ásia. É possível atravessar a Caverna da Cortina d\'Água, atrás da parede de água trovejante, e os respingos formam arco-íris sob o sol. Na estação das chuvas, seu rugido se ouve a quilômetros vale abaixo.'),
  'guiyang/miao': ('Cultura Miao', 'As aldeias de montanha de Guizhou são o lar do povo Miao, famoso por seus adornos de prata na cabeça. Nos festivais, as jovens vestem coroas de prata feitas à mão e trajes bordados, e formam-se rodas ao som das flautas de bambu lusheng. O batique e o bordado são uma língua transmitida de mães para filhas.'),
  'changchun/film': ('Cidade do Cinema', 'O Estúdio de Cinema de Changchun é o berço do cinema da nova China; por gerações, os filmes clássicos do país foram rodados aqui. Por isso a cidade é chamada de \'Hollywood do Oriente\'. Os antigos cenários viraram parques temáticos de cinema, enquanto a tradição do festival de cinema continua.'),
  'changchun/car': ('Cidade Automotiva', 'O primeiro caminhão e o primeiro automóvel de fabricação nacional da China saíram das fábricas de Changchun, e as limusines Hongqi que transportam chefes de Estado também são produzidas aqui. O título de \'cidade do automóvel\' é bem merecido: com suas fábricas, museus e feiras, a cultura automotiva é a própria identidade da cidade.'),
  'changchun/palace': ('Palácio do Imperador Fantoche', 'O último imperador da China, Puyi, viveu neste palácio como governante fantoche durante a era de Manchukuo. Hoje um museu, o edifício conta a vigilância e a solidão escondidas atrás de seus salões imponentes. O palácio é uma janela silenciosa para a turbulência do século XX.'),
  'changchun/snow': ('Neve de Inverno', 'Os invernos longos e branquíssimos de Changchun transformam a cidade num festival de neve. Esculturas de gelo brilham à noite com luzes coloridas, e o lago cercado de florestas de Jingyuetan recebe esquiadores e amantes do trenó. Apesar do frio, o inverno é aqui a estação mais alegre do ano.'),
  'xining/lake': ('Lago Qinghai', 'O Lago Qinghai é o maior lago da China e se estende como um mar turquesa no meio do planalto. No verão, suas margens se cobrem de campos dourados de colza e aves migratórias pousam em suas ilhas. Dar a volta ao lago de bicicleta é a aventura de altitude favorita dos viajantes.'),
  'xining/monastery': ('Mosteiro de Kumbum', 'Kumbum é um dos maiores mosteiros do budismo tibetano e se ergue no local de nascimento de Tsongkhapa, fundador da escola Gelug. Suas coloridas esculturas de manteiga de iaque, seus murais e suas apliques de tecido são celebrados como as \'três artes\'. Nos pátios, as rodas de oração dos peregrinos nunca param de girar.'),
  'xining/flower': ('Flor de Colza', 'Quando chega julho, o planalto de Qinghai se cobre até o horizonte com flores douradas de colza. As margens do lago e os sopés das montanhas ondulam em mil tons de amarelo. No ar fresco das terras altas, esse espetáculo atrai fotógrafos e casais em lua de mel ano após ano.'),
  'xining/lamb': ('Iaque e Cordeiro', 'A mesa de Xining é o ponto de encontro das cozinhas hui e tibetana. Os macarrões esticados à mão chegam em tigelas fumegantes, os espetinhos de cordeiro crepitam na brasa, e o iogurte de iaque e o chá com manteiga são os sabores cotidianos do planalto. À noite, os mercados se enchem do aroma das especiarias.'),
  'guilin/karst': ('Carste do Rio Li', 'O rio Li serpenteia entre picos de calcário que emergem da névoa — exatamente a cena estampada na nota de 20 yuans. Os barcos que deslizam de Guilin a Yangshuo, as jangadas de bambu e os pescadores com cormorões compõem uma pintura chinesa viva.'),
  'guilin/elephant': ('Colina da Tromba de Elefante', 'Lembrando um elefante que mergulha a tromba no rio Li, esta rocha é o símbolo mais querido de Guilin. O arco entre a tromba e o corpo espelha uma lua cheia na água e é chamado de \'Caverna da Lua sobre a Água\'. Há séculos os poetas transformam essa paisagem em versos.'),
  'guilin/terrace': ('Terraços de Arroz de Longji', 'Envolvendo as encostas degrau por degrau, os terraços de Longji, a \'Espinha do Dragão\', são obra de séculos de trabalho dos povos Zhuang e Yao. Na primavera, os terraços inundados brilham como espelhos; no outono, tornam-se dourados. As aldeias de madeira nas alturas mantêm a vida tradicional.'),
  'guilin/osmanthus': ('Flor de Osmanthus', 'O nome de Guilin significa \'floresta de osmanthus\', e no outono a cidade mergulha no perfume doce dessas pequenas flores. O chá, o vinho e os doces de osmanthus encabeçam a lista das iguarias locais. Caminhar sob as árvores perfumadas à beira do rio é o ritual mais bonito da estação.'),
  'wenzhou/merchant': ('Espírito Empreendedor', 'O povo de Wenzhou é famoso como uma das comunidades mais empreendedoras da China, construindo pontes comerciais da Europa às Américas por meio de redes familiares e de conterrâneos. Pioneira da iniciativa privada nos anos de reforma, a cidade transborda de histórias que vão da pequena oficina ao mercado mundial.'),
  'wenzhou/shoe': ('Calçados e Couro', 'Wenzhou é considerada a capital chinesa do calçado e do couro; grande parte dos sapatos de couro do mundo sai desta cidade-fábrica. Habilidosa também em pequenos artigos, de isqueiros a óculos, a cidade ainda carrega o espírito artesão de uma época em que cada casa era uma oficina.'),
  'wenzhou/mountain': ('Montanhas Yandang', 'Famosas por suas cachoeiras e picos recortados, as montanhas Yandang são celebradas como \'a primeira montanha à beira-mar\'. A Cachoeira do Grande Dragão despenca trovejante dos penhascos, e ao entardecer as silhuetas de certos picos parecem mudar de forma. A cadeia é um geoparque protegido por sua geologia.'),
  'wenzhou/seafood': ('Frutos do Mar', 'Aberta para o Mar da China Oriental, a culinária de Wenzhou é leve e fresca, com lula, vieiras e peixe no coração da mesa cotidiana. A cozinha local Ou deixa o sabor natural dos frutos do mar em primeiro plano. A sopa de bolinhos de peixe batidos à mão é a comida de rua mais amada da cidade.'),
  'tangshan/memorial': ('Memorial do Terremoto', 'O grande terremoto de 1976 arrasou Tangshan; no parque memorial de hoje, os nomes das vítimas estão gravados em longos muros de granito. Cerimônias de lembrança são realizadas todos os anos junto a seus lagos silenciosos. A cidade reconstruída tornou-se um símbolo de resiliência e renascimento.'),
  'tangshan/coal': ('Carvão e Aço', 'A primeira mina de carvão moderna da China e uma de suas primeiras ferrovias foram inauguradas em Tangshan, e a primeira locomotiva a vapor do país também foi construída aqui. Por isso, a cidade é considerada um berço da indústria chinesa. A cultura da mineração e do aço está entrelaçada em sua identidade até hoje.'),
  'tangshan/ceramic': ('Cerâmica de Tangshan', 'Tangshan é conhecida como a \'cidade da porcelana do norte\', célebre sobretudo por sua porcelana de ossos. Seus serviços de mesa brancos, finos e translúcidos, adornam mesas em toda a China. Feiras de cerâmica e oficinas de mestres artesãos mantêm a tradição viva na cidade.'),
  'tangshan/lake': ('Parque Nanhu', 'Nanhu nasceu quando uma antiga área de subsidência de mineração foi transformada em lago e num parque exuberante; hoje é o pulmão verde da cidade. Ciclovias e jardins floridos margeiam a orla, e o parque chegou a sediar uma grande exposição de horticultura. É o símbolo de uma cidade industrial fazendo as pazes com a natureza.'),
  'anshan/steel': ('Cidade do Aço', 'Anshan abriga uma das maiores siderúrgicas da China e é conhecida como a \'capital do aço\' do país. Por gerações, o brilho dos altos-fornos iluminou as noites da cidade. Aqui, a siderurgia não é apenas um ofício, mas a própria identidade da cidade.'),
  'anshan/jade': ('Jade de Xiuyan', 'Xiuyan, na região de Anshan, é uma das grandes terras do jade na China. O Palácio do Buda de Jade, na cidade, exibe uma estátua de Buda mundialmente famosa, esculpida em um único bloco colossal de jade. As oficinas e os mercados de jade transbordam da maestria que dá vida à pedra.'),
  'anshan/mountain': ('Monte Qian', 'Qianshan, os \'Mil Picos de Lótus\', é a montanha sagrada do nordeste, com seus cumes de granito enfileirados como pétalas de lótus. Templos budistas e taoistas se espalham por suas encostas, e uma rocha gigante é famosa por lembrar um Buda sentado. Na primavera, a montanha se cobre de flores.'),
  'anshan/spring': ('Fontes Termais de Tanggangzi', 'Há mil anos se busca cura nas fontes termais de Tanggangzi; gerações se banharam em suas águas minerais e em seus banhos de lama termal, tidos como benéficos para as dores nas articulações. Tendo recebido governantes e hóspedes ilustres ao longo da história, as termas continuam sendo um refúgio para quem busca descanso.'),
  'linyi/market': ('Mercado Atacadista', 'Linyi é o maior centro de comércio atacadista do norte da China; seus imensos pavilhões de mercado vendem de agulhas a móveis. Os caminhões que partem daqui levam mercadorias a todos os cantos do país. Esse movimento rendeu à cidade o título de \'capital da logística\'.'),
  'linyi/brush': ('Mestre da Caligrafia', 'Wang Xizhi, o \'sábio da caligrafia\' da China, nasceu em Linyi; suas pinceladas fluidas são imitadas há mais de mil anos. O templo memorial e os festivais de caligrafia da cidade mantêm esse legado vivo. Em Linyi, o aroma da tinta oferece um contraponto elegante ao burburinho do comércio.'),
  'linyi/mountain': ('Monte Meng', 'Mengshan, a pérola da cordilheira Yimeng, é uma das montanhas mais altas de Shandong. Suas florestas densas, cachoeiras e ar puríssimo lhe renderam o apelido de \'bar de oxigênio natural\'. Com trilhas, aldeias nas encostas e mel de montanha, oferece aos viajantes uma fuga tranquila.'),
  'linyi/pancake': ('Panqueca Yimeng', 'A panqueca finíssima de milho e grãos é o alimento básico secular do povo das montanhas Yimeng. Assada sobre uma chapa de pedra quente, é tradicionalmente comida enrolada em cebolinha fresca. Resistente e nutritivo, esse pão tem sido um companheiro fiel na vida dura das aldeias serranas.'),
  'cangzhou/lion': ('Leão de Ferro', 'De pé há mais de mil anos, o gigantesco leão de ferro fundido é o orgulhoso emblema de Cangzhou e uma das maiores peças antigas de ferro da China. O povo o chama de \'rugido que doma o mar\'; conta-se que foi fundido para conter as enchentes. A cidade abraça seu símbolo como um guardião.'),
  'cangzhou/martial': ('Artes Marciais', 'Cangzhou é conhecida como a \'terra do wushu\' da China; escolas duras e eficazes como o bajiquan floresceram aqui. Antigamente, muitos dos guardas armados que protegiam as caravanas de mercadores vinham desta cidade. Hoje, escolas de luta e torneios mantêm a tradição de pé.'),
  'cangzhou/canal': ('Grande Canal', 'O Grande Canal, que liga Pequim a Hangzhou, passa bem no meio de Cangzhou, e por séculos a cidade enriqueceu com o comércio fluvial. Os antigos cais e os bairros portuários ainda guardam os vestígios daqueles dias. Os parques à beira do canal são hoje os favoritos para as caminhadas do fim de tarde.'),
  'cangzhou/jujube': ('Jujuba Dourada', 'A jujuba \'fio de ouro\' de Cangzhou, de casca fina e sabor de mel, é considerada a rainha das frutas secas. Deve o nome aos delicados fios dourados e doces que se esticam de sua polpa quando partida ao meio. Na colheita de outono os pomares ficam avermelhados, e o chá e os doces de jujuba são presença certa na mesa local.'),
  'nantong/textile': ('Cidade Têxtil', 'A história têxtil moderna de Nantong começou com as fábricas de algodão fundadas pelo industrial Zhang Jian. Hoje a cidade é a capital chinesa dos têxteis para o lar, com roupas de cama e cortinas que alcançam mercados no mundo todo. A cultura da tecelagem também vive na arte local do tecido estampado em azul e branco.'),
  'nantong/mountain': ('Monte Lang', 'Erguendo-se onde o Yangtzé encontra o mar, o Langshan, de cinco picos, é a colina sagrada da região. Peregrinos e viajantes sobem as escadarias até o templo budista centenário em seu cume. Do alto, o encontro do grande rio com o mar se desdobra aos seus pés.'),
  'nantong/kite': ('Pipa Assobiadora', 'As pipas \'banyao\' de Nantong zumbem pelo céu graças a dezenas de pequenos apitos presos em suas armações; quando o vento aperta, o som cresce até virar uma orquestra. A confecção dessas pipas assobiadoras é um ofício secular, transmitido de geração em geração e cultivado com carinho pelos mestres locais.'),
  'nantong/school': ('Pioneirismo Educacional', 'O industrial e reformador Zhang Jian dedicou sua fortuna à terra natal, fundando escolas modernas, bibliotecas e o primeiro museu da China criado por um cidadão chinês. A cidade se tornou, assim, pioneira em educação. Seu ideal de \'salvar a nação pela indústria\' vive na memória local.'),
  'taizhou/opera': ('Mei Lanfang', 'As raízes de Mei Lanfang, mestre lendário da ópera de Pequim, remontam a Taizhou; a graça que ele trouxe aos papéis femininos apresentou essa arte ao mundo. O parque memorial e o museu contam sua história por meio de figurinos e fotografias de palco. As melodias da ópera ainda se ouvem nos parques da cidade.'),
  'taizhou/tea': ('Chá da Manhã', 'Taizhou começa o dia com o \'zaocha\': pãezinhos no vapor, tofu seco cortado em tirinhas finas e sopa de bolinhos de peixe chegam à mesa acompanhados de bules de chá forte. O chá da manhã aqui nunca tem pressa — os vizinhos se reúnem nas casas de chá e entram no dia conversando.'),
  'taizhou/boat': ('Festival de Barcos de Qintong', 'A cada primavera, centenas de barcos se reúnem nas áreas alagadas da cidadezinha de Qintong; os remadores competem ao som dos tambores, e a espuma branca sobe quando as varas golpeiam a água. Esse festival de barcos centenário é o dia mais vibrante da cultura das cidades aquáticas e está inscrito como patrimônio nacional.'),
  'taizhou/meatball': ('Almôndega Cabeça de Leão', 'A grande e macia almôndega de porco chamada \'cabeça de leão\' é um clássico da culinária Huaiyang, batizada assim porque sua textura fofa lembra a juba de um leão. Cozida em fogo brando por horas, desmancha na boca. A versão enriquecida com ovas de caranguejo é a iguaria mais honrada da mesa de outono.'),
  'jinhua/ham': ('Presunto de Jinhua', 'O presunto de Jinhua é maturado por um método centenário de salga e secagem ao ar; seu corte vermelho-escuro e seu aroma profundo fazem dele o presunto mais famoso da China. É usado sobretudo para dar profundidade a sopas e cozidos. Um bom presunto de Jinhua é fruto de anos de paciência.'),
  'jinhua/film': ('Estúdios Hengdian', 'Hengdian, na região de Jinhua, é o maior estúdio de cinema a céu aberto do mundo, onde se erguem réplicas gigantes da Cidade Proibida e de antigos palácios imperiais. Inúmeros filmes e séries de época são rodados aqui. Passeando pelos cenários, os visitantes podem cruzar com atores em trajes completos.'),
  'jinhua/cave': ('Caverna Shuanglong', 'Entrar em Shuanglong, a caverna do \'Dragão Duplo\', é inesquecível: os visitantes deslizam de barco, deitados de costas, sob um portal baixo de rocha. Lá dentro se abre um mundo subterrâneo fresco, adornado de estalactites e estalagmites. A caverna já era elogiada nos escritos dos viajantes de antigamente.'),
  'jinhua/bridge': ('Pontes Antigas', 'Os arredores de Jinhua, antigamente chamada Wuzhou, estão salpicados de pontes de pedra em arco e cidadezinhas aquáticas cortadas por canais. Casas de paredes brancas e telhas escuras se refletem na água, e casas de chá se agrupam junto às pontes. A cena traz até hoje o elegante estilo de vida da região de Jiangnan.'),
  'wuhu/park': ('Fangte Wonderland', 'Wuhu abriga um conjunto de alguns dos maiores parques temáticos da China, oferecendo às famílias dias de emoção, das montanhas-russas aos mundos de animação. A cidade se transformou, assim, na capital do entretenimento da região; nos fins de semana, visitantes chegam em massa das províncias vizinhas.'),
  'wuhu/ironart': ('Pintura em Ferro', 'Na arte da \'pintura em ferro\' de Wuhu, o ferro forjado se transforma em quadros elegantes que lembram pinceladas; esse ofício de cerca de três séculos leva o espírito da pintura a nanquim para o metal. Com martelo e bigorna, os mestres moldam montanhas, pinheiros e pássaros. Essas obras são o presente mais original da cidade.'),
  'wuhu/rice': ('Porto do Arroz', 'Wuhu foi, ao longo da história, um dos maiores mercados de arroz da China; graças à sua posição no Yangtzé, a colheita do sul trocava de mãos aqui. Armazéns modernos substituíram os carregadores que levavam sacas nos cais, mas a cidade se orgulha de sua herança no comércio de grãos.'),
  'wuhu/river': ('Porto do Rio Yangtzé', 'Seu porto movimentado às margens do Yangtzé faz de Wuhu a porta de entrada da província de Anhui para o mundo. Navios de carga e guindastes de contêineres nunca param ao longo do rio, e esse movimento é um belo espetáculo visto dos parques da orla. O rio traz à cidade tanto o comércio quanto o frescor das noites.'),
  'huangshan/peak': ('Montanha Amarela', 'Com picos de granito, mar de nuvens, pinheiros retorcidos e fontes termais, Huangshan é a montanha mais famosa da China e Patrimônio da UNESCO. Essas belezas, conhecidas como as \'quatro maravilhas\', inspiram pintores e poetas há séculos. Estar acima das nuvens ao nascer do sol é uma lembrança para a vida toda.'),
  'huangshan/village': ('Vila de Hongcun', 'Hongcun, uma aldeia hui de paredes brancas e telhas escuras, entrecortada por canais e com um lago em forma de meia-lua, parece saída de uma pintura e é tombada pela UNESCO. Seu traçado foi desenhado para lembrar o corpo de um boi. Quando a névoa da manhã desce sobre o lago, os pintores armam seus cavaletes na margem.'),
  'huangshan/tea': ('Chá Maofeng', 'Colhido nas encostas enevoadas, o Huangshan Maofeng é um dos chás verdes mais famosos da China, batizado por suas folhas aveludadas em forma de pico. A colheita do início da primavera é a mais valorizada. Deixa na xícara uma delicada nota de orquídea, como se as nuvens da montanha estivessem tecidas na folha.'),
  'huangshan/ink': ('Tinta e Artes de Huizhou', 'A antiga região de Huizhou produziu as barras de tinta e as pedras de tinta mais prestigiadas da China, procuradas pelos calígrafos há séculos. Seus casarões, adornados com entalhes em madeira, tijolo e pedra, nascem do mesmo espírito artesanal. A cultura hui une tinta e arquitetura numa única estética.'),
  'yichun/moon': ('Monte Mingyue', 'O Monte Mingyue, cujo nome significa \'Lua Brilhante\', é o símbolo de Yichun, cidade também conhecida por seus festivais com tema lunar. Um teleférico leva os visitantes a trilhas à beira de precipícios e a campos de altitude. Quando a névoa se dissipa no cume, os vales lá embaixo brilham com uma luz prateada.'),
  'yichun/spring': ('Fontes Termais', 'As fontes termais da cidadezinha de Wentang, em Yichun, são ricas em selênio, mineral raro, e há muito consideradas curativas. Hotéis-spa e piscinas ao ar livre recebem visitantes o ano inteiro. O encontro do ar da montanha com as águas quentes fez da cidade um dos destinos termais favoritos da China.'),
  'yichun/zen': ('Budismo Chan', 'As montanhas de Yichun estão entre as terras onde nasceram importantes escolas do budismo Chan (Zen) chinês; templos centenários se espalham por vales silenciosos. Os jardins de chá e as salas de meditação dos monges convidam os visitantes a desacelerar. O som dos sinos ecoa pela floresta enevoada.'),
  'yichun/rice': ('Planície de Yuan-He', 'A fértil planície do rio Yuan tem sido, ao longo da história, o celeiro de Jiangxi; suas terras bem irrigadas rendem fartas colheitas de arroz ano após ano. Nas aldeias, a época da colheita passa em clima de festa. O macarrão local feito de arroz fresco e o vinho de arroz levam à mesa a generosidade da planície.'),
  'zhangzhou/narcissus': ('Narciso', 'Os bulbos de narciso mais famosos da China são cultivados em Zhangzhou, e a flor é um enfeite indispensável da Festa da Primavera. Os artesãos trabalham os bulbos com cortes especiais para que as flores desabrochem em formas graciosas. Um narciso florescendo em casa no ano-novo é tido como um bom presságio para o ano que chega.'),
  'zhangzhou/tulou': ('Casas de Terra Hakka', 'As gigantescas fortalezas circulares de terra batida chamadas \'tulou\' reúnem uma aldeia inteira sob o mesmo teto e são Patrimônio da UNESCO. Suas paredes grossas garantem tanto defesa quanto frescor, e a vida comunitária continua em seus pátios há séculos. Agrupados entre colinas verdes, os tulou compõem uma paisagem de livro de histórias.'),
  'zhangzhou/banana': ('Frutas Tropicais', 'O delta quente e úmido de Zhangzhou dá frutos o ano inteiro: bananais, pomares de longan e plantações de tangerina se estendem até o horizonte. O pomelo grande e suculento da região também é um favorito da mesa. Em qualquer estação, os mercados de frutas são uma festa de cores e aromas.'),
  'zhangzhou/coast': ('Ilha de Dongshan', 'Com praias de areia dourada e vilas de pescadores, a Ilha Dongshan é a pérola do litoral sul. Sua vista mais famosa é a gigantesca \'rocha movida pelo vento\', equilibrada à beira de um penhasco e que, dizem, balança suavemente com a brisa. Ao entardecer, os barcos que voltam ao porto trazem a pesca fresca do dia.'),
  'guangzhou/tower': ('Canton Tower', 'Erguendo-se à beira do Rio das Pérolas, a torre ganhou o apelido de \'Cintura Fina\' graças à sua silhueta esbelta e retorcida. Uma das torres mais altas do mundo, ela muda de cor à noite com milhares de luzes de LED, coroando o horizonte moderno de Guangzhou com vistas deslumbrantes do delta.'),
  'guangzhou/dimsum': ('Chá da Manhã', 'As manhãs em Guangzhou começam com o \'yum cha\': bules de chá servidos ao lado de dim sum cozidos no vapor em cestas de bambu empilhadas. Bolinhos de camarão, siu mai e pastéis folhados acompanham conversas que se estendem por horas — um ritual que é a própria alma da culinária cantonesa.'),
  'guangzhou/academy': ('Academia do Clã Chen', 'Construído no fim da era Qing com contribuições das famílias de sobrenome Chen, este grandioso salão ancestral encanta com entalhes em madeira, relevos em pedra e figuras coloridas de cerâmica que lotam seus telhados. Hoje abriga um museu de arte popular que exibe o auge do artesanato do sul da China.'),
  'guangzhou/flower': ('Cidade das Flores', 'Graças ao clima ameno, as flores desabrocham em Guangzhou o ano inteiro, o que rendeu à cidade o antigo apelido de \'Cidade das Flores\'. Antes do Ano-Novo Chinês, enormes feiras de flores tomam as ruas, onde as famílias compram pés de kumquat e ramos de pessegueiro para atrair sorte no ano que chega.'),
  'wuhan/crane': ('Torre da Garça Amarela', 'Debruçada sobre o Yangtzé, a Torre do Grou Amarelo tem sua história ligada à era dos Três Reinos e figura entre as torres mais célebres da China. Imortalizada nos versos de poetas como Cui Hao e Li Bai, foi destruída e reconstruída muitas vezes, mas sua alma poética permanece intacta.'),
  'wuhan/noodle': ('Macarrão Hot-Dry', 'O reganmian, ou \'macarrão quente e seco\', mistura macarrão cozido e elástico com pasta de gergelim, conservas e cebolinha. Os moradores começam o dia com uma tigela comprada nas barracas de rua — o café da manhã é tão querido em Wuhan que ganhou nome próprio, \'guozao\', a arte de passar bem a manhã.'),
  'wuhan/duckneck': ('Pescoço de pato apimentado', 'O pescoço de pato cozido por horas num caldo perfumado de pimentas e especiarias é o petisco mais amado de Wuhan. Saboreado direto do osso, seu sabor picante e levemente anestesiante é o companheiro indispensável das conversas à beira do rio e da cerveja gelada nas longas noites de verão.'),
  'wuhan/university': ('Cerejeiras do campus', 'A cada primavera, o campus histórico da Universidade de Wuhan desaparece sob nuvens de flores de cerejeira rosa e brancas, atraindo visitantes de toda a China. Emolduradas pelos prédios antigos nas encostas da colina Luojia, as flores criam a paisagem primaveril mais romântica da cidade.'),
  'tianjin/eye': ('Olho de Tianjin', 'Erguida bem no meio de uma ponte sobre o Rio Hai, a Tianjin Eye é uma das raras rodas-gigantes do mundo construídas diretamente sobre águas correntes. Do alto, as duas margens se revelam de uma só vez: fachadas de estilo europeu de um lado, torres de vidro reluzentes do outro.'),
  'tianjin/baozi': ('Baozi Goubuli', 'Feitos desde a era Qing, os pãezinhos Goubuli são famosos pela massa fina, pelo recheio suculento de porco e pelas dobras cuidadosamente pregueadas. O nome curioso significa \'nem um cachorro daria atenção\' — diz a lenda que o fundador era tão ocupado dobrando pãezinhos que nunca conversava com os clientes.'),
  'tianjin/crosstalk': ('Comédia Crosstalk', 'O xiangsheng é uma arte cênica tradicional em que dois comediantes duelam com falas velozes, trocadilhos e imitações. Enraizada nas casas de chá de Tianjin, ela deu à cidade a fama de berço da comédia chinesa, e até hoje o público a aprecia acompanhada de xícaras fumegantes de chá.'),
  'tianjin/architecture': ('Bairro Europeu', 'Wudadao, as \'Cinco Grandes Avenidas\', preserva centenas de vilas em estilo europeu deixadas pela época das concessões estrangeiras. Com estilos britânico, francês e italiano lado a lado, o bairro rendeu a Tianjin o apelido de \'museu da arquitetura mundial\' — melhor explorado de charrete ou bicicleta.'),
  'xiamen/island': ('Ilha Gulangyu', 'Em Gulangyu, bem em frente a Xiamen, veículos motorizados são proibidos — pelas vielas estreitas só se ouvem passos e melodias de piano ao longe. Com antigos consulados e vilas cobertas de buganvílias, a ilha, patrimônio da UNESCO, é um museu a céu aberto a uma curta viagem de balsa.'),
  'xiamen/piano': ('Ilha do Piano', 'A música ocidental criou raízes em Gulangyu no século XIX, trazida por missionários e comerciantes que ali se estabeleceram. Famosa pelo número impressionante de pianos por família, a \'Ilha do Piano\' mantém a tradição viva com um museu do piano e gerações de músicos.'),
  'xiamen/egret': ('Garça-branca', 'O antigo nome de Xiamen, \'Ludao\', significa \'ilha das garças\', e elegantes garças brancas ainda hoje planam sobre suas praias e lagoas. Adotada como emblema da cidade, a ave aparece por toda parte, de esculturas a nomes de ruas, lembrando o laço profundo de Xiamen com o mar e a natureza.'),
  'xiamen/oyster': ('Omelete de ostra', 'Ostras frescas envolvidas em ovo e amido de batata-doce, fritas até ficarem crocantes por fora e macias por dentro — este omelete é um clássico da comida de rua da costa de Minnan. Servido com molho agridoce picante nos mercados noturnos de Xiamen, é igualmente adorado do outro lado do estreito, em Taiwan.'),
  'harbin/ice': ('Festival de Gelo', 'Todo inverno, blocos gigantes cortados do congelado Rio Songhua viram palácios, torres e escorregadores que brilham em cores vivas ao anoitecer. O Festival de Gelo e Neve de Harbin, o maior do gênero no mundo, transforma a cidade gelada num reino de conto de fadas para milhões de visitantes.'),
  'harbin/cathedral': ('Catedral de Santa Sofia', 'Com sua cúpula verde em forma de cebola e paredes de tijolo vermelho, a Catedral de Santa Sofia é a relíquia mais imponente da era ferroviária russa de Harbin. Hoje museu de arquitetura, ela preside uma praça animada, com pombos e músicos de rua — o ponto de encontro favorito da cidade.'),
  'harbin/sausage': ('Linguiça vermelha', 'A linguiça vermelha defumada, feita segundo receitas russas trazidas por imigrantes há mais de um século, é o sabor emblemático de Harbin. Seu aroma de fumaça de lenha e o toque suave de alho combinam perfeitamente com pão fresco e cerveja gelada, levando as raízes europeias da cidade direto à mesa.'),
  'harbin/accordion': ('Cidade da Música', 'Violinos, acordeões e a ópera chegaram com os colonos russos, fazendo de Harbin um dos primeiros centros de música ocidental da China. Lar da orquestra sinfônica pioneira do país, a cidade mantém vivo o título de \'cidade da música\' com um tradicional festival que acontece todo verão.'),
  'fuzhou/alley': ('Três Ruas e Sete Vielas', 'O bairro das \'Três Ruas e Sete Vielas\' preserva casas de paredes brancas e telhas pretas das eras Ming e Qing. Letrados e estadistas viveram um dia em suas estreitas ruelas de pedra; hoje, seus casarões com pátios abrigam casas de chá e ateliês de artesanato, mantendo o bairro antigo vibrante e vivo.'),
  'fuzhou/banyan': ('Cidade das Figueiras', 'Graças ao plantio de árvores iniciado na era Song, as ruas de Fuzhou se encheram de figueiras-de-bengala que resistem há séculos. Suas raízes aéreas pendem como longas barbas, oferecendo sombra fresca e profunda nos verões úmidos — por isso a cidade é carinhosamente chamada de \'Rongcheng\', a Cidade dos Banianos.'),
  'fuzhou/hotspring': ('Fontes termais', 'Fontes termais naturais brotam bem no coração de Fuzhou, alimentando uma cultura de banhos que remonta a mais de mil anos. Os moradores ainda relaxam nos spas de bairro para espantar o cansaço, fazendo de Fuzhou uma das raras cidades da China construídas diretamente sobre um tesouro geotérmico.'),
  'fuzhou/soup': ('Sopa \'Buda Pula o Muro\'', 'O fotiaoqiang é uma sopa lendária em que dezenas de ingredientes preciosos — vieiras, cogumelos, abalone e muito mais — cozinham por horas num pote de barro. O nome vem de um verso que diz que o aroma é tão irresistível que até um monge pularia o muro para prová-la; é a joia da coroa da culinária de Fujian.'),
  'dongguan/robot': ('Fábrica do Mundo', 'No coração do Delta do Rio das Pérolas, Dongguan é um gigante industrial cujas fábricas produzem uma parcela impressionante dos eletrônicos e brinquedos do mundo. As linhas de montagem vêm dando lugar a fábricas inteligentes e braços robóticos, enquanto a \'fábrica do mundo\' se reinventa para uma nova era.'),
  'dongguan/basketball': ('Cidade do Basquete', 'O basquete é uma paixão em Dongguan: há quadras em quase todos os bairros e um caminho sólido que leva das quadras de rua à liga profissional. O Guangdong Southern Tigers, um dos clubes mais vitoriosos do basquete chinês, joga aqui — a cidade foi oficialmente coroada a \'cidade do basquete\' da China.'),
  'dongguan/keyuan': ('Jardim Keyuan', 'Construído por um funcionário da era Qing, o Keyuan é celebrado por encaixar com maestria pavilhões, lagos e corredores sinuosos num espaço notavelmente compacto. Considerado um dos quatro grandes jardins clássicos de Guangdong, ele destila o refinamento discreto do paisagismo do sul da China.'),
  'dongguan/cannon': ('Fortes de Humen', 'Os fortes de Humen guardavam a foz do Rio das Pérolas com fileiras de canhões. Foi nesta costa que, em 1839, o comissário Lin Zexu destruiu o ópio confiscado, acendendo o estopim da Guerra do Ópio; hoje, as baterias e um museu contam esse momento decisivo da história moderna da China.'),
  'lanzhou/beefnoodle': ('Lámen de carne de Lanzhou', 'O lámen puxado à mão de Lanzhou segue uma fórmula famosa: caldo de carne translúcido, nabo branco, óleo de pimenta vermelha e coentro bem verde. Os mestres esticam a massa em fios finíssimos em segundos, diante dos seus olhos, e a tigela fumegante da manhã é ao mesmo tempo um ritual diário e um dos pratos mais famosos da China.'),
  'lanzhou/waterwheel': ('Rodas d\'água', 'Rodas d\'água gigantes de madeira, construídas na era Ming para levar as águas do Rio Amarelo aos campos, tornaram-se o símbolo eterno de Lanzhou. No parque das rodas d\'água à beira do rio, réplicas fiéis dessas maravilhas da engenharia ainda giram, e seu rangido lento ecoa séculos de irrigação engenhosa.'),
  'lanzhou/statue': ('Estátua da Mãe Rio Amarelo', 'Na margem do rio, a escultura \'Mãe Rio Amarelo\' mostra uma mãe serena, de cabelos ondulantes, com um bebê deitado sobre o peito. Ela encarna o rio que amamentou a civilização chinesa, e a criança representa o povo nascido de suas águas — a mais tocante homenagem de Lanzhou ao seu rio.'),
  'lanzhou/raft': ('Balsa de pele de carneiro', 'Balsas feitas de peles de carneiro infladas e amarradas a uma armação de madeira transportaram cargas e passageiros pelo Rio Amarelo durante séculos. Hoje essas embarcações tradicionais levam visitantes a passeio pela orla de Lanzhou, e deslizar sobre a correnteza barrenta continua sendo a experiência mais autêntica da cidade.'),
  'urumqi/bazaar': ('Grande Bazar', 'O Grande Bazar de Urumqi, com sua torre de inspiração islâmica e seus salões abobadados, mantém vivo o espírito do comércio da Rota da Seda. As bancas transbordam de frutas secas, especiarias, seda e facas artesanais, e ao anoitecer a praça ganha vida com apresentações de música e dança.'),
  'urumqi/tianshan': ('Lago Celestial', 'O Tianchi, o \'Lago Celestial\', repousa aos pés do nevado Pico Bogda, na cordilheira Tianshan, com suas águas de um azul profundo emolduradas por florestas de abetos. A lenda diz que ali a Rainha Mãe do Oeste dava seus banquetes, e o lago integra as montanhas Tianshan, patrimônio da UNESCO.'),
  'urumqi/kebab': ('Kebab de cordeiro', 'Espetinhos de cordeiro chiando sobre o carvão são polvilhados com cominho e pimenta em flocos, e seu aroma defumado percorre as ruas de Urumqi. Ícone da culinária uigur, o kebab é melhor apreciado no mercado noturno, com naan fresquinho saído do tandoor e bules de chá bem forte.'),
  'urumqi/dance': ('Dança uigur', 'As danças uigures, rodopiando ao ritmo dos tambores e das cordas do rawap e do dutar, coroam todos os casamentos e festas. Com gestos graciosos das mãos e giros cada vez mais velozes, elas são uma arte alegre e comunitária — os convidados sempre acabam puxados para a roda para dançar também.'),
  'haikou/coconut': ('Cidade do Coco', 'Em Haikou, capital da Ilha de Hainan, as avenidas são sombreadas por fileiras de coqueiros — daí o apelido \'Yecheng\', a Cidade do Coco. Os vendedores de rua abrem cocos gelados com um golpe de facão, oferecendo o remédio mais natural para o calor tropical.'),
  'haikou/arcade': ('Arcadas Qilou', 'As antigas ruas comerciais de Haikou são ladeadas por \'qilou\' — sobrados com arcadas construídos por mercadores que voltavam do Sudeste Asiático. Suas passagens cobertas protegem os pedestres da chuva tropical e do sol forte, uma elegante arquitetura da sombra que serve à cidade há cerca de um século.'),
  'haikou/crater': ('Crateras vulcânicas', 'Logo nos arredores de Haikou, um antigo campo vulcânico virou um geoparque verdejante de crateras extintas e túneis de lava. O basalto deixado pelas erupções de outrora ainda molda a vida local — casas e muros dos vilarejos são feitos dele — e os visitantes podem descer a pé até a boca de uma cratera.'),
  'haikou/turtle': ('Mar tropical', 'As águas quentes e cristalinas da costa de Hainan abrigam recifes de coral e pradarias marinhas repletas de vida. Tartarugas marinhas se alimentam e desovam nessas praias, e graças a projetos de conservação, os filhotes correndo em direção às ondas voltaram a ser uma cena cheia de esperança.'),
  'luoyang/grotto': ('Grutas de Longmen', 'Esculpidas nos penhascos que ladeiam o Rio Yi, as Grutas de Longmen guardam dezenas de milhares de estátuas budistas e são patrimônio da UNESCO. Iniciadas na era Wei do Norte e levadas ao auge sob os Tang, culminam no colossal Buda Vairocana, de sorriso sereno.'),
  'luoyang/peony': ('Capital da Peônia', 'Luoyang é sinônimo de peônias desde a era Tang; a lenda conta que a flor foi exilada aqui por desafiar a ordem da imperatriz Wu Zetian de florescer no inverno. Todo mês de abril a cidade explode em cores no seu festival de peônias, celebrando a flor que a tradição coroa como \'rainha das flores\'.'),
  'luoyang/whitehorse': ('Templo do Cavalo Branco', 'Fundado no ano 68 d.C., o Templo do Cavalo Branco é honrado como o primeiro templo budista da China. Seu nome lembra o cavalo branco que, segundo a tradição, trouxe as escrituras sagradas da Índia. Símbolo da chegada do budismo ao país, continua sendo um lugar ativo de culto e peregrinação.'),
  'luoyang/capital': ('Capital antiga', 'Luoyang foi capital de treze dinastias, entre elas a Han e a Tang, ocupando o próprio centro da história chinesa. Esta cidade milenar da bacia do Rio Amarelo era um dos pontos finais orientais da Rota da Seda, e seus museus e ruínas guardam milênios de memória imperial.'),
  'shantou/gongfutea': ('Chá Gongfu', 'O chá gongfu da região de Chaoshan é uma arte cerimonial de infusão: xícaras minúsculas enchidas, esvaziadas e reabastecidas em rodadas cuidadosas. Oferecer chá aqui é o gesto mais profundo de respeito, e o arranjo de três xícaras e os movimentos precisos das mãos passam de geração em geração.'),
  'shantou/beefpot': ('Hot pot de carne bovina', 'O hotpot de carne de Chaoshan é devotado ao frescor: a carne abatida no mesmo dia é separada por corte e mergulhada num caldo límpido por meros segundos. Cada fatia tem seu tempo exato de cozimento, e a carne é molhada num molho satê de amendoim, que realça sua doçura natural.'),
  'shantou/opera': ('Ópera Teochew', 'Com séculos de história, a ópera Teochew encanta plateias com melodias delicadas cantadas no dialeto local e figurinos bordados deslumbrantes. Levada ao exterior pelos emigrantes de Chaoshan, essa arte cênica se espalhou pelo Sudeste Asiático e ainda hoje liga a comunidade às suas raízes.'),
  'shantou/harbor': ('Porto de Shantou', 'Aberto ao comércio exterior no século XIX, o porto de Shantou tornou-se a porta pela qual incontáveis habitantes de Chaoshan emigraram para além-mar. Muitas famílias chinesas do Sudeste Asiático têm raízes aqui, um vínculo honrado nas cartas \'qiaopi\' que os migrantes enviavam para casa.'),
  'baoding/mansion': ('Mansão do Governador', 'A Mansão do Governador de Zhili foi, na era Qing, a sede dos vice-reis que governavam Zhili, a província que cercava a capital imperial. Figuras poderosas como Li Hongzhang e Yuan Shikai serviram aqui, e seus pátios e salões bem preservados são um documento vivo da administração provincial do império.'),
  'baoding/donkeyburger': ('Hambúrguer de carne de burro', 'O \'lurou huoshao\' recheia um pão achatado, crocante e recém-saído do forno, com carne de burro temperada e cozida lentamente. Elogiada num ditado local — \'no céu, carne de dragão; na terra, carne de burro\' — é a comida de rua mais famosa de Baoding e um orgulho regional apaixonado.'),
  'baoding/balls': ('Bolas de saúde', 'As bolas de Baoding, giradas na palma da mão, são um instrumento tradicional de exercício manual fabricado desde a era Ming. Lâminas sonoras em seu interior emitem dois tons ao girar — um agudo, um grave — e acredita-se que a prática cultiva tanto a destreza dos dedos quanto uma mente calma e concentrada.'),
  'baoding/reeds': ('Pântano de Baiyangdian', 'Baiyangdian, uma das maiores zonas úmidas do norte da China, é um labirinto de centenas de lagoas ligadas por canais margeados de juncos. No verão, flores de lótus cobrem as águas e os juncais se enchem de canto de pássaros, enquanto os aldeões ainda pescam e colhem juncos em barcos estreitos — a \'Pérola do Norte\'.'),
  'jilin/rime': ('Geada de Jilin', 'Nas noites de inverno, a névoa que sobe do Rio Songhua, que não congela, cristaliza-se nos galhos da margem como uma geada branca e reluzente. Conhecido como \'wusong\', o fenômeno figura entre as quatro grandes maravilhas naturais da China, e ao nascer do sol as árvores prateadas brilham como num conto de fadas.'),
  'jilin/snowboard': ('Estação de esqui', 'Com invernos longos e nevados, Jilin está entre as principais regiões de esportes de inverno da China. Resorts modernos nas montanhas ao redor atraem esquiadores e praticantes de snowboard com neve seca e fofa, e a região formou boa parte dos atletas de jogos de inverno do país.'),
  'jilin/meteorite': ('Museu do Meteorito', 'Em 1976, um meteorito se despedaçou nos céus de Jilin, produzindo uma das maiores chuvas de meteoritos rochosos já registradas. O fragmento principal, com mais de uma tonelada, está exposto no museu de meteoritos da cidade, onde os visitantes podem ficar cara a cara com esse hóspede vindo do espaço.'),
  'jilin/skate': ('Rio Songhua congelado', 'Quando o inverno chega, os trechos calmos do Rio Songhua congelam em camadas espessas e viram a pista de patinação a céu aberto da cidade. Patinadores deslizam, piões giram sobre o gelo e crianças apostam corrida de trenó — nos meses frios, a beira do rio é o ponto de encontro mais animado de Jilin.'),
  'ordos/khan': ('Mausoléu de Gengis Khan', 'O Mausoléu de Genghis Khan, na estepe de Ordos, homenageia o grande cã sob três cúpulas em forma de yurta mongol. Há séculos os guardiões Darhad mantêm ali os fogos cerimoniais e as oferendas, fazendo do santuário um dos lugares mais sagrados da cultura mongol.'),
  'ordos/cashmere': ('Caxemira', 'As cabras endurecidas pelos invernos rigorosos da estepe de Ordos desenvolvem uma lã interna finíssima que rende uma das melhores caxemiras do mundo. Esse \'ouro macio\' fez da cidade um centro global de produção de caxemira, transformando a tradição pastoril numa moderna indústria de luxo.'),
  'ordos/sanddune': ('Dunas Cantantes', 'As dunas imponentes do Deserto de Kubuqi emitem um zumbido profundo e ressonante quando se desliza por suas encostas — daí o nome \'areias que cantam\'. Os visitantes cruzam as dunas em caravanas de camelos ou descem de sandboard, e ao pôr do sol o deserto se tinge de dourado num silêncio que parece poesia.'),
  'ordos/yurt': ('Iurta mongol', 'A yurta mongol, redonda e coberta de feltro branco, foi projetada para resistir aos ventos da estepe e, ao mesmo tempo, ser desmontada facilmente para a próxima migração. Sua porta olha para o sul e a lareira central é o coração da vida familiar; dormir numa yurta na estepe de Ordos é a melhor forma de provar a hospitalidade nômade.'),
  'jining/confucius': ('Templo de Confúcio', 'Qufu, no território de Jining, é a cidade natal do grande sábio Confúcio. O templo erguido em sua honra, a mansão da família Kong e o cemitério arborizado do clã formam juntos um patrimônio da UNESCO; seus pátios de ciprestes e estelas antigas são testemunhas silenciosas de mais de dois mil anos de reverência.'),
  'jining/barge': ('Grande Canal', 'Porto movimentado do Grande Canal que liga Pequim a Hangzhou, Jining prosperou durante séculos com as barcaças de grãos e o vai e vem dos mercadores. O comércio do canal trouxe riqueza e uma vibrante cultura de cais à cidade, e os trechos sul da grande via ainda transportam carga até hoje.'),
  'jining/sword': ('Heróis de Liangshan', 'No romance clássico \'Margem da Água\', 108 heróis injustiçados por oficiais corruptos se reúnem nas colinas de Liangshan, cercadas de pântanos. Liderados por Song Jiang, os fora da lei lutam pelos pobres contra os poderosos. Hoje, Liangshan recebe visitantes com lugares que evocam as cenas lendárias do romance.'),
  'jining/fishnet': ('Lago Weishan', 'O Weishan, um dos maiores lagos de água doce do norte da China, cobre-se a cada verão de campos de lótus que se estendem até o horizonte. Famílias de pescadores lançam redes com técnicas passadas por gerações, vivendo ao ritmo do lago, e a cozinha local celebra o peixe fresco e a raiz de lótus crocante.'),
  'langfang/culture': ('Centro Cultural da Rota da Seda', 'Situado entre Pequim e Tianjin, o vasto e moderno centro cultural de Langfang reúne sob o mesmo teto exposições sobre a Rota da Seda, artes cênicas e artesanato. Inspirado na estética das antigas rotas de caravanas, o edifício simboliza o papel da cidade como ponte cultural entre duas grandes metrópoles.'),
  'langfang/furniture': ('Cidade dos Móveis', 'O distrito de Xianghe, em Langfang, está entre os maiores polos de fabricação e comércio de móveis da China. Lojas e oficinas se estendem por quilômetros, oferecendo de tudo, da marcenaria clássica em jacarandá ao design moderno — famílias que montam casa por todo o norte da China vêm comprar aqui.'),
  'langfang/tunnel': ('Túneis de Guerra Antigos', 'Ao longo da antiga fronteira entre a dinastia Song e os Liao do norte, redes secretas de túneis defensivos foram escavadas sob a terra. De pé há cerca de mil anos, essas passagens revestidas de tijolos, com dutos de ventilação e câmaras de emboscada, são testemunhas subterrâneas das antigas guerras de fronteira.'),
  'langfang/themepark': ('Parque \'Cidade Nº 1\'', '\'Tianxia Diyi Cheng\', a \'Primeira Cidade Sob o Céu\', é um imenso parque temático que recria com grandiosidade as muralhas e os portões da velha Pequim. Com feiras de templo, espetáculos tradicionais e arquitetura clássica, leva as famílias numa viagem ao passado imperial da capital.'),
  'yancheng/salt': ('Cidade do Sal', 'O nome de Yancheng significa \'cidade do sal\': durante séculos, suas salinas costeiras encheram os cofres do império. O sal obtido pela evaporação da água do mar sob o sol moldou o destino da cidade, e essa herança vive hoje em museus, nomes de lugares e na memória local.'),
  'yancheng/crane': ('Grou-de-coroa-vermelha', 'As zonas úmidas costeiras de Yancheng são o maior refúgio de invernada do mundo para os grous-de-coroa-vermelha selvagens. Símbolos de longevidade e graça na cultura chinesa, essas aves majestosas migram do norte para cá todo inverno, e seu voo pausado sobre os juncais encanta os observadores de aves.'),
  'yancheng/elk': ('Cervo-do-padre-david', 'O cervo milu chegou a desaparecer da natureza na China, sobrevivendo apenas em parques no exterior. Reintroduzida na reserva de Dafeng, em Yancheng, a espécie prosperou, e hoje a maior manada de milu do mundo vagueia livre por essas campinas úmidas do litoral — um triunfo da conservação.'),
  'yancheng/wetland': ('Zona Úmida Costeira', 'As planícies de maré da costa do Mar Amarelo formam uma imensa escala para aves migratórias, inscrita como Patrimônio Mundial da UNESCO. Milhões de aves limícolas da rota migratória Ásia Oriental-Australásia descansam e se alimentam aqui, enchendo os lamaçais com o bater de asas a cada primavera e outono.'),
  'huzhou/brush': ('Pincel Hu', 'O pincel Hu, produzido em Huzhou, é o mais prestigiado dos pincéis de escrita chineses, um dos \'quatro tesouros do estúdio\'. Pontas de pelo de cabra, coelho e fuinha passam por dezenas de etapas minuciosas até ficarem ao mesmo tempo afiadas e flexíveis — para os calígrafos, seu valor é inestimável.'),
  'huzhou/bamboo': ('Mar de Bambu de Anji', 'As florestas de bambu que cobrem as colinas de Anji ondulam ao vento como um mar verde sem fim. Cenário de cenas inesquecíveis do filme \'O Tigre e o Dragão\', elas renovam os visitantes com ar fresco, trilhas para caminhada e uma culinária local que celebra os tenros brotos de bambu.'),
  'huzhou/silkworm': ('Bicho-da-seda', 'Na margem sul do Lago Tai, Huzhou é há milhares de anos um coração da seda de amoreira. Seu sistema tradicional, que combina pomares de amoreiras com tanques de peixes, é hoje reconhecido como patrimônio agrícola mundial, e a seda de Huzhou já vestiu imperadores e suas cortes.'),
  'huzhou/whitetea': ('Chá Branco de Anji', 'O chá branco de Anji é, na verdade, um chá verde, feito de uma variedade rara cujas folhas de primavera brotam tão pálidas que parecem quase brancas. Amado pelo frescor suave e adocicado e pela baixa adstringência, tem uma janela de colheita curtíssima que o torna um dos chás mais cobiçados da China.'),
  'quzhou/go': ('Go (Weiqi)', 'A lenda conta que um lenhador no Monte Lanke assistiu a dois imortais jogando Go, tão absorto que eras se passaram e o cabo do seu machado apodreceu. Graças a essa história, Quzhou é reverenciada como terra sagrada do Go, e o antigo jogo de estratégia é celebrado com entusiasmo por toda a cidade.'),
  'quzhou/peaks': ('Monte Jianglang', 'Os três colossais pilares de pedra do Monte Jianglang erguem-se a prumo da floresta verde em direção ao céu. Exemplo notável das formações de arenito vermelho chamadas \'danxia\', a montanha é patrimônio da UNESCO, e percorrer a fenda estreita entre os pilares é uma experiência de tirar o fôlego.'),
  'quzhou/ponkan': ('Tangerina Ponkan de Quzhou', 'As tangerinas ponkan cultivadas nas colinas amenas de Quzhou são famosas pela casca fácil de descascar e pelos gomos doces como mel. No fim do outono os pomares se tingem de laranja, a colheita reúne as famílias entre as árvores e a fruta alegra as mesas de inverno de toda a região.'),
  'quzhou/cake': ('Pão sírio assado', 'O pão assado de Quzhou é feito colando discos de massa fermentada na parede interna escaldante de um forno de barril. Sob a casca crocante coberta de gergelim esconde-se um recheio saboroso e temperado, e a fila que se forma de manhã na porta da padaria mostra o quanto os moradores amam esse começo de dia.'),
  'huainan/tofu': ('Berço do tofu', 'A lenda atribui a criação do tofu aos alquimistas do príncipe Liu An, no Monte Bagong, durante a dinastia Han, quando o leite de soja foi coalhado pela primeira vez. Inventado aqui há cerca de dois mil anos, esse alimento humilde se espalhou pela culinária mundial, e Huainan celebra o legado com um festival anual do tofu.'),
  'huainan/coalmine': ('Cidade do carvão', 'Erguida sobre ricas jazidas de carvão, Huainan é há muito tempo uma das bases energéticas do leste da China. Suas minas e usinas alimentam a rede elétrica regional, enquanto a cidade transforma cada vez mais as antigas áreas de mineração em lagos e parques, guiando seu legado industrial rumo a um futuro mais verde.'),
  'huainan/oldtown': ('Cidade Antiga de Shou', 'A cidade antiga do Condado de Shou é uma das raras cidades chinesas cujas muralhas da era Song sobrevivem completas. As grossas muralhas de tijolo e os portões em arco chegaram a proteger a cidade até das enchentes, e as ruas intramuros guardam vestígios do antigo reino de Chu, que manteve aqui sua última capital.'),
  'huainan/classic': ('Huainanzi', 'O Huainanzi é um clássico da filosofia compilado pelos eruditos reunidos na corte de Liu An, príncipe de Huainan, na era Han. Combinando pensamento taoista, cosmologia e arte de governar, a obra também preservou lendas queridas, como a da deusa Nüwa consertando o céu partido.'),
  'jingdezhen/porcelain': ('Capital da porcelana', 'Jingdezhen produz porcelana há mais de mil anos e, como centro dos fornos imperiais, enviava suas peças mais finas à corte. O caulim, argila essencial da porcelana, tira seu nome da vizinha aldeia de Gaoling, e ainda hoje a cidade atrai ceramistas do mundo inteiro.'),
  'jingdezhen/kiln': ('Forno antigo', 'No sítio cultural do Forno Antigo, fornos tradicionais a lenha e oficinas de artesanato mantêm vivas as velhas técnicas. Dos fornos-dragão que sobem as encostas às câmaras em forma de ovo, ali se acompanha a prova de fogo da porcelana, enquanto os mestres torneiam, esmaltam e pintam as peças diante do público.'),
  'jingdezhen/bluewhite': ('Porcelana azul e branca', 'O \'qinghua\' — desenhos em azul-cobalto pintados sob o esmalte da porcelana branquíssima — é a assinatura mundialmente famosa de Jingdezhen. Aperfeiçoado nas eras Yuan e Ming, o estilo azul e branco viajou pela Rota da Seda e pelas rotas marítimas, tornando-se paixão de colecionadores nas cortes europeias.'),
  'jingdezhen/painting': ('Pintura em porcelana', 'Em Jingdezhen, a porcelana não é apenas um recipiente, mas uma tela: os mestres pintam paisagens, pássaros e versos de poesia com os pincéis mais finos. Técnicas como a pintura sob o esmalte e o esmalte sobre a cobertura passam de geração em geração, e as obras assinadas são colecionadas como quadros.'),
  'jian/jinggang': ('Montanhas Jinggang', 'As Montanhas Jinggang, envoltas em névoa, abrigaram em 1927 a primeira base rural da revolução chinesa. Hoje coração do \'turismo vermelho\', a serra recebe visitantes com sítios históricos ao lado de cachoeiras, florestas de bambu e mares de nuvens rolando abaixo dos picos.'),
  'jian/torch': ('Centelha revolucionária', 'O ditado \'uma única fagulha pode incendiar a pradaria\' descreve como a revolução se espalhou dessas montanhas para todo o país. Memoriais, museus e quartéis preservados na região de Jinggang documentam aquela dura luta, e os caminhantes seguem trilhas históricas por paisagens montanhosas de tirar o fôlego.'),
  'jian/academy': ('Academia Bailuzhou', 'Fundada na era Song sobre uma ilha no Rio Gan, a Academia Bailuzhou formou eruditos durante séculos — entre eles o herói nacional Wen Tianxiang. Seus pátios tranquilos, abraçados pelo rio de todos os lados, permanecem como uma memória elegante da tradição clássica de ensino da China.'),
  'jian/pine': ('Pinheiros de Jinggang', 'Os pinheiros enraizados nas encostas íngremes das Montanhas Jinggang mantêm-se firmes contra a névoa e o vento. Crescendo agarrados à rocha nua, tornaram-se símbolo de resistência e esperança, e suas silhuetas emergindo do mar de nuvens ao nascer do sol formam uma cena difícil de esquecer.'),
  'nanping/wuyi': ('Montanhas Wuyi', 'As Montanhas Wuyi, com penhascos avermelhados, desfiladeiros verdes e um riacho cristalino serpenteando entre eles, são patrimônio da UNESCO tanto pela natureza quanto pela cultura. Antigas inscrições rupestres, jardins de chá em terraços e os vestígios das academias de Zhu Xi entrelaçam a serra também à história do pensamento chinês.'),
  'nanping/rocktea': ('Chá das Rochas', 'O Da Hong Pao, o \'Grande Manto Vermelho\', é a coroa dos \'chás de rocha\' — oolongs cultivados no solo rico em minerais dos penhascos de Wuyi. Folhas dos veneráveis arbustos-mãe presos à rocha já alcançaram preços lendários, e o aroma profundo e tostado do chá é reverenciado no mundo do chá.'),
  'nanping/bambooraft': ('Balsa do Riacho das Nove Curvas', 'O Riacho das Nove Curvas serpenteia entre os penhascos vermelhos das Montanhas Wuyi em nove amplas voltas. A bordo de balsas de bambu conduzidas a vara pelos barqueiros, os visitantes passam por misteriosos caixões-barco antigos encravados no alto da rocha e veem a paisagem mudar a cada curva.'),
  'nanping/scholar': ('Mestre Zhu Xi', 'Zhu Xi, o grande mestre do neoconfucionismo, passou boa parte da vida nos arredores das Montanhas Wuyi, onde fundou academias e formou discípulos. Sua releitura do pensamento de Confúcio moldou por séculos a educação e os exames imperiais na China e em toda a Ásia Oriental.'),
  'shenzhen/skyscraper': ('Arranha-céus', 'Vila de pescadores há quarenta anos, Shenzhen virou uma floresta de arranha-céus depois de ser declarada a primeira zona econômica especial da China. Seu horizonte, coroado pela torre Ping An que fura as nuvens, encarna o ritmo da era das reformas — fala-se aqui em \'velocidade de Shenzhen\', andares que sobem da noite para o dia.'),
  'shenzhen/chip': ('Cidade Tecnológica', 'No mercado de eletrônicos de Huaqiangbei, chips, placas e peças de drone circulam de banca em banca; gigantes como Tencent, Huawei e DJI cresceram nesta cidade. No \'Vale do Silício da China\', as ideias viram protótipos em questão de dias — Shenzhen é a capital mundial das startups de hardware.'),
  'shenzhen/miniature': ('Janela do Mundo', 'O parque temático Janela do Mundo reúne miniaturas das construções mais famosas do planeta, da Torre Eiffel às pirâmides. É possível passear por continentes inteiros em uma tarde; a \'Eiffel\' do parque se ilumina à noite, resumindo o espírito divertido e ambicioso de Shenzhen.'),
  'shenzhen/mangrove': ('Baía de Shenzhen', 'As florestas de mangue da Baía de Shenzhen, estendidas aos pés dos arranha-céus, são uma parada essencial para as aves em suas rotas migratórias. Garças e aves costeiras se alimentam nos bancos de lama, enquanto o calçadão do parque litorâneo oferece aos moradores uma visão rara da natureza e da metrópole lado a lado.'),
  'xian/terracotta': ('Exército de Terracota', 'Os milhares de soldados de terracota que guardam o túmulo do imperador Qin Shi Huang foram descobertos por acaso em 1974, por camponeses que cavavam um poço. Cada soldado tem um rosto diferente; alinhado em fileiras silenciosas, o exército exibe o poder de um imperador que buscava a imortalidade e é frequentemente chamado de oitava maravilha do mundo.'),
  'xian/citywall': ('Muralha da Cidade', 'A muralha de Xi\'an, da era Ming, é a mais completa da China; seu corpo maciço envolve a cidade antiga em um retângulo ininterrupto. Alugar uma bicicleta para percorrê-la é uma experiência clássica de Xi\'an; das torres de vigia, a cidade moderna e a capital milenar dividem o mesmo quadro.'),
  'xian/drumtower': ('Torre do Sino', 'A Torre do Sino da dinastia Ming, bem no centro da cidade, marca o coração da antiga capital; seu sino outrora anunciava as horas do dia. Junto com a vizinha Torre do Tambor e as ruas gastronômicas do Bairro Muçulmano logo atrás, ela ancora a praça mais animada das noites de Xi\'an.'),
  'xian/roujiamo': ('Hambúrguer chinês', 'Carne cozida por horas com especiarias, recheando um pão achatado e crocante — por isso o roujiamo é chamado de \'hambúrguer chinês\'. Este petisco milenar da comida de rua de Shaanxi combina perfeitamente com a agitação da capital da Rota da Seda: cabe em uma mão e, em duas mordidas, conecta você a mil anos de tradição.'),
  'suzhou/garden': ('Jardins Clássicos', 'Os jardins clássicos de Suzhou são obras-primas que recriam a natureza em pequena escala com rochedos, lagos e pavilhões; os mais belos são Patrimônio Mundial da UNESCO. Cada janela é enquadrada como uma pintura, e caminhar por suas trilhas é como desenrolar um rolo de pintura que muda a cada passo.'),
  'suzhou/watertown': ('Cidade das Águas', 'Com seus canais, pontes de pedra arqueadas e casas caiadas de branco, Suzhou é chamada de \'Veneza do Oriente\'. Em ruelas antigas como a Rua Pingjiang, a água corre rente às portas das casas; deslizando de barco, ouve-se o som da pipa e de baladas locais vindo das casas de chá.'),
  'suzhou/embroidery': ('Bordado de Su', 'O bordado Su é um ofício milenar de Suzhou, trabalhado sobre seda com fios mais finos que um cabelo; os maiores mestres conseguem bordar desenhos diferentes nas duas faces de um mesmo tecido. Capturando com a agulha o brilho do pelo de um gato ou as escamas de um peixe, essa arte encarna a paciência e o refinamento da cidade.'),
  'suzhou/kunqu': ('Ópera Kunqu', 'O Kunqu, reverenciado como a mãe de todas as óperas chinesas, nasceu na região de Suzhou; é conhecido por melodias que fluem como água e gestos delicadamente estilizados. Inscrita na lista de patrimônio imaterial da UNESCO, essa arte ainda é apresentada hoje em pavilhões de jardim e teatros intimistas.'),
  'kunming/stoneforest': ('Floresta de Pedra', 'Pilares gigantes de calcário, esculpidos pela água ao longo de milhões de anos, formam o labirinto conhecido como Floresta de Pedra, perto de Kunming. O povo Sani da região conta essas rochas pela lenda de Ashima — uma bela jovem transformada em pedra, que ainda saúda os visitantes na forma de um famoso pilar.'),
  'kunming/springcity': ('Cidade da Primavera', 'No alto planalto de Yunnan os invernos são suaves e os verões frescos, e por isso Kunming é chamada de \'Cidade da Primavera\', onde as flores nunca murcham. Ela abriga um dos maiores mercados de flores da Ásia, e buquês frescos são vendidos até nas esquinas.'),
  'kunming/seagull': ('Gaivotas-de-cabeça-preta', 'A cada inverno, milhares de gaivotas vindas da Sibéria pintam de branco as margens dos lagos e os parques de Kunming. Alimentá-las na mão é um querido ritual da estação fria, e o retorno das gaivotas é celebrado quase como o anúncio de uma estação em si.'),
  'kunming/ricenoodle': ('Macarrão Crossing-the-Bridge', 'O macarrão \'travessia da ponte\' é o prato símbolo de Yunnan: o caldo fervente chega à mesa, e o fino macarrão de arroz e os acompanhamentos são adicionados à tigela diante dos seus olhos. Diz a lenda que uma esposa, que atravessava uma ponte para levar comida ao marido que estudava, inventou essa forma de manter a sopa quente.'),
  'jinan/spring': ('Cidade das Fontes', 'Em Jinan, as águas subterrâneas brotam borbulhando no próprio coração da cidade; a preferida entre suas 72 fontes famosas é a jorrante Fonte Baotu. Na \'Cidade das Fontes\', água cristalina corre até pelas vielas dos bairros antigos, e os moradores ainda se orgulham de preparar seu chá com água de fonte.'),
  'jinan/daminglake': ('Lago Daming', 'Alimentado pelas fontes da cidade, o Lago Daming é um oásis urbano cercado de salgueiros e flores de lótus. No verão, barcos deslizam entre os canteiros de lótus em flor, enquanto os pavilhões e casas de chá à beira do lago mantêm o ritmo de vida lento e elegante pelo qual Jinan é conhecida na literatura chinesa.'),
  'jinan/buddhamountain': ('Montanha dos Mil Budas', 'Centenas de figuras de Buda foram esculpidas nas encostas do Monte dos Mil Budas ao longo dos séculos; os relevos mais antigos remontam à dinastia Sui. Subindo suas trilhas, os visitantes contemplam tanto as estátuas em seus nichos de pedra quanto, do alto, a vista panorâmica de Jinan, a cidade das fontes.'),
  'jinan/poet': ('Poetisa Li Qingzhao', 'Li Qingzhao, reverenciada como a maior poetisa da China, nasceu nesta cidade das fontes durante a dinastia Song. Seus poemas ci, de melancolia delicada, falam de amor, exílio e perda; o salão memorial ao lado da Fonte Baotu preserva o mundo de águas murmurantes que deu origem aos seus versos.'),
  'ningbo/library': ('Pavilhão Tianyi', 'Fundada na dinastia Ming, a Tianyi Ge é a mais antiga biblioteca particular ainda existente na Ásia, criada por um estadista apaixonado por livros. Para proteger seus manuscritos raros da umidade e do fogo, foi concebida quase como um templo dos livros, com seu jardim, seu lago e rígidas regras familiares sobre quem podia entrar.'),
  'ningbo/port': ('Porto de Carga', 'O porto de Ningbo-Zhoushan é o mais movimentado do mundo em tonelagem de carga; seu litoral é uma floresta de navios porta-contêineres e guindastes imponentes. A história marítima da cidade vem de longe — Ningbo foi um dos portões de partida da antiga Rota da Seda Marítima.'),
  'ningbo/tangyuan': ('Tangyuan', 'O tangyuan ao estilo de Ningbo consiste em sedosas bolinhas de arroz glutinoso recheadas com pasta doce de gergelim; na mordida, o recheio quente escorre como uma pequena surpresa. Doce símbolo do Festival das Lanternas, sua forma redonda representa a união e o reencontro da família.'),
  'ningbo/seafood': ('Frutos do mar', 'De frente para o Mar da China Oriental, Ningbo põe sua mesa a partir da água: corvina-amarela, caranguejo e frutos do mar formam a base da culinária. O paladar local preza o equilíbrio \'salgado-fresco\' — cozimentos simples no vapor e salmouras leves que nunca abafam o sabor próprio do peixe são sua assinatura.'),
  'shijiazhuang/bridge': ('Ponte Zhaozhou', 'Construída na dinastia Sui pelo mestre engenheiro Li Chun, a Ponte Zhaozhou é a mais antiga ponte de arco de pedra com tímpanos abertos do mundo. Resistindo a enchentes e terremotos há cerca de 1.400 anos, o arco elegante é ensinado nos livros escolares como uma obra-prima clássica da engenharia chinesa.'),
  'shijiazhuang/clifftemple': ('Monte Cangyan', 'No Monte Cangyan, um templo pousado sobre uma ponte de pedra suspensa entre dois penhascos compõe uma das cenas mais impressionantes da China. Alcançado por íngremes escadarias de pedra que sobem do vale verde, o local serviu de cenário para a cena final de \'O Tigre e o Dragão\'.'),
  'shijiazhuang/redbase': ('Base de Xibaipo', 'A aldeia de Xibaipo, perto de Shijiazhuang, serviu de quartel-general revolucionário na fase final da guerra civil; a fundação da Nova China foi planejada em seus pátios de terra. Hoje é uma parada sagrada do \'turismo vermelho\', e suas casas simples de aldeia testemunham as grandes decisões da história.'),
  'shijiazhuang/pharma': ('Cidade Farmacêutica', 'Shijiazhuang é um dos maiores polos farmacêuticos da China, conhecida como a \'cidade dos medicamentos\', sobretudo pela produção de antibióticos e matérias-primas. Jovem capital de província que cresceu como entroncamento ferroviário, ela funde sua identidade industrial com a indústria farmacêutica e a manufatura moderna.'),
  'taiyuan/jincitemple': ('Templo Jinci', 'O Templo Jinci, na periferia de Taiyuan, é o mais gracioso jardim-templo do norte da China, com fontes sagradas, ciprestes seculares e estátuas de damas de companhia da dinastia Song. No Salão de madeira da Santa Mãe, cada figura exibe uma expressão diferente — como se sussurrassem entre si há mil anos.'),
  'taiyuan/coalcart': ('Terra do Carvão', 'As montanhas de Shanxi são entremeadas de veios de carvão, de onde sai boa parte da energia da China; Taiyuan é a capital dessa riqueza. A mineração deu à cidade sua indústria, suas ferrovias e sua cultura de máquinas pesadas, e hoje ela trabalha para equilibrar a herança do carvão com energias mais limpas.'),
  'taiyuan/vinegar': ('Vinagre Envelhecido', 'O vinagre maturado de Shanxi é feito pela lenta fermentação de sorgo e outros grãos, apreciado por sua cor escura e sua acidez defumada. Os moradores o regam sobre tudo, do macarrão aos dumplings — aqui o vinagre não é um tempero, mas quase uma identidade.'),
  'taiyuan/twinpagoda': ('Pagodes Gêmeos', 'Dois pagodes octogonais da era Ming, erguendo-se lado a lado no sudeste da cidade, são há séculos o emblema imutável de Taiyuan. As torres de tijolo exibem o requinte da arte da alvenaria, e na primavera as flores de ameixeira ao seu redor oferecem o momento mais fotogênico da visita.'),
  'hohhot/lamatemple': ('Templo Dazhao', 'Fundado na era Ming, o Templo Dazhao é o coração espiritual de Hohhot, e seu maior tesouro é uma estátua de Buda em prata. Este centro do budismo tibetano na estepe oferece um mundo à parte do barulho da cidade, envolto em fumaça de incenso, rodas de oração e cânticos em voz baixa.'),
  'hohhot/dairy': ('Capital dos Laticínios', 'As maiores marcas de laticínios da China nasceram em Hohhot, onde a tradição leiteira da estepe se transformou em uma indústria moderna — a cidade é chamada de \'capital do leite\'. À mesa, delícias mongóis como o chá com leite, as coalhadas secas e o creme de leite ainda convivem lado a lado com os produtos de fábrica.'),
  'hohhot/wrestling': ('Luta Mongol', 'A luta mongol, o bökh, é a competição estrela do festival Naadam; os lutadores entram na arena com coletes bordados, executando a dança da águia. O vencedor é aplaudido tanto pela elegância quanto pela força — na estepe, a luta figura ao lado da equitação e do arco e flecha entre as \'três habilidades viris\'.'),
  'hohhot/prairie': ('Pradaria', 'Logo além de Hohhot, a estepe mongol se estende até o horizonte; no verão, suas pastagens ondulam como um mar verde onde pastam manadas de cavalos e ovelhas. Os hóspedes das yurtas são recebidos com chá de leite e banquetes de cordeiro, e à noite o céu se enche de estrelas há muito esquecidas na cidade.'),
  'sanya/resortbeach': ('Praia Tropical', 'Na ponta sul da ilha de Hainan, Sanya é a capital tropical do turismo na China; as areias finíssimas e as águas turquesa da Baía de Yalong lhe renderam o apelido de \'Havaí da China\'. O verão dura o ano inteiro em suas praias margeadas de palmeiras — uma das poucas costas chinesas onde se pode nadar até no inverno.'),
  'sanya/guanyin': ('Estátua de Guanyin', 'Erguendo-se 108 metros sobre o mar em Nanshan, a estátua de Guanyin está entre as mais altas figuras de deusas do mundo. Seus três rostos olham para a terra, para o mar e para o horizonte; o caminho que leva aos pés da deusa da misericórdia atrai tanto peregrinos quanto viajantes curiosos.'),
  'sanya/diving': ('Mergulho', 'Com águas quentes e cristalinas, Sanya é o paraíso do mergulho na China; os recifes de coral ao redor da ilha de Wuzhizhou fervilham de peixes coloridos. Iniciantes mergulham nos recifes rasos acompanhados de instrutores, e mesmo só com um snorkel é possível contemplar o jardim tropical sob a superfície.'),
  'sanya/coconutdrink': ('Coco', 'Em Sanya, o coco faz parte da vida cotidiana: ao longo das praias, os vendedores abrem a fruta fresca com um facão e a entregam com um canudo. Sua água fresquinha é o remédio mais natural contra o calor tropical, enquanto o leite dá sabor a pratos de frango e sobremesas locais e a casca vira artesanato.'),
  'yangzhou/slenderlake': ('Lago Slender West', 'O Lago do Oeste Delgado recebeu seu nome como uma graciosa homenagem ao famoso lago de Hangzhou; o canal longo e estreito é adornado com salgueiros, pontes brancas arqueadas e pavilhões. Admirada pelos imperadores Qing em suas viagens ao sul, a paisagem continua tão elegante quanto uma pintura a nanquim.'),
  'yangzhou/friedrice': ('Arroz frito de Yangzhou', 'O arroz frito de Yangzhou é um clássico dourado de camarão, ovo e cebolinha, salteado até cada grão ficar soltinho; seu nome vive nos restaurantes chineses do mundo inteiro. O segredo está na simplicidade — cada grão envolto em ovo, com ingredientes frescos e sempre na medida certa.'),
  'yangzhou/morningtea': ('Chá da manhã', 'Em Yangzhou, o dia começa com o ritual do \'chá da manhã\': chá forte acompanhado de pães no vapor, massas finíssimas desfiadas e dumplings recheados de sopa. Nas antigas casas de chá, esse café da manhã se estende por horas — apressá-lo seria quase uma indelicadeza.'),
  'yangzhou/gegarden': ('Jardim Ge', 'Construído por um rico mercador de sal, o Jardim Ge deve seu nome ao formato das folhas de bambu. Seu truque mais celebrado é um conjunto de rochedos que evocam as quatro estações em pedras diferentes — em poucos passos, você caminha da primavera ao inverno através de um ápice da arte clássica dos jardins.'),
  'weihai/navalisland': ('Ilha Liugong', 'A ilha de Liugong, ao largo de Weihai, foi a base da Frota Beiyang, a marinha moderna da dinastia Qing, que ali foi derrotada na guerra contra a frota japonesa. Com seus museus e antigas fortificações, a ilha conta hoje uma página dolorosa, mas instrutiva, da história naval da China.'),
  'weihai/swan': ('Lago dos Cisnes', 'A cada inverno, centenas de cisnes-bravos chegam da Sibéria para se instalar na laguna costeira perto de Weihai. As aves brancas deslizando pela névoa da manhã atraem fotógrafos e amantes da natureza, enquanto os aldeões cuidam dos cisnes e os alimentam como a vizinhos.'),
  'weihai/seacucumber': ('Pepino-do-mar', 'O pepino-do-mar criado nas águas frias e limpas de Weihai está entre as iguarias mais valorizadas da mesa chinesa. Considerado profundamente nutritivo, é servido em ocasiões especiais e oferecido como um presente de respeito; as fazendas marinhas ao longo da costa são um dos pilares do sustento da cidade.'),
  'weihai/cape': ('Cabo da China', 'Chengshantou, o cabo a leste de Weihai, é um dos pontos mais orientais onde a terra da China encontra o mar — é aqui que o sol saúda o país primeiro. Diz a lenda que o Primeiro Imperador, Qin Shi Huang, viajou até aqui em busca da terra da imortalidade além das ondas; o cabo também é chamado de \'a beira do céu\'.'),
  'handan/taichi': ('Tai Chi', 'A cidade murada de Guangfu, perto de Handan, é o berço dos estilos Yang e Wu do taijiquan; o lendário mestre Yang Luchan treinou aqui. Pelas manhãs, alunos praticando formas lentas e fluidas ao pé das muralhas e nos pátios mantêm viva a herança dessa arte marcial \'suave\'.'),
  'handan/congtai': ('Terraço Congtai', 'O Terraço Congtai sobrevive do poderoso reino de Zhao, da era dos Reinos Combatentes; a alta plataforma de onde os reis assistiam a cerimônias e exercícios militares fica hoje no coração de um parque. Ao subi-lo, você contempla do alto os mais de dois mil anos de história de Handan como antiga capital.'),
  'handan/idiom': ('Cidade dos Provérbios', 'Handan é a \'cidade dos provérbios\': mais de 1.500 expressões idiomáticas chinesas têm origem em fatos e histórias destas terras. A mais famosa é \'aprender o andar de Handan\' — sobre alguém que imita os outros até esquecer o próprio jeito de andar — e gravou para sempre o nome da cidade no idioma.'),
  'handan/ciporcelain': ('Porcelana Cizhou', 'A cerâmica de Cizhou é conhecida por seus desenhos negros e vigorosos, pincelados livremente sobre um engobe branco — flores, peixes e versos de poesia aplicados com a franqueza da arte popular. Viva desde a dinastia Song, a tradição representa a cerâmica do dia a dia, um contraponto à porcelana da corte imperial.'),
  'daqing/oilpump': ('Campo petrolífero', 'A descoberta do campo petrolífero de Daqing libertou a jovem República Popular da dependência do petróleo importado; a cidade praticamente cresceu sobre seus poços. Os cavaletes de bombeamento ainda balançam lentamente pela planície, e Daqing entrou para a história como o maior campo de petróleo da China.'),
  'daqing/oilworker': ('Homem de Ferro', 'O operário do petróleo Wang Jinxi ganhou o apelido de \'Homem de Ferro\' por sua garra ao abrir poços no frio congelante; conta-se que uma vez ele pulou em um tanque de lama e misturou o fluido de perfuração com o próprio corpo. O museu que leva seu nome e o \'espírito do Homem de Ferro\' mantêm viva a lenda da fundação de Daqing.'),
  'daqing/reedlake': ('Áreas úmidas', 'Uma natureza surpreendente se esconde entre os poços de petróleo: os vastos lagos de juncos e as zonas úmidas de Daqing abrigam grous, cisnes e aves aquáticas migratórias. No outono, quando os juncos dourados balançam ao vento, a cidade industrial se transforma em um santuário de pássaros.'),
  'daqing/hotspring': ('Fonte termal', 'Ao redor de Daqing, águas termais ricas em minerais, vindas das profundezas da terra, oferecem um refúgio revigorante nos frios invernos do nordeste. O condado de Lindian fez fama como cidade termal, e relaxar em suas piscinas fumegantes é uma doce resposta ao clima rigoroso da cidade do petróleo.'),
  'zibo/bbq': ('Churrasco de Zibo', 'O churrasco de Zibo é famoso por seu trio: um pequeno braseiro a carvão, espetinhos finos e panquecas macias e finas. Você termina de assar o próprio espetinho e o enrola na panqueca com cebolinha fresca e molho — um ritual acolhedor que varreu as redes sociais chinesas e tornou a cidade uma sensação nacional da noite para o dia.'),
  'zibo/cuju': ('Cuju', 'O cuju, a forma mais antiga de futebol do mundo, era jogado em Linzi, capital do antigo estado de Qi — uma herança que a FIFA reconhece como a origem do esporte. Mantendo no ar uma bola de couro com os pés, o jogo teve uma vida rica, que ia do entretenimento palaciano ao treinamento militar.'),
  'zibo/ceramic': ('Cerâmica de Zibo', 'Os fornos de Zibo ardem há mais de mil anos, fazendo da cidade um dos centros cerâmicos mais tradicionais do norte da China. Uma tradição que vai das vasilhas do cotidiano à porcelana artística sobrevive em seus museus e ateliês, e as feiras de cerâmica atraem mestres de todo o país.'),
  'zibo/glass': ('Liuli', 'O liuli, moldado à mão a partir de vidro fundido colorido, é o ofício de Zibo que brinca com a luz; o distrito de Boshan é famoso como seu centro histórico. Os artesãos puxam e dobram o vidro incandescente com pinças, e as contas, aves e vasos resultantes brilham ao sol como vitrais.'),
  'taian/mounttai': ('Monte Tai', 'O Monte Tai, o principal das Cinco Montanhas Sagradas, é o pico mais sagrado da China; durante séculos, os imperadores realizaram aqui ritos sacrificiais para anunciar seus reinados ao céu. Inscrições de poetas e calígrafos estão gravadas nas rochas deste sítio da UNESCO — cada pedra é uma página de história.'),
  'taian/sunrise': ('Nascer do sol no cume', 'O grande prêmio de escalar o Monte Tai é assistir ao sol nascer acima de um mar de nuvens no cume. Milhares sobem durante a noite para esperar o amanhecer no Pico do Imperador de Jade; quando o horizonte se tinge de carmesim, o grito de alegria que sobe da multidão apaga todo o cansaço.'),
  'taian/stonesteps': ('Escadaria de pedra', 'Os cerca de 7.000 degraus de pedra até o cume são uma prova física que os peregrinos escalam passo a passo há séculos. O trecho mais íngreme são as \'Dezoito Curvas para o Céu\', e os carregadores que sobem e descem essas escadas diariamente com suas cargas são os heróis silenciosos da montanha.'),
  'taian/daitemple': ('Templo Dai', 'O Templo Dai, ao pé da montanha, é um grandioso complexo onde os imperadores se hospedavam e se preparavam antes dos ritos no Monte Tai. Seu salão principal, em estilo palaciano, é famoso por um vasto mural que retrata a jornada do deus do Monte Tai, e os ciprestes milenares de seus pátios são testemunhas da história.'),
  'lianyungang/monkey': ('Montanha Huaguoshan', 'Aqui se ergue Huaguoshan, a Montanha das Flores e Frutos — lar do Rei Macaco Sun Wukong, da epopeia \'Jornada ao Oeste\'. Entra-se na Caverna da Cortina d\'Água por trás de uma cachoeira, e os macacos de verdade que vagam pelas rochas confundem a fronteira entre lenda e paisagem.'),
  'lianyungang/seaport': ('Porto de Lianyungang', 'Lianyungang é a ponta do Pacífico da ponte ferroviária terrestre que atravessa a Eurásia; os trens carregados aqui seguem pela Ásia Central rumo à Europa. Considerado o portão marítimo oriental da Rota da Seda, o porto parece uma continuação moderna das antigas rotas de comércio.'),
  'lianyungang/mountain': ('Monte Yuntai', 'Os picos escarpados do Monte Yuntai abrigam o ponto mais alto de Jiangsu — uma exceção surpreendente em uma província conhecida por suas planícies baixas. Com encostas cobertas de florestas, templos e cristas com vista para o mar, a serra é o refúgio natural da cidade.'),
  'lianyungang/crystal': ('Terra dos cristais', 'O condado de Donghai, em Lianyungang, abriga um dos maiores mercados de cristal de quartzo do mundo. Os cristais límpidos extraídos de seu solo servem de tudo, de joias a matéria-prima industrial, e as bancas do mercado da cidade cintilam com pedras reluzentes.'),
  'maanshan/libai': ('Poeta Li Bai', 'Li Bai, reverenciado como o maior poeta da China, passou seus últimos anos nos arredores desta cidade ribeirinha; seu túmulo fica na vizinha Dangtu. O parque memorial guarda os vestígios do mestre que transformou o vinho, a lua e a liberdade em versos, e Ma\'anshan orgulhosamente se apresenta como \'cidade da poesia\'.'),
  'maanshan/steel': ('Cidade do aço', 'A siderúrgica Magang fez de Ma\'anshan uma das principais bases de ferro e aço da China; seus altos-fornos fumegam às margens do Yangtze há décadas. A cidade equilibra essa identidade de indústria pesada com seu passado poético — o aço fundido de um lado, os versos de Li Bai do outro.'),
  'maanshan/rivercliff': ('Penhasco Caishiji', 'O penhasco de Caishiji, mergulhando a pique no Yangtze, oferece uma das vistas mais poéticas do rio. Diz a lenda que Li Bai caiu na água aqui ao tentar abraçar o reflexo da lua, passando à imortalidade; os pavilhões e as trilhas do penhasco ainda sussurram essa história.'),
  'maanshan/moonwine': ('Lua e Vinho', 'A lua e o vinho, as duas grandes imagens dos versos de Li Bai, ainda são celebradas em Ma\'anshan, que realiza festivais de poesia em sua memória. Erguer uma taça à beira do rio enquanto se contempla a lua é a maneira mais simples de compartilhar um sentimento com um poeta de mil anos atrás.'),
  'longyan/tulou': ('Tulou de Yongding', 'Os gigantescos tulou redondos espalhados pelas montanhas de Yongding são casas-fortaleza que o povo Hakka ergueu de terra e madeira, hoje Patrimônio Mundial da UNESCO. Atrás das grossas paredes de terra, dezenas de famílias vivem lado a lado; a fumaça dos fogões que sobe do pátio carrega o aroma de séculos de vida comunitária.'),
  'longyan/redmeeting': ('Reunião de Gutian', 'Em 1929, a histórica Reunião de Gutian, que definiu os princípios e o rumo do Exército Vermelho, foi realizada nesta aldeia de montanha de Longyan. O salão de assembleias caiado de branco está preservado até hoje, e a aldeia atrai visitantes que seguem os passos de um dos pontos de virada da história revolucionária.'),
  'longyan/hakka': ('Cultura Hakka', 'Os Hakka, cujo nome significa \'famílias hóspedes\', ganharam esse título ao migrar do norte da China para o sul, fugindo das guerras. Nas montanhas de Longyan, eles mantêm vivos há séculos sua língua própria, pratos como o frango assado no sal e seus fortes laços de família.'),
  'longyan/mountain': ('Monte Guanzhi', 'O Monte Guanzhi é conhecido por seu cume de rocha vermelha, que lembraria o chapéu de um antigo magistrado; esses penhascos carmesins, chamados danxia, estão cercados de lagos límpidos e ravinas escarpadas. Com escadarias talhadas na rocha e passeios de barco em seu lago, a montanha é considerada a pérola natural do sul de Fujian.'),
  'sanming/danxia': ('Danxia de Taining', 'Taining, no noroeste de Fujian, é um geoparque da UNESCO com falésias de arenito vermelho, desfiladeiros estreitos e cavernas. A água esculpiu esse labirinto de pedra ao longo de milhões de anos; hoje você o percorre de barco, vendo riachos verdes deslizarem entre paredes escarlates.'),
  'sanming/shaxian': ('Petiscos de Sha County', 'A cozinha humilde do condado de Sha virou um fenômeno nacional de comida barata e reconfortante. Wontons de massa finíssima, macarrão ao molho de amendoim e sopas cozidas lentamente no vapor são servidos com o mesmo carinho nas lanchonetes Shaxian, presentes em quase toda rua da China.'),
  'sanming/forest': ('Capital Verde', 'Sanming está entre as cidades mais arborizadas da China, com montanhas cobertas de verde do cume ao vale. Antiga cidade madeireira, ela se voltou ao ecoturismo e carrega com orgulho o título de \'capital verde\', com ar puro e trilhas na floresta.'),
  'sanming/goldenlake': ('Lago Dourado', 'O Lago Dourado, ou Jinhu, é um amplo reservatório que serpenteia entre as falésias vermelhas de Danxia em Taining. Passeios de barco levam você por estreitos cânions de água, passando por paredões escarpados e pelo Templo Ganlu, construído dentro da rocha — uma paisagem rara onde a água encontra a pedra.'),
  'ningde/mudflat': ('Planícies de lama de Xiapu', 'Todo dia a maré recua em Xiapu, revelando imensas planícies de lama que brilham sob a luz cambiante. Fazendas de algas, fileiras de varas de bambu e pescadores trabalhando nas águas rasas transformaram esse litoral em um ponto de encontro mundialmente famoso entre fotógrafos.'),
  'ningde/whitetea': ('Chá branco de Fuding', 'Fuding é a terra natal do chá branco chinês: os brotos prateados e aveludados são apenas murchados e secos, nunca tostados. Um ditado local — \'um ano é chá, três anos é remédio, sete anos é tesouro\' — resume como essa folha delicada se torna mais preciosa com a idade.'),
  'ningde/taimu': ('Monte Taimu', 'O Monte Taimu se ergue diante do mar com torres de granito arredondadas, fendas estreitas e passagens em cavernas. Chamado desde a antiguidade de \'terra das fadas sobre o mar\', suas trilhas serpenteiam entre rochedos até mirantes onde a névoa encontra o oceano.'),
  'ningde/croaker': ('Corvina amarela', 'As baías abrigadas de Sandu\'ao fazem de Ningde o maior polo da China no cultivo da corvina amarela. Fazendas de gaiolas flutuantes formam verdadeiras vilas sobre a água, e a carne branca e delicada do peixe, simplesmente cozida no vapor, reina nas mesas de Fujian.'),
  'shaoguan/redcliff': ('Monte Danxia', 'O Monte Danxia é o maciço de arenito vermelho que deu nome às formações \'danxia\' em todo o mundo e integra a lista do Patrimônio Mundial da UNESCO. Torres e pilares esculpidos pelo vento e pela água ardem como brasas ao pôr do sol, explorados por trilhas sinuosas e passeios de barco pelo rio.'),
  'shaoguan/chantemple': ('Templo Nanhua', 'O Templo Nanhua, perto de Shaoguan, é o lugar onde Huineng, o Sexto Patriarca do Budismo Chan (Zen), ensinou sua doutrina. Com uma história de quase quinze séculos, permanece o coração sagrado do Chan do sul, onde peregrinos ainda seguem os passos do mestre em meio à fumaça do incenso.'),
  'shaoguan/ancestor': ('Beco Zhuji', 'A Viela Zhuji, em Nanxiong, foi o ponto de parada onde famílias que migravam do norte na era Song descansavam antes de se estabelecer no sul. Milhões de cantoneses hoje traçam suas genealogias até essa estreita ruela de pedra, voltando ano após ano em busca dos nomes de seus antepassados.'),
  'shaoguan/yaodance': ('Povo Yao', 'O povo Yao dos condados montanhosos de Shaoguan é conhecido por seus trajes bordados deslumbrantes e pelas danças do tambor longo. Nas festas da colheita, os tambores ecoam pelos vales, enquanto os padrões de bordado transmitem a história dos clãs de geração em geração, como uma língua sem escrita.'),
  'zhanjiang/oyster': ('Ostra de Zhanjiang', 'As ostras criadas nas águas quentes e limpas do sul, em Zhanjiang, crescem gordas e leitosas. À noite, elas chiam sobre o carvão com alho e óleo nas barracas de rua — um ritual com gosto de mar no coração da vida noturna da cidade.'),
  'zhanjiang/navy': ('Porto Naval', 'Com seu porto natural profundo e abrigado, Zhanjiang sedia a Frota do Mar do Sul da marinha chinesa. Outrora arrendada à França sob o nome de Guangzhouwan, a cidade portuária é hoje a porta estratégica do país para o Mar do Sul da China.'),
  'zhanjiang/mangrove': ('Floresta de Mangue', 'A floresta de mangue ao longo do litoral de Zhanjiang forma a maior reserva de manguezais da China. Enchendo e esvaziando com as marés, esse bosque de água salgada abriga garças, peixes-saltadores e caranguejos, enquanto suas raízes emaranhadas protegem a costa das tempestades e servem de berçário para peixes jovens.'),
  'zhanjiang/donghai': ('Ilha Donghai', 'A Ilha Donghai, ao largo de Zhanjiang, é famosa por uma praia que se estende sem interrupção por muitos quilômetros. Os ventos constantes atraem surfistas, e a ilha é igualmente conhecida pela tradicional \'dança do dragão humano\', em que dezenas de pessoas se unem ombro a ombro para formar um único dragão.'),
  'maoming/lychee': ('Capital da Lichia', 'Maoming é uma das grandes regiões produtoras de lichia do mundo; no início do verão, suas colinas se tingem de vermelho com as frutas. Na época imperial, as lichias dessas terras eram levadas às pressas ao palácio como tributo, e árvores centenárias dos pomares ainda dão frutos até hoje.'),
  'maoming/refinery': ('Base Petroquímica', 'Maoming se tornou uma cidade industrial nos anos 1950 processando xisto betuminoso e hoje abriga um dos maiores complexos petroquímicos do sul da China. Refinarias e plantas de etileno dão a essa região verde e agrícola uma poderosa espinha dorsal econômica.'),
  'maoming/ladyxian': ('Dama Xian', 'Lady Xian, sábia líder do século VI, uniu em paz os povos do extremo sul. Centenas de templos ao redor de Maoming são dedicados a ela, e os ritos anuais em sua memória atestam uma reverência que já dura cerca de mil e quinhentos anos.'),
  'maoming/seaside': ('Praia de Maoming', 'O litoral de Maoming, promovido como a \'Praia Número Um da China\', estende-se por quilômetros de areia dourada. Uma floresta plantada de casuarinas acompanha a costa como quebra-vento verde, e as famílias passam o dia nadando antes de encerrá-lo nos restaurantes de frutos do mar.'),
  'zhaoqing/sevenstar': ('Penhascos das Sete Estrelas', 'Sete penhascos de calcário erguem-se do Lago das Estrelas em uma formação que, dizem, espelha a constelação da Ursa Maior. As rochas escondem cavernas repletas de inscrições acumuladas por séculos, e um passeio pelos diques à beira do lago mostra por que a paisagem é chamada de \'Guilin de Guangdong\'.'),
  'zhaoqing/inkstone': ('Pedra de Tinta Duan', 'Entre os \'quatro tesouros do gabinete do letrado\', a pedra de tinta mais celebrada é a pedra Duan de Zhaoqing. Extraída daqui desde a dinastia Tang, a rocha púrpura vira arte nas mãos dos entalhadores; uma boa pedra Duan mantém a tinta úmida e trata o pincel com delicadeza.'),
  'zhaoqing/dinghu': ('Monte Dinghu', 'O Monte Dinghu tornou-se a primeira reserva natural da China em 1956. Com floresta tropical subtropical intocada, cachoeiras e o Templo Qingyun, a montanha é um refúgio fresco que os moradores das cidades chamam carinhosamente de \'bar de oxigênio\' natural.'),
  'zhaoqing/songwall': ('Muralha da Dinastia Song', 'A muralha de Zhaoqing foi erguida na dinastia Song e sobrevive quase completa em seu perímetro. As camadas de tijolos registram reparos de dinastia após dinastia, e caminhar sobre suas ameias é dar uma volta por quase mil anos de história urbana.'),
  'huizhou/westlake': ('Lago Oeste de Huizhou', 'O Lago do Oeste de Huizhou é um gracioso cenário clássico de diques ladeados por salgueiros, pontes de pedra e ilhotas. O grande poeta Su Dongpo, exilado aqui, imortalizou o lago em versos, e um dique à beira d\'água ainda leva o seu nome.'),
  'huizhou/luofu': ('Monte Luofu', 'O Monte Luofu é uma das montanhas taoistas mais sagradas do sul da China, atraindo eremitas e alquimistas a seus picos por séculos. Suas florestas, famosas pelas ervas medicinais, escondem templos, fontes de água pura e trilhas que sobem até as nuvens.'),
  'huizhou/alchemy': ('Alquimia de Ge Hong', 'Ge Hong, alquimista e médico da dinastia Jin, retirou-se para o Monte Luofu para destilar elixires e escrever suas obras de medicina. Sua anotação sobre a artemísia-doce em um antigo manual inspirou, séculos depois, a descoberta de um remédio moderno contra a malária.'),
  'huizhou/xunliao': ('Baía de Xunliao', 'A Baía de Xunliao encanta com águas rasas cor de turquesa e uma longa faixa de areia clara, sendo um dos balneários favoritos do litoral de Guangdong. Vilarejos que antes eram aldeias de pescadores hoje servem frutos do mar fresquíssimos, e o mar calmo é ideal para famílias com crianças.'),
  'meizhou/weilongwu': ('Capital Hakka', 'Meizhou é considerada a capital espiritual do povo Hakka, espalhado pelo mundo inteiro. As casas weilongwu, em forma de ferradura, apoiam-se nas colinas e reúnem clãs inteiros sob um só teto; seus pátios ainda hoje se enchem com as festas de linhagem.'),
  'meizhou/saltchicken': ('Frango assado no sal', 'O frango assado no sal é o clássico mais conhecido da cozinha Hakka: a ave inteira, embrulhada em papel, é enterrada em sal grosso quente para cozinhar. Em vez de ressecar a carne, o sal sela seus sucos, resultando em uma carne sedosa e perfumada com gengibre.'),
  'meizhou/football': ('Berço do futebol', 'Meizhou é um dos lugares onde o futebol moderno primeiro criou raízes na China, o que lhe rendeu o título de \'berço do futebol chinês\'. O lendário artilheiro Li Huitang nasceu nessas terras, e a paixão segue viva, dos campos de aldeia aos clubes profissionais.'),
  'meizhou/plum': ('Flor de ameixeira', 'Meizhou tira seu nome do caractere que significa \'ameixa\', e o Meijiang, o Rio das Ameixas, banha a cidade. Florescendo no frio do inverno, a flor de ameixeira simboliza o espírito resiliente e trabalhador do povo Hakka e aparece como motivo por toda a cidade.'),
  'jiangmen/diaolou': ('Diaolou de Kaiping', 'As torres diaolou que se erguem entre os arrozais de Kaiping foram construídas no início do século XX por emigrantes que voltavam do exterior. Projetadas como fortalezas contra bandidos e enchentes, elas misturam colunas ocidentais com telhados chineses e hoje são Patrimônio Mundial da UNESCO.'),
  'jiangmen/qiaoxiang': ('Terra natal dos chineses no exterior', 'Jiangmen e a região de Wuyi ao redor são a terra ancestral de milhões de chineses da diáspora. Espalhada das Américas ao Sudeste Asiático, essa comunidade financiou escolas, estradas e casarões em sua terra natal, dando à cidade um tecido que mistura Oriente e Ocidente.'),
  'jiangmen/chenpi': ('Casca de tangerina seca', 'A casca de tangerina seca de Xinhui, o chenpi, é secada ao sol e amadurecida por anos antes do uso. Ela empresta um aroma profundo aos pratos cantoneses e é valorizada na medicina tradicional; uma casca bem envelhecida é apreciada quase como um vinho de boa safra.'),
  'jiangmen/birds': ('Paraíso das Aves', 'O \'Paraíso dos Pássaros\', em Xinhui, é uma única figueira-de-bengala gigante cujos galhos criaram raízes até cobrir uma pequena ilha inteira. Milhares de garças e aves aquáticas pousam ali, e um famoso ensaio do escritor Ba Jin fez toda a China se apaixonar por essa ilha verde.'),
  'yangjiang/knife': ('Capital das facas', 'Yangjiang é a capital chinesa das facas e tesouras, e boa parte das lâminas de cozinha do país sai de suas oficinas e fábricas. A tradição centenária de forjaria local uniu-se à moderna tecnologia do aço, levando marcas da cidade a cozinhas do mundo todo.'),
  'yangjiang/shipwreck': ('Naufrágio Nanhai No. 1', 'O Nanhai n.º 1 é um navio mercante da dinastia Song que naufragou na Rota da Seda Marítima e dormiu no fundo do mar por séculos. Içado inteiro, ele repousa hoje em um museu com tanque de vidro na Ilha Hailing, de cujo porão já emergiram dezenas de milhares de peças de porcelana.'),
  'yangjiang/hailing': ('Ilha Hailing', 'A Ilha Hailing, com a Baía Dajiao em forma de meia-lua e praias de areia macia, é uma das ilhas de veraneio mais queridas de Guangdong. Os dias são para nadar nas ondas, as noites para saborear frutos do mar frescos do porto pesqueiro — e a ilha ainda abriga o museu do naufrágio Nanhai n.º 1.'),
  'yangjiang/kite': ('Cidade das pipas', 'Yangjiang é considerada, ao lado de Weifang, no norte, uma das duas capitais da pipa na China. Pipas tradicionais com armação de bambu são feitas à mão aqui há gerações, e todo outono, no Festival do Duplo Nove, o céu se enche de asas coloridas.'),
  'qingyuan/rafting': ('Capital do Rafting', 'Com torrentes que descem de suas montanhas, Qingyuan é conhecida na China como a \'terra do rafting\'. No verão, milhares descem os percursos espumantes de bote, enquanto os vales oferecem florestas frescas e piscinas naturais de pedra, longe do calor da cidade.'),
  'qingyuan/chicken': ('Frango de Qingyuan', 'O frango local de Qingyuan, de penas salpicadas, ossos finos e sabor profundo, é a ave mais cobiçada da cozinha cantonesa. Criado solto, costuma ser servido apenas escaldado, com molho de gengibre e cebolinha — e é justamente essa simplicidade que comprova sua qualidade.'),
  'qingyuan/hotspring': ('Fontes Termais', 'As águas termais ricas em minerais que brotam nos vales montanhosos de Qingyuan fizeram da cidade o coração dos spas de Guangdong. O vapor sobe das piscinas ao ar livre entre bambuzais farfalhantes, e visitantes de Guangzhou vêm nos fins de semana dissolver o cansaço nessas águas.'),
  'qingyuan/yaoterrace': ('Terraços de Arroz dos Yao', 'Nas aldeias Yao de Liannan, os terraços de arroz sobem as encostas das montanhas degrau por degrau. Construídos à mão ao longo de séculos, viram espelhos d\'água na primavera e escadarias douradas no outono, enquanto antigas aldeias Yao seguem vivas entre eles.'),
  'chaozhou/guangjibridge': ('Ponte Guangji', 'A Ponte Guangji, sobre o Rio Han, começou a ser construída na dinastia Song e é única por seu trecho central formado por barcos amarrados lado a lado. A seção flutuante se abre diariamente para dar passagem aos navios, o que garante à ponte um lugar entre as quatro famosas travessias antigas da China.'),
  'chaozhou/woodcarving': ('Esculturas em Madeira Dourada', 'O entalhe em madeira dourada de Chaozhou é um ofício lendário que sobrepõe cena após cena em um único painel. Cada detalhe, das redes de pesca aos heróis da ópera, é esculpido com precisão, e as obras folheadas a ouro enchem templos e casarões de brilho.'),
  'chaozhou/chaoxiu': ('Bordado de Chaozhou', 'O bordado de Chaozhou é o ramo mais suntuoso da arte da agulha de Guangdong: fios de ouro e prata são costurados sobre enchimento, criando um efeito de relevo quase escultural. Dragões e fênix parecem prestes a saltar do tecido, adornando vestidos de noiva e trajes de ópera.'),
  'chaozhou/kaiyuan': ('Templo Kaiyuan', 'Fundado em 738, durante a era Kaiyuan da dinastia Tang, o templo carrega até hoje o nome desse reinado. Há mais de um milênio a devoção não cessa em seus pátios, onde os incensários fumegam sob salões adornados com os mais belos entalhes em madeira de Chaozhou.'),
  'jieyang/citygate': ('Portão Jinxian', 'O Portão Jinxian, o \'Portão de Boas-Vindas aos Virtuosos\', é o gracioso símbolo sobrevivente da antiga Jieyang. Sua torre de madeira, com beirais em camadas, debruça-se sobre o fosso da cidade, e seu nome carrega o desejo de acolher os sábios e os dignos.'),
  'jieyang/jade': ('Capital do Jade', 'Yangmei, cidade sob a jurisdição de Jieyang, é um dos maiores centros da China de lapidação e comércio de jade. A jadeíta bruta vinda de Mianmar é cortada, entalhada e polida aqui, e nas vielas do mercado os mestres tentam ler o verde escondido dentro de cada pedra, como quem faz uma aposta.'),
  'jieyang/jieyanglou': ('Torre de Jieyang', 'A Torre de Jieyang é um monumento moderno que revive a arquitetura antiga, com amplos beirais tradicionais e porte imponente. Ela abriga exposições culturais e representa, em pedra e madeira, o orgulho que o povo Chaoshan sente de suas raízes.'),
  'jieyang/beefbroth': ('Caldo de Carne Chaoshan', 'O caldo e o hotpot de carne bovina de Chaoshan formam uma cozinha devotada ao frescor: cada corte do boi tem nome próprio e seus poucos segundos exatos no caldo claro e fervente. Servida com molho sacha, essa maestria dentro da simplicidade é o orgulho da região.'),
  'yunfu/marble': ('Reino da Pedra', 'Yunfu é conhecida como a capital chinesa do trabalho em pedra, onde mármore e granito são cortados e polidos há gerações. Milhares de oficinas enfileiradas ao longo da rodovia exportam bancadas, esculturas e revestimentos para o mundo inteiro; a pedra é o pão de cada dia da cidade.'),
  'yunfu/patriarch': ('Sexto Patriarca', 'Huineng, o Sexto Patriarca do Budismo Chan, nasceu em Xinxing, sob a jurisdição de Yunfu, e ali passou seus últimos dias. O Templo Guoen, erguido em sua honra, é um centro sereno que atrai peregrinos — o lugar onde começou sua história, de menino lenhador a mestre iluminado.'),
  'yunfu/tianlu': ('Monte Tianlu', 'O Monte Tianlu é a coroa verde de Yunfu, com cristas que alcançam as nuvens e encostas cobertas de plantações de chá. Pela manhã, os vales costumam se encher de um mar de nuvens, recompensando quem sobe para ver o nascer do sol com picos emergindo da névoa.'),
  'yunfu/xijiang': ('Rio Xi', 'O Xijiang, ou Rio do Oeste, é o braço principal do sistema do Rio das Pérolas e uma das hidrovias mais movimentadas do sul da China. Barcaças passam diante de Yunfu dia e noite, e o rio segue sendo a artéria que leva pedra e produtos agrícolas até Guangzhou e dali para o mundo.'),
  'liuzhou/luosifen': ('Luosifen', 'O macarrão de arroz com caramujo de Liuzhou, o luosifen, é famoso pelo caldo cozido com caramujos de rio e pelo toque pungente do broto de bambu em conserva. O cheiro divide opiniões à distância, mas uma prova costuma converter qualquer um; na versão instantânea, esse prato local conquistou a China e o mundo.'),
  'liuzhou/autocity': ('Cidade dos Automóveis', 'Liuzhou é o coração industrial de Guangxi e uma das principais bases de fabricação de automóveis da China. Os carros elétricos pequenos e acessíveis produzidos aqui viraram símbolo de suas ruas, adotados de coração pelos moradores por caberem nas vagas mais apertadas.'),
  'liuzhou/karst': ('Carste do Rio Liu', 'O Rio Liu contorna a cidade como um cinto, com picos de calcário erguendo-se por todos os lados. Essa grande curva rendeu a Liuzhou o apelido de \'cidade-bule\', e, no meio de um polo industrial, parques ribeirinhos e cumes cársticos oferecem uma beleza natural surpreendente.'),
  'liuzhou/liuhou': ('Poeta Liu Zongyuan', 'Liu Zongyuan, grande letrado da dinastia Tang, governou seu local de exílio, Liuzhou, onde mandou cavar poços e cuidou dos pobres. Um santuário em sua homenagem permanece no Parque Liuhou, no centro, e o poeta segue inseparável da cidade de seus últimos anos.'),
  'wuzhou/gemstone': ('Capital das Pedras Preciosas', 'Wuzhou é a capital mundial das gemas artificiais: a maior parte da zircônia sintética do planeta é lapidada e polida nas oficinas à beira do rio. Mãos habilidosas esculpem faceta após faceta em pedras minúsculas, que daqui se espalham pelos mercados de joias do mundo inteiro.'),
  'wuzhou/liubaotea': ('Chá escuro Liubao', 'O chá Liubao de Wuzhou é um chá escuro fermentado que amadurece com anos de envelhecimento. Antigamente era transportado em barcos fluviais para os mineiros do Sudeste Asiático, que confiavam nele para equilibrar o corpo no clima úmido; hoje, seus antigos cestos envelhecidos são disputados por colecionadores.'),
  'wuzhou/turtlejelly': ('Geleia de tartaruga', 'Wuzhou é tida como a terra natal do guilinggao, a gelatina preta preparada com ervas medicinais. Levemente amarga, é adoçada com mel e comida gelada — uma tradição refrescante que, acredita-se, retira o \'calor interno\' do corpo nos verões úmidos do sul.'),
  'wuzhou/dragonmother': ('Templo da Mãe Dragão', 'O Templo da Mãe dos Dragões, às margens do Xijiang, é dedicado à deusa considerada protetora do povo do rio. Conta a lenda que ela criou cinco dragões como filhos e protegeu o povo das enchentes; nos dias de festa, o templo se enche de incenso e fitas de desejos.'),
  'beihai/silverbeach': ('Praia de Prata', 'A Praia de Prata de Beihai faz jus ao nome: sua areia branca, rica em quartzo, reluz prateada ao sol. Aclamada como \'a praia número um sob o céu\', a orla se estende por quilômetros, e seu mar raso e morno oferece espaço sem fim para nadar e passear.'),
  'beihai/pearl': ('Cidade das Pérolas', 'Hepu, sob a jurisdição de Beihai, é famosa por suas pérolas desde a dinastia Han; as \'pérolas do sul\' estavam entre os tributos mais valiosos oferecidos à corte. O provérbio \'as pérolas voltam a Hepu\' nasceu neste litoral, e fazendas de pérolas e mercados de joias mantêm a tradição viva.'),
  'beihai/weizhou': ('Ilha Weizhou', 'Weizhou, ao largo de Beihai, é conhecida como a ilha vulcânica mais jovem da China. Falésias negras de lava, recifes de coral e bananais cercam suas margens, e uma igreja católica de pedra, erguida por missionários no século XIX, é a surpresa mais inesperada da ilha.'),
  'beihai/oldstreet': ('Rua Antiga', 'A Rua Antiga de Beihai é ladeada por edifícios qilou com arcadas, erguidos quando o porto se abriu ao comércio exterior no fim do século XIX. As fachadas em arco trazem ecos do Sudeste Asiático e da Europa, e hoje a rua mantém o passado vivo entre barracas de omelete de ostra e vestígios de antigos consulados.'),
  'qinzhou/nixingpottery': ('Cerâmica Nixing', 'A cerâmica Nixing de Qinzhou, queimada sem nenhum esmalte, ganha por conta própria tons de bronze, carmim e púrpura dentro do forno. Feita com argilas misturadas das duas margens do rio, essa arte figura entre as quatro famosas tradições ceramistas da China.'),
  'qinzhou/dolphin': ('Golfinho-branco-chinês', 'A Baía de Sanniang, em Qinzhou, é um dos lares mais conhecidos do raro golfinho-branco-chinês. Esses mamíferos graciosos ficam rosados com a idade e emergem ao lado dos barcos de passeio; os moradores protegem com orgulho aquele que chamam de \'panda do mar\'.'),
  'qinzhou/oysterfarm': ('Fazendas de Ostras', 'O Mar de Maowei, raso e rico em nutrientes, em Qinzhou, é um dos grandes berçários de ostras jovens da China. Suas águas se cobrem de fileiras e mais fileiras de balsas flutuantes, e a colheita gorda e carnuda faz da cidade a capital da ostra do sul — na época do festival, as grelhas nunca se apagam.'),
  'qinzhou/general': ('General Feng Zicai', 'O general Feng Zicai, da dinastia Qing, saiu da aposentadoria já idoso e conquistou uma vitória histórica contra a invasão no Passo de Zhennan, na fronteira com o Vietnã. Em sua terra natal, Qinzhou, sua antiga residência é preservada como museu, e seu nome perdura como símbolo da defesa da pátria.'),
  'guigang/lotus': ('Cidade do Lótus', 'Guigang é conhecida na China como a \'Cidade do Lótus\': no verão, os lagos e campos ao redor se cobrem de flores rosa e brancas. A raiz e as sementes de lótus são pilares da cozinha local, e um festival anual da flor enche a cidade de celebração.'),
  'guigang/uprising': ('Revolta de Jintian', 'Em 1851, na aldeia de Jintian, em Guiping, Hong Xiuquan ergueu a bandeira da Revolta Taiping. Um dos maiores movimentos populares do século XIX partiu daqui e sacudiu metade da China; hoje, um memorial na aldeia conta a história desse período turbulento.'),
  'guigang/nanshan': ('Templo Nanshan', 'O Templo Nanshan, em Guigang, é um santuário milenar instalado nas cavernas naturais de uma colina de calcário. Inscrições e poemas gravados ao longo de várias dinastias cobrem as paredes das grutas, enquanto estátuas de Buda repousam em silêncio nos frescos salões de pedra.'),
  'guigang/sugarcane': ('Cana-de-açúcar', 'Guangxi é a maior fonte de açúcar da China, e a fértil planície fluvial de Guigang é peça-chave dessa doce colheita. No outono, a cana já ultrapassa a altura de uma pessoa, e na época do corte as estradas se enchem de caminhões levando cana às usinas.'),
  'yulin/medicine': ('Mercado de Medicina Herbal', 'O mercado de ervas de Yulin está entre os maiores polos do comércio de medicina tradicional do sul da China. Em seus corredores se misturam os aromas de raízes, cascas e flores secas, e os comerciantes, herdeiros de séculos de saber, conhecem de cor o temperamento de cada erva.'),
  'yulin/goldenpalace': ('Palácio Yuntian', 'O Palácio Yuntian é uma grandiosa construção cultural que reinterpreta a arquitetura palaciana tradicional em escala colossal. Seus andares exibem entalhes delicados, estátuas de bronze e cenas mitológicas, e suas torres douradas são o traço mais marcante do horizonte da cidade.'),
  'yulin/lychee': ('Pomares de Lichia', 'As colinas e vales quentes de Yulin são cobertos de pomares de lichia e longana. No início do verão, os galhos se curvam sob os cachos de frutas vermelhas, as bancas do mercado transbordam com a colheita de aroma doce, e as famílias tratam o dia da colheita como uma festa.'),
  'yulin/beef': ('Carne de Yulin', 'O petisco típico de Yulin, o niuba, é feito secando e cozinhando lentamente fatias finas de carne bovina em um molho condimentado. Escura, levemente adocicada e de sabor intenso, a carne é comida com arroz ou acompanhando o chá, e suas receitas passam de geração em geração nas famílias.'),
  'baise/redbase': ('Revolta de Baise', 'Em 1929, a Revolta de Baise, liderada por um jovem Deng Xiaoping, estabeleceu uma base revolucionária às margens do Rio You. Por isso a cidade é uma parada importante nas rotas da \'memória vermelha\' da China; o salão memorial e os antigos quartéis-generais trazem aquela época até o presente.'),
  'baise/sinkhole': ('Sumidouros de Leye', 'As dolinas gigantes, ou tiankeng, do condado de Leye formam um dos aglomerados mais densos desses abismos na Terra. Florestas intocadas crescem no fundo de poços com centenas de metros de profundidade, e rios subterrâneos e sistemas de cavernas fazem da região a queridinha de geólogos e espeleólogos.'),
  'baise/mango': ('Capital da Manga', 'Os vales quentes e ensolarados de Baise estão entre as regiões produtoras de manga mais importantes da China. Em pleno verão, as encostas ficam douradas, caminhões levam a fruta doce a todos os cantos do país, e a manga tornou-se ao mesmo tempo sustento e orgulho desses condados montanhosos.'),
  'baise/aluminum': ('Cidade do Alumínio', 'As montanhas de Baise são ricas em bauxita, o minério que fez da cidade a base sulista da indústria de alumínio da China. Minas e fundições formam a espinha dorsal da economia regional, e esse metal \'prateado\' sob a terra vermelha dá trabalho a milhares de famílias.'),
  'hechi/longevity': ('Longevidade de Bama', 'Bama, sob a jurisdição de Hechi, é uma \'terra da longevidade\' mundialmente famosa, com uma proporção notável de moradores que passaram dos cem anos. Ar puro, comida simples e uma vida sem pressa são apontados como o segredo, e milhares de visitantes chegam a esses vales todo ano em busca de saúde.'),
  'hechi/folksong': ('Liu Sanjie', 'Yizhou, em Hechi, é celebrada como a terra natal de Liu Sanjie, a lendária cantora folclórica do povo Zhuang. Nos contos, a \'fada da canção\' derrota os senhores de terras em duelos de cantoria improvisada — uma tradição que ainda floresce com entusiasmo nas feiras de canto de hoje.'),
  'hechi/bronzedrum': ('Tambor de bronze', 'O tambor de bronze está entre os objetos mais sagrados de povos do sul como os Zhuang e os Yao, e Hechi é considerada o coração da cultura viva do tambor de bronze. Os tambores em relevo soam nas festas para invocar bênçãos e proteção, e muitas aldeias guardam seus tambores centenários como relíquias de família.'),
  'hechi/geopark': ('Geoparque Cárstico', 'O território cárstico de Hechi é um laboratório natural de dolinas, vastos salões de caverna e rios subterrâneos. As pontes de pedra naturais e as claraboias de caverna ao redor de Fengshan são as estrelas do geoparque, e onde a luz desce pelos poços, mundos escondidos surgem lá embaixo.'),
  'laibin/sugarcity': ('Capital do açúcar', 'As planícies de Laibin são cobertas de cana-de-açúcar a perder de vista, o que rendeu à cidade o nome de \'capital do açúcar da China\'. Quando começa a colheita de inverno, as chaminés das usinas voltam a fumegar, transformando a cana em açúcar, melaço e papel, enquanto um aroma doce paira sobre as cidades.'),
  'laibin/yao': ('Povo Yao de Dayao', 'As Montanhas Dayao de Jinxiu, sob a jurisdição de Laibin, abrigam cinco ramos distintos do povo Yao, cada um com seu próprio traje, dialeto e ritos. Adornos de prata e toucados bordados brilham nas festas das aldeias, fazendo de Jinxiu um museu vivo de cultura.'),
  'laibin/hongshui': ('Rio Hongshui', 'O Hongshui, que deve o nome ao sedimento avermelhado que carrega, é um rio poderoso que rasga as montanhas de Guangxi. As barragens ao longo de seus vales enviam eletricidade por todo o sul, enquanto as aldeias ribeirinhas desfrutam das paisagens que ele esculpe entre os picos cársticos.'),
  'laibin/shengtang': ('Monte Shengtang', 'O Monte Shengtang é o pico mais alto da cordilheira Dayao e figura entre os cumes que formam o teto de Guangxi. Na primavera, suas encostas se incendeiam com rododendros vermelhos, e no topo um mar de nuvens, o nascer do sol e a névoa levada pelo vento recompensam quem sobe.'),
  'chongzuo/waterfall': ('Cachoeira Detian', 'A Cachoeira Detian despenca em largos degraus sobre o rio na fronteira entre China e Vietnã e é considerada a maior cachoeira transnacional da Ásia. Balsas de bambu levam você até a névoa fresca da cortina d\'água, enquanto os picos cársticos ao redor transformam a cena em uma pintura chinesa.'),
  'chongzuo/langur': ('Langur-de-cabeça-branca', 'O langur-de-cabeça-branca vive apenas entre as colinas de calcário de Chongzuo e está entre os primatas mais raros do mundo. Ele dorme em fendas dos penhascos à noite e salta pelas rochas escarpadas durante o dia; graças às reservas protegidas, sua população vem se recuperando aos poucos.'),
  'chongzuo/rockart': ('Arte Rupestre de Huashan', 'Pintadas nas falésias do Rio Zuojiang há cerca de dois mil anos pelo povo Luoyue, as figuras vermelhas mostram milhares de pessoas dançando em pose de rã. Ainda se discute como foram pintadas em paredes de rocha tão inacessíveis, e a arte rupestre é reconhecida como Patrimônio Mundial da UNESCO.'),
  'chongzuo/borderpass': ('Passagem da Amizade', 'O Passo da Amizade é a histórica porta de fronteira que liga a China ao Vietnã e figura entre os desfiladeiros mais famosos do país. Sua torre em arco, entre montanhas verdes, recebeu exércitos, caravanas e emissários por séculos, e segue sendo até hoje uma porta viva do comércio fronteiriço.'),
  'beijing/great-wall': ('Grande Muralha da China', 'A mais longa fortificação do mundo — mais de 20.000 km construídos ao longo de séculos para proteger a fronteira norte da China. O trecho de Badaling, o mais próximo de Pequim, com seus degraus de pedra, muralhas e torres de vigia ao longo das cristas, é o mais visitado.'),
  'beijing/temple': ('Templo do Céu', 'Um complexo sagrado onde os imperadores Ming e Qing oravam ao céu todos os anos pedindo boas colheitas. Seu telhado azul redondo de três camadas — construído sem um único prego — é um dos ícones mais reconhecidos da arquitetura chinesa.'),
  'beijing/pagoda': ('Pagode Tianning', 'Um pagode de tijolos da dinastia Liao, com cerca de 57 metros e 13 andares. Com seus relevos entalhados e corpo octogonal, é uma das construções mais antigas ainda de pé em Pequim — testemunha dos mil anos de história da cidade.'),
  'beijing/opera': ('Ópera de Pequim', 'Uma arte cênica tradicional chinesa de 200 anos que funde canto, fala, artes marciais e acrobacia. A maquiagem colorida dos atores (lianpu) revela a personalidade de cada personagem: o vermelho simboliza a lealdade, o branco, a astúcia.'),
  'zunyi/huiyi': ('Conferência de Zunyi', 'Nos dias mais sombrios da Longa Marcha, os líderes do Partido Comunista se reuniram nesta mansão de pedra cinzenta em 1935, redesenhando o rumo da revolução e abrindo o caminho de Mao para a liderança. Hoje transformada em museu, a casa coloca Zunyi no coração do mapa do \'turismo vermelho\' da China.'),
  'zunyi/moutai': ('Moutai', 'A pequena cidade de Moutai, às margens do rio Chishui, é o lar do lendário baijiu considerado a bebida nacional da China. Destilada de sorgo e envelhecida por anos, essa aguardente ardente tornou-se presença obrigatória nos banquetes de Estado; até o ar da cidade carrega um aroma de fermentação.'),
  'zunyi/loushan': ('Passagem de Loushan', 'O íngreme Passo de Loushan, que corta as montanhas, foi palco de uma vitória histórica do Exército Vermelho durante a Longa Marcha. Mao o imortalizou em um famoso poema escrito ali; hoje os visitantes sobem os penhascos enevoados e leem seus versos gravados na pedra.'),
  'zunyi/chishui': ('Cachoeiras de Chishui', 'Cachoeiras despencam dos penhascos vermelhos de Danxia em Chishui, num vale de florestas de bambu e samambaias gigantes sobreviventes da era dos dinossauros. O nome significa \'água vermelha\', pois o rio corre carmesim depois da chuva, e a paisagem faz parte do patrimônio natural Danxia da China reconhecido pela UNESCO.'),
  'liupanshui/coolcity': ('Cidade Fresca', 'Erguida sobre um planalto elevado onde os verões permanecem agradavelmente frescos, Liupanshui carrega com orgulho o título de \'capital fresca da China\'. Visitantes das escaldantes Sichuan e Chongqing fogem para cá todo verão, e a cidade transformou seu clima ameno em festivais e turismo de altitude.'),
  'liupanshui/coal': ('Mar de Carvão do Sudoeste', 'Construída sobre ricas jazidas de carvão, Liupanshui foi por muito tempo o coração energético do sudoeste da China. A cidade cresceu em torno de minas e siderúrgicas durante o grande impulso industrial do século XX; hoje, equilibra sua identidade mineira com energia verde e turismo.'),
  'liupanshui/grassland': ('Pradarias de Wumeng', 'Os campos infinitos do planalto de Wumeng, vizinhos das nuvens, são pontilhados por manadas de cavalos e fileiras de turbinas eólicas no horizonte. Aldeões das etnias Yi e Miao pastoreiam seus rebanhos nos verões frescos, e a névoa do planalto pode descer num instante, transformando toda a paisagem em conto de fadas.'),
  'liupanshui/kiwi': ('Kiwi de polpa vermelha', 'O kiwi de polpa vermelha prospera nos planaltos frescos e enevoados ao redor de Liupanshui e tornou-se o doce tesouro verde da cidade. Com o centro rubro como um rubi, é mais doce que o kiwi comum, e na época da colheita as aldeias da montanha transbordam de caixas da fruta.'),
  'anshun/huangguoshu': ('Cachoeira de Huangguoshu', 'Huangguoshu, a maior cachoeira da China, despenca com estrondo de 77 metros e espalha arco-íris em sua névoa. Um caminho atravessa a Caverna da Cortina d\'Água atrás da queda, permitindo observar o mundo por trás da torrente — cenas da clássica série de TV Jornada ao Oeste foram filmadas aqui.'),
  'anshun/dixi': ('Ópera Dixi', 'Encenado nas praças das aldeias com máscaras de guerreiros esculpidas em madeira e gongos retumbantes, o Dixi é chamado de \'fóssil vivo da ópera chinesa\'. Trazido a Guizhou pelos soldados das guarnições Ming, esse teatro ritual reconta antigos épicos de guerra com o mesmo fervor há cerca de seis séculos.'),
  'anshun/batik': ('Arte em Batik', 'As mulheres Buyi e Miao desenham pássaros, flores e padrões espiralados no tecido com cera derretida, e depois mergulham o pano em tinta índigo. A cor que penetra nas finas rachaduras da cera torna cada peça única — por isso o batik de Anshun é conhecido como um artesanato sem gêmeos.'),
  'anshun/tunpu': ('Vilarejos de Tunpu', 'Em aldeias-fortaleza de pedra fundadas pelo exército Ming há cerca de 600 anos, o povo Tunpu ainda veste os trajes de estilo antigo de Nanjing de seus ancestrais e fala um dialeto arcaico. Caminhar pelas ruelas muradas de pedra é como entrar numa cidade Ming congelada no tempo.'),
  'bijie/azalea': ('Cinturão de Azaleias de Cem Li', 'A cada primavera, as cristas das montanhas de Bijie se incendeiam de azaleias carmesim, rosa e violeta, e o \'Cinturão de Azaleias de Cem Li\' é considerado a maior floresta natural de azaleias do mundo. Nos festivais de abril, aldeões Yi e Miao saúdam a primavera com canções em meio ao mar de flores.'),
  'bijie/zhijin': ('Caverna de Zhijin', 'A Caverna de Zhijin, onde estalagmites gigantes se erguem como uma floresta de pedra, é apelidada de \'palácio subterrâneo\' e figura entre as cavernas mais espetaculares da China. Em salões do tamanho de catedrais, formações delicadas como a \'Árvore da Chuva de Prata\' deixam os visitantes fascinados.'),
  'bijie/caohai': ('Garças de Caohai', 'Caohai, um lago raso e coberto de vegetação no planalto de Weining, torna-se todo ano o refúgio de inverno dos raros grous-de-pescoço-preto. Quando a névoa da manhã se dissipa, o canto de milhares de aves enche as águas, enquanto barqueiros conduzem os visitantes em silêncio por entre os juncos.'),
  'bijie/potato': ('Capital da Batata', 'As batatas cultivadas nos planaltos frescos e ensolarados fazem de Bijie um dos grandes celeiros de batata da China, e as de Weining são famosas em todo o país. Assadas na brasa, fritas até ficarem crocantes e temperadas com pimenta nas barracas de rua, a humilde batata é a rainha da cozinha do planalto.'),
  'qujing/rapeseed': ('Mar de Canola de Luoping', 'No fim do inverno, a planície de Luoping se cobre de flores douradas de canola, com cones cársticos erguendo-se dos campos como ilhas em um mar amarelo. A floração atrai apicultores, fotógrafos e amantes de mel de todos os cantos, e o próprio ar fica adocicado.'),
  'qujing/ham': ('Presunto de Xuanwei', 'Curado no sal e seco ao ar da montanha há séculos, o presunto de Xuanwei é o orgulho da mesa de Yunnan. Sua carne rosada e seu aroma profundo o colocam entre os presuntos mais famosos da China, dando sabor a tudo, de sopas a bolos da lua festivos.'),
  'qujing/jiulong': ('Cachoeiras de Jiulong', 'Perto de Luoping, o rio dos \'Nove Dragões\' desce em uma escadaria de cascatas, cada queda com sua própria largura e caráter. Na época das águas altas, o cenário, emoldurado por campos dourados de canola, é considerado uma das mais belas cadeias de cachoeiras da China.'),
  'qujing/sandforest': ('Floresta de Areia Colorida', 'Na Floresta de Areia Colorida de Luliang, colunas de areia esculpidas pelo vento e pela chuva brilham em tons que vão do dourado e ferrugem ao branco e violeta. As cores mudam conforme a luz, fazendo deste jardim natural de esculturas um cenário favorito de equipes de cinema e fotógrafos.'),
  'yuxi/fuxian': ('Lago Fuxian', 'Fuxian, um dos lagos mais profundos da China, repousa encravado no planalto de Yunnan como um espelho de montanha de águas cristalinas. Lendas falam de um antigo povoado submerso sob a superfície, e os pescadores das aldeias ribeirinhas ainda capturam o famoso peixinho kanglang do lago.'),
  'yuxi/nieer': ('Compositor Nie Er', 'Nie Er, compositor do hino nacional da China, vinha de uma família de Yuxi, e a cidade o reivindica com orgulho como filho da terra. Com um parque musical, um memorial e festivais em seu nome, Yuxi transmite de geração em geração as melodias do compositor, perdido tragicamente jovem.'),
  'yuxi/chengjiang': ('Fósseis de Chengjiang', 'Os leitos fósseis cambrianos de Chengjiang, com 530 milhões de anos, formam um Patrimônio Mundial da UNESCO que revela a aurora da vida animal em detalhes surpreendentes. Até os tecidos moles ficaram impressos na rocha, tornando essas criaturas algumas das testemunhas mais ricas da explosão cambriana.'),
  'yuxi/kiln': ('Fornos de Yuxi', 'O antigo forno de Yuxi, datado da era Yuan, é considerado o berço da cerâmica azul e branca de Yunnan. Trabalhando longe da famosa Jingdezhen, os oleiros locais desenvolveram um estilo próprio, marcando a tradição ceramista do sudoeste com peças pintadas em cobalto.'),
  'dali/threepagodas': ('Três Pagodes', 'Erguendo-se há mil anos ao pé da cordilheira de Cangshan, os três elegantes pagodes são o emblema dos antigos reinos de Nanzhao e Dali. Tendo resistido a séculos de terremotos, eles compõem o cartão-postal mais querido de Dali, com picos nevados ao fundo e um lago de reflexos à frente.'),
  'dali/erhai': ('Lago Erhai', 'Batizado por seu formato de orelha, Erhai é um lago de altitude estendido entre as montanhas Cangshan e a planície de Dali. Aldeias Bai de muros brancos adornam suas margens, e pedalar pela estrada do lago ou observar os barcos de pesca ao nascer do sol está entre os prazeres clássicos de Dali.'),
  'dali/cangshan': ('Montanhas Cangshan', 'Com dezenove picos e dezoito riachos correndo entre eles, Cangshan se ergue como uma cortina verde atrás de Dali. Em chinês, o mármore chama-se literalmente \'pedra de Dali\': a rocha rajada extraída dessas encostas adorna palácios e templos há séculos.'),
  'dali/wind': ('Vento, Flor, Neve e Lua', 'O vento de Xiaguan, as flores de Shangguan, a neve de Cangshan e a lua sobre o Erhai — as quatro belezas de Dali são recitadas como um único poema. Até os adornos de cabeça das mulheres Bai trazem esses quatro símbolos bordados, uma fórmula graciosa com que a cidade resume sua própria natureza.'),
  'lijiang/oldtown': ('Cidade Antiga de Lijiang', 'Tecida de canais, vielas de pedra e casas de madeira com telhados de telha, a Cidade Antiga de Lijiang é o coração vivo da cultura Naxi. Cidade da UNESCO famosa por não ter muralhas, ela já hospedou as caravanas da Rota do Chá e dos Cavalos, e o som da água corrente ainda acompanha cada rua.'),
  'lijiang/snowmountain': ('Montanha Nevada do Dragão de Jade', 'Com seu cume glaciar a 5.596 metros, a Montanha Nevada do Dragão de Jade reluz sobre Lijiang como um dragão adormecido. Os Naxi consideram a montanha sagrada; um teleférico leva os visitantes ao parque do glaciar, enquanto o Vale da Lua Azul, ao sopé, encanta com suas piscinas turquesa.'),
  'lijiang/dongba': ('Escrita Dongba', 'O Dongba, a escrita pictográfica dos sacerdotes Naxi, é considerado o último sistema pictográfico vivo do mundo. Milhares de manuscritos registram rituais dedicados aos espíritos da natureza e a visão Naxi do cosmos, um arquivo inscrito no registro Memória do Mundo da UNESCO.'),
  'lijiang/tigerleaping': ('Desfiladeiro do Salto do Tigre', 'Diz a lenda que um tigre cruzou o ponto mais estreito do rio Jinsha em um único salto, dando nome à garganta. Mergulhando entre as montanhas nevadas do Dragão de Jade e Haba, ela figura entre os desfiladeiros mais profundos da Terra, e a trilha alta ao longo de sua encosta é o sonho de todo trekker.'),
  'lincang/dianhong': ('Chá preto Dianhong', 'O Dianhong, chá preto de brotos dourados de Fengqing, é um chá jovem nascido no século passado, mas que rapidamente levou o nome de Yunnan ao mundo. Apreciado por sua infusão com notas de mel e caramelo, figura entre os chás pretos mais respeitados da China, ganhando profundidade extra das folhas de árvores de chá milenares.'),
  'lincang/wadrum': ('Tambor de madeira Wa', 'O povo Wa considera sagrado o tambor de madeira, cuja voz, dizem, faz a ponte entre o céu e a humanidade. Nas aldeias serranas de Cangyuan, a dança do tambor com cabelos ao vento — mulheres chicoteando os longos cabelos no ritmo — enche vales inteiros de trovão nos dias de colheita e nos festivais.'),
  'lincang/teatrees': ('Árvores de chá milenares', 'As montanhas enevoadas de Lincang abrigam árvores de chá silvestres e cultivadas cujas idades se contam em séculos, até milênios, guardando as florestas onde o chá nasceu. Na colheita da primavera, os aldeões sobem nas árvores gigantes com escadas, e dessas folhas antigas nascem alguns dos pu\'er mais cobiçados do mundo.'),
  'lincang/lancang': ('Rio Lancang', 'O Lancang, o curso superior do Mekong, desce do Tibete e abre caminho pelos vales profundos de Lincang rumo ao sul, em direção ao Sudeste Asiático. As barragens ao longo de seu curso iluminam a região, enquanto plantações de chá e pomares tropicais escalam as encostas acima de suas margens.'),
  'puer/tea': ('Chá Pu\'er', 'O chá pu\'er prensado, batizado em homenagem a esta cidade montanhosa, é um tesouro vivo que amadurece e se valoriza com o passar dos anos. Moldadas em forma de bolo, as folhas podem ser guardadas por décadas, e caravanas de mulas já as transportaram pelas montanhas até o Tibete e a corte imperial.'),
  'puer/coffee': ('Capital do café da China', 'A maior parte do café da China cresce em plantações de arábica nas encostas enevoadas de Pu\'er — assim, a capital do chá hoje, surpreendentemente, cheira a latte. As fazendas organizam tours de degustação entre os cafeeiros, e jovens baristas estão determinados a levar o grão local ao cenário mundial.'),
  'puer/teahorse': ('Rota do Chá e dos Cavalos', 'A antiga Rota do Chá e dos Cavalos, pela qual caravanas de mulas levavam tijolos de chá ao Tibete e traziam cavalos de volta à China, começava em Pu\'er e subia por desfiladeiros envoltos em nuvens. Vestígios das trilhas de pedra e antigas cidades de parada ainda mantêm viva a memória desse comércio árduo.'),
  'puer/peafowl': ('Pavão-verde', 'As florestas tropicais ao redor de Pu\'er estão entre os últimos refúgios do pavão-verde, uma das aves mais raras da China. As reservas daqui abrigam não só essa ave magnífica, mas também elefantes selvagens e gibões, e a cidade se orgulha de suas florestas tanto quanto de seu chá.'),
  'baoshan/volcano': ('Vulcões de Tengchong', 'Noventa e sete cones vulcânicos adormecidos enfileiram-se na planície de Tengchong, dando à paisagem um ar de superfície lunar. Os visitantes sobem até as bordas das crateras ou sobrevoam os cones em balão de ar quente, e a rocha negra de lava está incrustada até nas paredes das casas da cidade.'),
  'baoshan/rehai': ('Vale Rehai', 'No vale do \'Mar Quente\' de Tengchong, gêiseres soltam vapor e piscinas fervem, sendo a mais famosa o imenso \'Grande Caldeirão Fervente\'. Os visitantes provam ovos cozidos no vapor das fontes e depois mergulham em banhos minerais, buscando o calor curativo desta terra vulcânica.'),
  'baoshan/heshun': ('Cidade de Heshun', 'Heshun, cidade de pedra de mercadores que por séculos comerciaram com a Birmânia e além, viu seus filhos enviarem fortunas para casa na forma de pátios elegantes e escolas. Abrigando uma das bibliotecas de aldeia mais antigas da China, a cidade respira calma com seus lagos de lótus e pontes de pedra.'),
  'baoshan/gaoligong': ('Montanhas Gaoligong', 'Estendendo-se ao longo da fronteira com Mianmar, as montanhas Gaoligong são um tesouro de vida, com vales de borboletas, florestas quentes e milhares de espécies de plantas. Subindo de vales tropicais a cristas nevadas, elas abrigam incontáveis criaturas raras, de gibões a aves raramente vistas.'),
  'deyang/sanxingdui': ('Ruínas de Sanxingdui', 'Máscaras gigantes de bronze com olhos saltados, desenterradas de fossos sacrificiais descobertos em 1986, trouxeram à luz a misteriosa civilização Shu, de 3.000 anos. Com seus cetros de ouro e árvores sagradas de bronze, Sanxingdui figura entre as maiores surpresas da arqueologia chinesa.'),
  'deyang/jiannanchun': ('Licor Jiannanchun', 'O Jiannanchun, destilado em Mianzhu, é um baijiu histórico cujo nome aparece entre as bebidas servidas na corte Tang. Com antigos fossos de fermentação em uso contínuo e um aroma floral, está entre os nomes mais respeitados da tradição licoreira de Sichuan.'),
  'deyang/nianhua': ('Gravuras de Ano Novo de Mianzhu', 'As xilogravuras de Ano Novo pintadas à mão de Mianzhu penduram fortuna nas portas: deuses guardiões, bebês rechonchudos e símbolos de abundância. Considerada uma das grandes tradições de nianhua da China, essa arte transforma cada estampa em obra única graças às vívidas pinceladas finais dos mestres.'),
  'deyang/turbine': ('Capital da Indústria Pesada', 'Grande parte das turbinas gigantes, geradores e equipamentos de usinas do país é forjada nas vastas oficinas de Deyang. Considerada uma capital da maquinaria pesada, a cidade é um dos silenciosos músculos de aço que sustentam a infraestrutura energética da China.'),
  'mianyang/libai': ('Cidade natal de Li Bai', 'Li Bai, o imortal dos poetas, passou a infância entre as montanhas de Jiangyou, onde seus versos dedicados ao luar e ao vinho criaram raízes. Um memorial e um museu em seu nome reúnem todos os anos os amantes da poesia nos passos deste lendário mestre da dinastia Tang.'),
  'mianyang/sciencecity': ('Cidade da Ciência', 'Mianyang, a única cidade a ostentar o título oficial chinês de \'Cidade da Ciência e Tecnologia\', constrói o futuro com institutos de pesquisa e fábricas de eletrônicos. Terra natal das televisões Changhong, é o rosto de jaleco branco e decididamente inteligente de Sichuan.'),
  'mianyang/qiang': ('Torres de Pedra Qiang', 'Nas aldeias montanhosas de Beichuan, as torres de vigia de pedra do povo Qiang permanecem de pé há séculos, erguidas com maestria como símbolos de defesa e de prestígio. Mantendo vivas suas crenças da pedra branca e seus bordados de lã, as aldeias Qiang sustentam uma antiga cultura de montanha.'),
  'mianyang/mifen': ('Macarrão de arroz de Mianyang', 'Finos macarrões de arroz fumegando em caldo de frango, boi ou miúdos despertam Mianyang de manhã cedo. Os fios delicados cozinham em segundos, e a multidão debruçada sobre as tigelas no balcão é o ritual matinal mais fiel da cidade.'),
  'nanchong/langzhong': ('Cidade Antiga de Langzhong', 'Langzhong, uma das cidades antigas mais bem preservadas traçadas segundo o feng shui, dorme abraçada por uma curva do rio Jialing. Terra natal do astrônomo Han Luoxia Hong, é honrada como um dos berços das tradições do Ano Novo Chinês, e suas ruelas perfumadas de vinagre conservam seu tecido das eras Ming e Qing.'),
  'nanchong/silk': ('Capital da Seda', 'Com mais de dois mil anos de cultivo de amoreiras e tecelagem, Nanchong carrega o título de capital da seda do oeste da China. Cidade que outrora abasteceu de tecidos a Rota da Seda, ainda vive de suas fiações e de seu museu da seda, com seus panos lustrosos viajando para mercados do mundo inteiro.'),
  'nanchong/zhangfei': ('Carne bovina Zhang Fei', 'Zhang Fei, herói dos Três Reinos, serviu por muito tempo na guarnição de Langzhong, onde seu santuário ainda está de pé. A carne bovina curada e temperada que leva seu nome — negra por fora, rosada por dentro — é uma homenagem bem-humorada à imagem famosamente sombria do rosto do herói.'),
  'nanchong/zhude': ('Cidade natal de Zhu De', 'O marechal Zhu De, um dos comandantes fundadores do Exército de Libertação Popular, nasceu numa humilde casa de fazenda em Yilong. A simples moradia e seu salão memorial são parada de peregrinação da história moderna da China, onde os visitantes sentem a força dos começos humildes.'),
  'yibin/wuliangye': ('Licor Wuliangye', 'Destilado de sorgo, arroz, arroz glutinoso, trigo e milho, o Wuliangye deve seu nome a esses \'cinco grãos\' e figura entre as marcas de baijiu mais valiosas da China. O clima úmido de Yibin e seus fossos de fermentação seculares dão à bebida seu aroma característico em camadas.'),
  'yibin/firstcity': ('Primeira Cidade do Rio Yangtzé', 'Onde os rios Min e Jinsha se encontram, o rio recebe o nome de Yangtzé — por isso Yibin é chamada de \'primeira cidade do Yangtzé\'. O promontório onde as duas águas se fundem em cores diferentes, hoje um parque ribeirinho, é o emblema de que a cidade mais se orgulha.'),
  'yibin/bamboosea': ('Mar de Bambu de Shunan', 'O Mar de Bambu de Shunan, cobrindo mais de cem colinas, ondula ao vento como um oceano verde sem fim. Trilhas frescas na floresta, cachoeiras escondidas e uma culinária baseada em brotos de bambu envolvem o visitante, e equipes de cinema voltam sempre a este manto de verde.'),
  'yibin/ranmian': ('Macarrão Ardente', 'Sovado quase sem água e envolto em óleo aromático, o \'ranmian\' ganha o nome de \'macarrão em chamas\' por ser seco o bastante para o óleo pegar fogo. Temperado com pimenta, pimenta-de-sichuan e amendoim torrado, é a estrela que abre os olhos no café da manhã de Yibin.'),
  'luzhou/laojiao': ('Adega Laojiao', 'Fossos de fermentação de barro em uso contínuo desde 1573 são o coração da tradição de baijiu de \'aroma forte\' de Luzhou. A cultura microbiana viva dos fossos passa de geração em geração, e os mestres destiladores sustentam que os fossos mais antigos dão à bebida sua fragrância mais profunda.'),
  'luzhou/port': ('Porto de Luzhou', 'Fundada onde o rio Tuo encontra o Yangtzé, Luzhou é o portão fluvial de Sichuan rumo ao mar. Por séculos, seus cais embarcaram sal, licor e grãos; hoje, seu porto de contêineres ainda liga as províncias do interior ao baixo Yangtzé e ao mundo.'),
  'luzhou/longan': ('Pomares de Longan', 'O longan, a pequena fruta doce como mel chamada \'olho de dragão\', cresce nas encostas quentes dos vales fluviais de Luzhou. A cidade abriga alguns dos grandes pomares de longan mais setentrionais da China, e a fruta de amadurecimento tardio enche as bancas dos mercados no outono.'),
  'luzhou/umbrella': ('Guarda-chuvas de papel oleado', 'As sombrinhas de papel oleado feitas à mão pelos mestres de Fenshui, com varetas de bambu e desenhos pintados à mão, são um artesanato gracioso de quatro séculos. Cada sombrinha passa por dezenas de etapas e se abre tanto para a sorte quanto para a chuva — sua forma redonda simboliza plenitude e felicidade.'),
  'leshan/giantbuddha': ('Grande Buda de Leshan', 'Esculpido no penhasco, o Buda sentado de 71 metros contempla com serenidade o encontro turbulento de três rios há doze séculos. Iniciado pelo monge Tang Haitong para proteger os barcos que passavam, o projeto colossal é hoje patrimônio da UNESCO — só nos dedos dos pés cabem dezenas de pessoas.'),
  'leshan/emei': ('Monte Emei', 'O Monte Emei, uma das quatro montanhas sagradas do budismo, chama peregrinos e caminhantes com seu Cume Dourado brilhando acima de um mar de nuvens. As trilhas sobem passando por mosteiros antigos, e nos dias de sorte o cume revela o arco-íris em anel conhecido como \'luz de Buda\'.'),
  'leshan/monkeys': ('Macacos de Emei', 'Os macacos travessos que vivem ao longo das trilhas do Emei são famosos por revistar sem cerimônia as mochilas dos peregrinos. Os moradores os chamam de anfitriões da montanha; recostados nos corrimãos e posando para fotos, os macacos deixam nos caminhantes as lembranças mais divertidas — e mais levadas — da subida.'),
  'leshan/qiaojiao': ('Sopa de carne Qiaojiao', 'O \'qiaojiao\', sopa de carne bovina cozida por horas com ervas e especiarias, deve seu nome aos fregueses que apoiavam os pés nos bancos altos enquanto a tomavam. Clássico das ruas de Leshan há cerca de um século, essa tigela fumegante transforma até os miúdos mais humildes em banquete.'),
  'zigong/saltwell': ('Poços de sal de um quilômetro de profundidade', 'Zigong vive de seus poços de sal há cerca de dois mil anos, e sua genialidade na perfuração com cabos de bambu atingiu o auge com o Poço Shenhai — o primeiro furo do mundo a ultrapassar mil metros de profundidade. Torres de perfuração de madeira e um museu do sal ainda contam a história desta \'capital do sal\'.'),
  'zigong/lantern': ('Festival de Lanternas de Zigong', 'A cada temporada de Ano Novo, Zigong se transforma numa terra encantada de colossais jardins de lanternas luminosas. Dragões, palácios e heróis de contos de fadas erguem-se em seda e aço, e os mestres lanterneiros da cidade agora montam esses festivais de luz em cidades do mundo inteiro.'),
  'zigong/dinosaur': ('Museu dos Dinossauros', 'Milhares de fósseis que brotam das camadas jurássicas de Dashanpu fazem de Zigong a capital dos dinossauros da China. O museu construído diretamente sobre a escavação exibe os leitos de ossos exatamente como foram encontrados, e imponentes esqueletos de saurópodes levam os visitantes às profundezas da era jurássica.'),
  'zigong/rabbit': ('Coelho frio', 'O \'lengtu\', coelho servido frio em óleo de pimenta com pimenta-de-sichuan e amendoim, é um dos aperitivos mais ousados de Sichuan, e Zigong é sua terra natal. Nascida das fartas mesas dos trabalhadores do sal, a culinária da cidade mantém até hoje essa tradição de generosidade nos temperos.'),
  'panzhihua/steel': ('Capital do Vanádio e Titânio', 'Encravada no vale montanhoso do rio Jinsha, Panzhihua é uma gigantesca cidade do aço que explora as jazidas de vanádio e titânio mais ricas do mundo. Erguida do nada durante o grande impulso industrial do século XX, ela deve seu nome à flor vermelho-fogo da árvore de sumaúma local.'),
  'panzhihua/fruitvalley': ('Vale das Frutas Ensolaradas', 'Mangas, romãs e bananas do vale seco e quente do Jinsha amadurecem neste microclima banhado de sol até mesmo no inverno. As mangas de colheita tardia são o orgulho da cidade, e os pomares dão à cidade do aço um sabor surpreendentemente tropical.'),
  'panzhihua/sunshine': ('Cidade do Sol de Inverno', 'Com cerca de 2.700 horas de sol por ano, Panzhihua é a parada de bem-estar de quem busca um inverno ameno e luminoso. Aposentados fugindo do frio do norte se instalam ali durante a estação, e a cidade coroa seu sol com centros de treinamento esportivo e resorts de águas termais.'),
  'panzhihua/jinsha': ('Rio Jinsha', 'O Jinsha — \'rio de areia dourada\' — é o curso superior do Yangtzé, cavando vales profundos ao atravessar impetuoso o coração de Panzhihua. As barragens hidrelétricas ao longo de seu curso abastecem a região, enquanto pontes e passeios ribeirinhos dão vida às suas margens.'),
  'dazhou/gas': ('Capital do Gás Natural', 'Sob Dazhou estende-se Puguang, um dos maiores campos de gás natural da China, o que faz da cidade uma base energética nacional. Gasodutos partem daqui rumo às cidades industriais do leste, e a economia do gás abriu uma nova era para este canto montanhoso de Sichuan.'),
  'dazhou/ba': ('Legado do Reino Ba', 'Esta era a terra dos antigos guerreiros Ba, famosos por suas espadas em forma de folha de salgueiro, cujos bronzes com emblemas de tigre falam através das ruínas de Luojiaba. A cultura misteriosa desse povo guerreiro dos vales fluviais forma uma das camadas mais antigas da história de Sichuan.'),
  'dazhou/dengying': ('Carne Dengying', 'A carne \'dengying\', fatiada tão fina que deixa a luz passar, deve seu nome ao teatro de sombras outrora projetado à luz das lanternas. As fatias crocantes, finas como papel, são cobertas de tempero doce e picante, e esse elegante petisco de Dazhou enfeita as mesas há bem mais de um século.'),
  'dazhou/hanque': ('Torres de Pedra Han', 'As torres de pedra \'que\', com dois mil anos, erguidas nos campos de Quxian, são uma rara graça sobrevivente da arquitetura Han. Outrora coroando os caminhos de acesso às tumbas, essas torres-portais esculpidas gravam na pedra o mundo Han, com criaturas míticas e cenas do cotidiano.'),
  'guangyuan/jianmen': ('Passagem de Jianmen', 'O Passo de Jianmen, onde \'um homem pode deter dez mil\', é a fechadura da antiga estrada de Shu, com penhascos que se erguem como lâminas de espada. Ponto de convergência de exércitos desde os Três Reinos, o passo evoca o verso de Li Bai de que o caminho para Shu é \'mais difícil que subir ao céu\'.'),
  'guangyuan/wuzetian': ('Local de nascimento de Wu Zetian', 'Acredita-se que Wu Zetian, a única imperatriz da história da China, nasceu em Guangyuan, e o Templo Huangze a honra há um milênio. A cidade celebra a formidável governante com um festival anual das mulheres, enquanto sua estátua repousa serena no templo à beira do rio.'),
  'guangyuan/plankroad': ('Antigas estradas de pranchas', 'Estradas de tábuas apoiadas em vigas cravadas em penhascos verticais foram os monumentos de ousadia que tornaram transitável a estrada de Shu, \'mais difícil que subir ao céu\'. Vestígios das antigas galerias sobrevivem na Garganta de Mingyue, onde os visitantes caminham sobre tábuas restauradas e sentem o pulsar das velhas caravanas.'),
  'guangyuan/cypress': ('Corredor de Ciprestes de Cuiyun', 'Dezenas de milhares de ciprestes antigos ladeiam a velha estrada, transformando o Corredor de Cuiyun em um túnel verde. A lenda atribui parte do plantio a ordens do herói dos Três Reinos Zhang Fei, e o caminho sombreado figura entre as mais antigas arborizações de estrada preservadas do mundo.'),
  'yaan/panda': ('Berço do Panda', 'O panda-gigante foi descrito pela ciência pela primeira vez em Baoxing, em 1869, quando o relato do naturalista francês Armand David apresentou ao mundo a adorada espécie. A base de pandas de Bifengxia mantém vivo esse legado, e as florestas de bambu enevoadas de Ya\'an continuam sendo o berço do panda.'),
  'yaan/rain': ('Cidade da Chuva', 'A \'chuva de Ya\' lava os telhados quase toda noite, e a cada manhã a cidade brilha em mil tons de verde recém-enxaguado. Os moradores contam três graças — a chuva de Ya, o peixe de Ya e as moças de Ya —, um trio que resume o espírito gentil e generoso da cidade da chuva.'),
  'yaan/mengding': ('Chá do Monte Mengding', 'Diz a tradição que o chá foi plantado por mãos humanas pela primeira vez no Monte Mengding, há cerca de dois mil anos, o que rendeu à montanha o título de berço da cultura do chá. As folhas dos antigos jardins do cume foram por séculos oferecidas aos imperadores, e cerimônias do chá ainda acontecem nas encostas enevoadas.'),
  'yaan/yayu': ('Peixe Ya', 'O lendário peixe de Ya, criado em riachos alimentados pelo degelo, chega à mesa em caçarolas borbulhantes e é contado entre as três graças da cidade. Famoso por sua carne branca e firme, o peixe esconde na cabeça um ossinho em forma de espada, em torno do qual as lendas locais teceram muitas histórias.'),
  'xianyang/qincapital': ('Capital Imperial Qin', 'Aqui ficava a capital dos Qin, a dinastia que unificou a China pela primeira vez; foi de Xianyang que Qin Shi Huang trilhou o caminho para o império. Os palácios sobrevivem como sítios arqueológicos, onde bronzes e fundações sussurram sobre um poder de mais de dois mil anos.'),
  'xianyang/qianling': ('Mausoléu de Qianling', 'Qianling, o túmulo conjunto escavado na montanha de Wu Zetian e seu marido, o imperador Gaozong, é um dos raros mausoléus Tang a chegar até nós sem ser saqueado. Guardiões de pedra e estátuas de emissários estrangeiros ladeiam seu caminho das almas, enquanto a famosa estela sem inscrições erguida por Wu Zetian deixa seu julgamento para a história.'),
  'xianyang/zhengguo': ('Canal Zhengguo', 'Escavado no fim da era dos Reinos Combatentes, o Canal de Zhengguo irrigou a planície de Guanzhong, transformando-a no celeiro de Qin e lançando as bases econômicas da unificação. Alimentando a região há mais de dois milênios, o sistema permanece como um golpe de gênio da engenharia antiga.'),
  'xianyang/guokui': ('Pão guokui', 'O \'guokui\', pão achatado, crocante, grande e grosso como a tampa de uma panela, é contado entre as famosas \'dez esquisitices\' de Shaanxi. Assado lentamente sobre fogo de lenha, dura dias, e a tradição o remonta a antigas campanhas militares, quando os soldados o teriam assado em seus capacetes.'),
  'baoji/bronze': ('Capital dos Bronzes', 'Do solo de Baoji, coração da dinastia Zhou, emergiram milhares de vasos de bronze com inscrições — entre eles o He zun, que traz o registro escrito mais antigo conhecido do nome \'China\' (Zhongguo). O museu do bronze da cidade exibe essa maestria de três mil anos em uma das coleções mais ricas do mundo.'),
  'baoji/famen': ('Templo Famen', 'O Templo Famen, guardião da relíquia do osso do dedo de Buda, serviu de tesouro sagrado aos imperadores Tang. Quando a cripta oculta sob seu pagode foi aberta em 1987, veio à luz um deslumbrante tesouro Tang de ouro, prata e seda; hoje, um vasto complexo abriga a relíquia.'),
  'baoji/taibai': ('Monte Taibai', 'O Taibai, teto de 3.771 metros da cordilheira Qinling, alimenta lendas com neves que persistem até o verão — a \'neve de junho no Taibai\' era uma das paisagens célebres da antiga Guanzhong. As trilhas que sobem até seus lagos glaciais percorrem a própria divisa natural entre o norte e o sul da China.'),
  'baoji/saozi': ('Macarrão saozi', 'O macarrão \'saozi\' de Qishan, com molho de carne agridoce e picante, é considerado o sabor vivo da culinária da era Zhou, com fios finos, longos e elásticos. O vinagre e a pimenta frita dançam com cenoura, ovo e cogumelo orelha-de-pau, e servir tigela após tigela aos convidados nos casamentos é um costume centenário.'),
};
